// ============================================================
// data/certifications.js
// ============================================================
// Estructura unificada de proveedores y certificaciones.
// Soporta múltiples proveedores y certificaciones de forma escalable.
// ============================================================

const certifications = {
  redhat: {
    id: 'redhat',
    name: 'Red Hat',
    icon: '🔴',
    certifications: {
      ex200: {
        id: 'ex200',
        name: 'EX200 - Red Hat Certified System Administrator',
        shortName: 'EX200',
        description: 'Prepara tu certificación Red Hat con test prácticos, simulacros, escenarios y conceptos clave de administración de sistemas.',
        hasPractice: true,
        hasScenarios: true,
        hasConsole: true,
        hasLivePractice: true,
        questions: [
          { id: 1, category: "Usuarios y grupos", level: "básico", question: "¿Qué comando crea un usuario llamado 'developer' con directorio home y shell /bin/bash?", options: ["useradd -m -s /bin/bash developer", "adduser developer --home /bin/bash", "usermod -m -s /bin/bash developer", "groupadd developer"], correctAnswer: 0, explanation: "useradd -m crea el home, -s establece la shell. adduser no existe en RHEL por defecto; usermod modifica usuarios existentes; groupadd crea grupos.", command: "useradd -m -s /bin/bash developer" },
          { id: 2, category: "Permisos Linux", level: "básico", question: "¿Qué permisos octales asignan lectura, escritura y ejecución al propietario, solo lectura al grupo, y nada a otros?", options: ["755", "740", "644", "700"], correctAnswer: 1, explanation: "7=rwx (propietario), 4=r (grupo), 0=--- (otros). 755 daría r-x al grupo, 644 es rw-r--r--, 700 excluye al grupo por completo.", command: "chmod 740 archivo" },
          { id: 3, category: "Sudo", level: "medio", question: "¿Dónde se configura qué usuarios pueden usar sudo y qué comandos pueden ejecutar?", options: ["/etc/passwd", "/etc/sudoers y /etc/sudoers.d/", "/etc/group", "/etc/shadow"], correctAnswer: 1, explanation: "/etc/sudoers es el archivo principal de configuración de sudo. Se edita con visudo. /etc/sudoers.d/ permite configuraciones modulares.", command: "visudo" },
          { id: 4, category: "SELinux", level: "medio", question: "¿Cuál es el modo de SELinux que registra violaciones pero no las bloquea?", options: ["Enforcing", "Permissive", "Disabled", "Restricted"], correctAnswer: 1, explanation: "Permissive registra denegaciones de acceso en los logs pero no bloquea las operaciones. Enforcing sí bloquea. Disabled desactiva SELinux por completo.", command: "setenforce 0 # cambia a Permissive temporalmente" },
          { id: 5, category: "Firewalld", level: "básico", question: "¿Qué opción de firewall-cmd hace que una regla sea persistente tras reiniciar?", options: ["--reload", "--permanent", "--persistent", "--save"], correctAnswer: 1, explanation: "--permanent guarda la regla en la configuración persistente. Después se debe ejecutar --reload para aplicarla en la sesión actual.", command: "firewall-cmd --permanent --add-service=http" },
          { id: 6, category: "Systemd", level: "básico", question: "¿Qué comando habilita un servicio para que arranque automáticamente en el boot y lo inicia inmediatamente?", options: ["systemctl start servicio", "systemctl enable --now servicio", "chkconfig servicio on", "service servicio enable"], correctAnswer: 1, explanation: "systemctl enable --now crea los enlaces simbólicos para el arranque automático y ejecuta start en la misma operación. chkconfig es obsoleto en RHEL 7+.", command: "systemctl enable --now httpd" },
          { id: 7, category: "LVM", level: "medio", question: "¿Cuál es el orden correcto para crear un volumen lógico desde cero?", options: ["pvcreate → vgcreate → lvcreate", "lvcreate → pvcreate → vgcreate", "vgcreate → pvcreate → lvcreate", "pvcreate → lvcreate → vgcreate"], correctAnswer: 0, explanation: "Primero Physical Volume (pvcreate), luego Volume Group (vgcreate), y finalmente Logical Volume (lvcreate).", command: "pvcreate /dev/sdb1; vgcreate vg_datos /dev/sdb1; lvcreate -L 5G -n lv_web vg_datos" },
          { id: 8, category: "Particiones", level: "medio", question: "¿Qué herramienta se usa en RHEL 9 para crear una partición GPT en un disco de más de 2 TB?", options: ["fdisk", "parted", "mkfs", "mount"], correctAnswer: 1, explanation: "parted soporta tablas de particiones GPT y discos de cualquier tamaño. fdisk tradicional está limitado a MBR (2TB). En RHEL 8+ fdisk también soporta GPT, pero parted es la herramienta preferida.", command: "parted /dev/sdb mklabel gpt; parted /dev/sdb mkpart primary xfs 0% 100%" },
          { id: 9, category: "Montajes persistentes", level: "medio", question: "¿Qué campo de /etc/fstab indica el orden de verificación con fsck al arrancar?", options: ["dump", "pass", "options", "type"], correctAnswer: 1, explanation: "El último campo (pass) indica el orden de fsck. 0=no verificar, 1=raíz primero, 2=otros filesystems. dump es obsoleto.", command: "UUID=xxx /mnt/data xfs defaults 0 0" },
          { id: 10, category: "Redes", level: "medio", question: "¿Qué comando de nmcli configura una conexión con IP estática, desactivando DHCP?", options: ["nmcli con modify eth1 ipv4.method auto", "nmcli con modify eth1 ipv4.method manual", "nmcli con modify eth1 ipv4.ignore-auto-dns yes", "nmcli con down eth1"], correctAnswer: 1, explanation: "ipv4.method manual desactiva DHCP y permite usar IP estática. auto activa DHCP. Después de configurar IP, gateway y DNS, se usa nmcli con up.", command: "nmcli con modify eth1 ipv4.addresses 192.168.1.10/24 ipv4.gateway 192.168.1.1 ipv4.dns 8.8.8.8 ipv4.method manual" },
          { id: 11, category: "Repositorios y dnf", level: "básico", question: "¿Qué comando instala un paquete y sus dependencias sin pedir confirmación?", options: ["dnf install httpd", "dnf install -y httpd", "dnf download httpd", "rpm -ivh httpd"], correctAnswer: 1, explanation: "dnf install -y responde automáticamente 'yes' a las confirmaciones. dnf download solo descarga el RPM. rpm -ivh no resuelve dependencias.", command: "dnf install -y httpd" },
          { id: 12, category: "SSH", level: "básico", question: "¿Qué comando copia la clave pública SSH al servidor remoto para acceso sin contraseña?", options: ["ssh-copy-id user@remote", "scp id_rsa.pub user@remote:", "ssh-keygen -t rsa user@remote", "cat id_rsa.pub | ssh user@remote"], correctAnswer: 0, explanation: "ssh-copy-id instala la clave pública en ~/.ssh/authorized_keys del servidor remoto. Es la forma más sencilla y segura.", command: "ssh-copy-id root@server.example.com" },
          { id: 13, category: "Cron, at y timers", level: "medio", question: "¿Qué significa esta línea de crontab: 0 2 * * 1 /usr/local/bin/backup.sh?", options: ["Ejecutar todos los días a las 2:00", "Ejecutar los lunes a las 2:00", "Ejecutar el día 2 de cada mes", "Ejecutar cada 2 horas los lunes"], correctAnswer: 1, explanation: "minuto=0, hora=2, día_mes=*, mes=*, día_semana=1 (lunes). Por tanto, se ejecuta todos los lunes a las 2:00 AM.", command: "crontab -e # añadir: 0 2 * * 1 /usr/local/bin/backup.sh" },
          { id: 14, category: "Logs", level: "básico", question: "¿Qué comando muestra los logs de un servicio específico desde la última hora?", options: ["tail -f /var/log/messages", "journalctl -u httpd --since '1 hour ago'", "dmesg | grep httpd", "systemctl logs httpd"], correctAnswer: 1, explanation: "journalctl -u filtra por unidad (servicio). --since permite rangos de tiempo relativos como '1 hour ago'. systemctl logs no existe.", command: "journalctl -u httpd --since '1 hour ago'" },
          { id: 15, category: "NFS y autofs", level: "avanzado", question: "¿Qué archivo configura el punto de montaje automático con autofs para un recurso NFS?", options: ["/etc/fstab", "/etc/auto.master y /etc/auto.misc (o similar)", "/etc/exports", "/etc/nfs.conf"], correctAnswer: 1, explanation: "/etc/auto.master define el punto de montaje padre y el mapa a usar. El mapa (ej. /etc/auto.misc) define las subcarpetas y los recursos NFS. /etc/exports es para el servidor NFS.", command: "# /etc/auto.master:\n/misc /etc/auto.misc\n# /etc/auto.misc:\nshare -rw,sync server:/exported/path" },
          { id: 16, category: "Recuperación de root", level: "avanzado", question: "Durante la recuperación con rd.break, ¿qué paso permite escribir en /sysroot?", options: ["chroot /sysroot", "mount -o remount,rw /sysroot", "passwd root", "touch /.autorelabel"], correctAnswer: 1, explanation: "En rd.break, /sysroot está montado en modo solo lectura. mount -o remount,rw lo vuelve lectura/escritura para poder modificar archivos como /etc/shadow.", command: "mount -o remount,rw /sysroot" },
          { id: 17, category: "Bash scripting", level: "medio", question: "¿Qué construcción de Bash ejecuta un bloque de código solo si un comando falla (código distinto de 0)?", options: ["cmd && echo 'éxito'", "cmd || echo 'fallo'", "if [ $? -eq 0 ]; then ... fi", "cmd ; echo 'siempre'"], correctAnswer: 1, explanation: "|| es el operador OR lógico en Bash: ejecuta el segundo comando solo si el primero falla (retorna != 0). && ejecuta solo si tiene éxito.", command: "mkdir /datos || echo 'No se pudo crear el directorio'" },
          { id: 18, category: "Firewalld", level: "medio", question: "¿Qué comando de firewall-cmd permite ver todas las reglas activas de la zona por defecto?", options: ["firewall-cmd --get-active-zones", "firewall-cmd --list-all", "firewall-cmd --list-services", "firewall-cmd --state"], correctAnswer: 1, explanation: "--list-all muestra la zona por defecto con todos sus servicios, puertos, reglas rich, interfaces... --get-active-zones solo lista zonas activas, no sus reglas.", command: "firewall-cmd --list-all" },
          { id: 19, category: "SELinux", level: "avanzado", question: "¿Qué comando aplica permanentemente el contexto httpd_sys_content_t a /web y todo su contenido?", options: ["chcon -t httpd_sys_content_t /web", "semanage fcontext -a -t httpd_sys_content_t '/web(/.*)?' && restorecon -Rv /web", "setsebool -P httpd_enable_homedirs on", "chmod 755 /web"], correctAnswer: 1, explanation: "semanage fcontext añade la regla a la base de datos persistente de SELinux. restorecon -Rv la aplica recursivamente. chcon es temporal (se pierde al restaurar).", command: "semanage fcontext -a -t httpd_sys_content_t '/web(/.*)?' && restorecon -Rv /web" },
          { id: 20, category: "Almacenamiento", level: "medio", question: "¿Qué comando extiende un volumen lógico LVM en caliente y luego expande el filesystem XFS?", options: ["lvextend -L +2G /dev/vg_datos/lv_docs && resize2fs /dev/vg_datos/lv_docs", "lvextend -L +2G /dev/vg_datos/lv_docs && xfs_growfs /mnt/docs", "lvresize -L +2G /dev/vg_datos/lv_docs && mkfs.xfs /dev/vg_datos/lv_docs", "vgextend vg_datos /dev/sdc1"], correctAnswer: 1, explanation: "lvextend aumenta el tamaño del LV. xfs_growfs expande el filesystem XFS sin desmontar. resize2fs es para ext2/3/4, no para XFS.", command: "lvextend -L +2G /dev/vg_datos/lv_docs && xfs_growfs /mnt/docs" },
          { id: 21, category: "Usuarios y grupos", level: "medio", question: "¿Qué comando modifica un usuario existente para añadirlo al grupo wheel como grupo secundario?", options: ["usermod -aG wheel developer", "usermod -G wheel developer", "groupmod -a wheel developer", "useradd -G wheel developer"], correctAnswer: 0, explanation: "usermod -aG añade (append) el grupo wheel sin eliminar los grupos secundarios actuales. -G sin -a reemplaza todos los grupos secundarios, lo cual es peligroso.", command: "usermod -aG wheel developer" },
          { id: 22, category: "Systemd", level: "medio", question: "¿Qué comando crea un timer de systemd que ejecute /usr/local/bin/backup.sh cada día a las 3:00 AM?", options: ["systemctl timer add backup.timer", "Se crean dos archivos de unidad: backup.service y backup.timer", "crontab -e", "systemctl enable cron.timer"], correctAnswer: 1, explanation: "Los timers de systemd requieren dos unidades: un .service que define qué ejecutar, y un .timer que define cuándo. Se colocan en /etc/systemd/system/.", command: "# /etc/systemd/system/backup.timer:\n[Unit]\nDescription=Daily backup\n[Timer]\nOnCalendar=*-*-* 03:00:00\n[Install]\nWantedBy=timers.target" },
          { id: 23, category: "Redes", level: "básico", question: "¿Qué comando muestra la configuración IP actual de todas las interfaces?", options: ["ifconfig -a", "ip addr show", "netstat -i", "nmcli con show"], correctAnswer: 1, explanation: "ip addr show (o ip a) es el comando moderno en RHEL para ver interfaces y direcciones IP. ifconfig está obsoleto. nmcli con show muestra conexiones, no interfaces.", command: "ip addr show" },
          { id: 24, category: "Permisos Linux", level: "avanzado", question: "¿Qué bit especial hace que los archivos creados dentro de un directorio hereden el grupo del directorio?", options: ["SUID (4xxx)", "SGID (2xxx)", "Sticky bit (1xxx)", "ACL (setfacl)"], correctAnswer: 1, explanation: "SGID (Set Group ID, bit 2 en octal) en un directorio hace que los archivos nuevos hereden el grupo del directorio, no el grupo primario del usuario creador.", command: "chmod 2775 /compartido" },
          { id: 25, category: "Logs", level: "medio", question: "¿Dónde se almacenan por defecto los logs de denegación de SELinux?", options: ["/var/log/secure", "/var/log/audit/audit.log", "/var/log/messages", "/var/log/dmesg"], correctAnswer: 1, explanation: "/var/log/audit/audit.log contiene los registros de auditoría de SELinux, incluyendo las denegaciones AVC (Access Vector Cache). /var/log/messages también puede mostrar resúmenes.", command: "ausearch -m avc -ts recent" },
          { id: 26, category: "Herramientas esenciales", level: "básico", question: "¿Qué comando busca archivos llamados 'config.txt' en /etc y sus subdirectorios?", options: ["grep -r config.txt /etc", "find /etc -name 'config.txt'", "locate /etc/config.txt", "ls -R /etc | grep config.txt"], correctAnswer: 1, explanation: "find busca archivos en tiempo real en el sistema de archivos. -name especifica el nombre del archivo. locate usa una base de datos preconstruida y puede no estar actualizada.", command: "find /etc -name 'config.txt'" },
          { id: 27, category: "Herramientas esenciales", level: "básico", question: "¿Qué redirección añade la salida de un comando al final de un archivo existente sin sobrescribirlo?", options: [">", ">>", "2>", "|"], correctAnswer: 1, explanation: ">> añade (append) la salida al final del archivo. > sobrescribe el archivo completamente. 2> redirige solo stderr. | redirige stdout a la entrada de otro comando.", command: "echo 'nueva línea' >> /etc/motd" },
          { id: 28, category: "Herramientas esenciales", level: "medio", question: "¿Qué redirección combina stdout y stderr en el mismo archivo de log?", options: ["2>&1 >archivo.log", ">archivo.log 2>&1", ">&archivo.log", "2>archivo.log"], correctAnswer: 1, explanation: ">archivo.log 2>&1 primero redirige stdout al archivo, luego stderr al mismo destino que stdout. El orden importa: si se invierte, stderr seguirá a la terminal.", command: "comando >salida.log 2>&1" },
          { id: 29, category: "Herramientas esenciales", level: "básico", question: "¿Qué comando crea un archivo tar comprimido con gzip llamado backup.tar.gz del directorio /etc?", options: ["tar -cvf backup.tar.gz /etc", "tar -czf backup.tar.gz /etc", "tar -cjf backup.tar.gz /etc", "gzip /etc > backup.tar.gz"], correctAnswer: 1, explanation: "tar -czf: -c=crear, -z=comprimir con gzip, -f=nombre archivo. -cjf usa bzip2 (más lento, más compresión). Para extraer: tar -xzf. Para ver contenido sin extraer: tar -tzf.", command: "tar -czf backup.tar.gz /etc" },
          { id: 30, category: "Systemd", level: "medio", question: "¿Cuál es el target de systemd equivalente al antiguo runlevel 3 (multiusuario sin GUI)?", options: ["graphical.target", "multi-user.target", "rescue.target", "network.target"], correctAnswer: 1, explanation: "multi-user.target equivale al runlevel 3 (multiusuario, con red, sin entorno gráfico). graphical.target es runlevel 5 (con GUI). rescue.target es runlevel 1 (modo rescate).", command: "systemctl set-default multi-user.target" },
          { id: 31, category: "Procesos", level: "medio", question: "¿Qué comando ejecuta un proceso con menor prioridad (nice value +10)?", options: ["nice 10 tar -czf backup.tar.gz /datos", "nice -n 10 tar -czf backup.tar.gz /datos", "renice 10 tar", "chprio 10 tar"], correctAnswer: 1, explanation: "nice -n 10 lanza un proceso con prioridad reducida. nice values van de -20 (máxima, solo root) a 19 (mínima). renice cambia la prioridad de un proceso ya en ejecución por su PID.", command: "nice -n 10 tar -czf backup.tar.gz /datos" },
          { id: 32, category: "Redes", level: "básico", question: "¿Qué comando habilita la sincronización automática de la hora con NTP de forma permanente?", options: ["date -s '2024-01-15 10:00'", "timedatectl set-ntp true", "ntpdate pool.ntp.org", "hwclock --systohc"], correctAnswer: 1, explanation: "timedatectl set-ntp true habilita la sincronización NTP automática mediante chronyd. date -s cambia la hora manualmente. ntpdate está obsoleto en RHEL 8/9.", command: "timedatectl set-ntp true" },
          { id: 33, category: "Permisos Linux", level: "avanzado", question: "¿Qué comando añade una ACL que permite al usuario 'bob' leer y escribir en /proyecto sin modificar los permisos del propietario?", options: ["setfacl -m u:bob:rw /proyecto", "setfacl -x u:bob /proyecto", "getfacl -m u:bob:rw /proyecto", "chmod u+rw /proyecto"], correctAnswer: 0, explanation: "setfacl -m (modify) u:bob:rw añade/modifica la ACL para el usuario 'bob'. getfacl solo lee ACLs. chmod no afecta a usuarios específicos. -x elimina entradas ACL.", command: "setfacl -m u:bob:rw /proyecto" },
          { id: 34, category: "Permisos Linux", level: "medio", question: "¿Qué comando muestra las ACLs extendidas de un archivo o directorio?", options: ["ls -l archivo", "getfacl archivo", "stat archivo", "lsattr archivo"], correctAnswer: 1, explanation: "getfacl muestra todas las ACLs del archivo: propietario, grupo y entradas adicionales de usuarios/grupos. ls -l solo muestra el '+' indicando que hay ACLs pero no las detalla. lsattr muestra atributos del filesystem.", command: "getfacl /proyecto" },
          { id: 35, category: "Usuarios y grupos", level: "básico", question: "¿Cuál es la diferencia principal entre 'su -' y 'su' al cambiar de usuario?", options: ["No hay diferencia entre ambos comandos", "'su -' carga el entorno completo del usuario destino; 'su' mantiene el entorno actual", "'su' requiere contraseña de root; 'su -' no", "'su -' solo funciona para root"], correctAnswer: 1, explanation: "su - (equivalente a su -l) carga el entorno completo del destino: variables de entorno, PATH, directorio home y perfil. 'su' sin guion solo cambia el usuario manteniendo el entorno del usuario original.", command: "su - root" },
          { id: 36, category: "Sudo", level: "avanzado", question: "¿Qué línea en /etc/sudoers.d/ permite a 'devuser' ejecutar dnf sin contraseña?", options: ["devuser ALL=(ALL) /usr/bin/dnf", "devuser ALL=(ALL) NOPASSWD: /usr/bin/dnf", "devuser ALL=NOPASSWD ALL", "NOPASSWD: devuser=/usr/bin/dnf"], correctAnswer: 1, explanation: "La sintaxis correcta de sudoers es: usuario HOSTS=(RUNAS) NOPASSWD: /ruta/absoluta/comando. Los comandos deben ser rutas absolutas. Edita con visudo para validar la sintaxis.", command: "# /etc/sudoers.d/devuser:\ndevuser ALL=(ALL) NOPASSWD: /usr/bin/dnf" },
          { id: 37, category: "SSH", level: "medio", question: "¿Qué directiva de /etc/ssh/sshd_config deshabilita el acceso SSH directo como root?", options: ["AllowRoot no", "PermitRootLogin no", "RootAccess disable", "DenyRoot yes"], correctAnswer: 1, explanation: "PermitRootLogin no en sshd_config impide el login SSH directo como root. Tras el cambio hay que reiniciar: systemctl restart sshd. La opción 'prohibit-password' permite solo con clave pero no contraseña.", command: "# En /etc/ssh/sshd_config:\nPermitRootLogin no" },
          { id: 38, category: "SELinux", level: "avanzado", question: "¿Qué comando permite a un servicio como httpd escuchar en el puerto 9090/tcp según SELinux?", options: ["semanage port -a -t http_port_t -p tcp 9090", "setsebool -P httpd_use_port 9090", "chcon -t http_port_t 9090/tcp", "semanage fcontext -a -t http_port_t :9090"], correctAnswer: 0, explanation: "semanage port -a añade el puerto 9090/tcp al tipo http_port_t de SELinux, permitiendo que httpd escuche en él. Usa 'semanage port -l | grep http' para ver los puertos ya permitidos.", command: "semanage port -a -t http_port_t -p tcp 9090" },
          { id: 39, category: "SELinux", level: "avanzado", question: "¿Qué comando activa permanentemente el booleano SELinux que permite a httpd conectar a bases de datos externas?", options: ["setsebool httpd_can_network_connect_db on", "setsebool -P httpd_can_network_connect_db on", "semanage boolean -m httpd_can_network_connect_db on", "setenforce httpd_can_network_connect_db 1"], correctAnswer: 1, explanation: "setsebool -P hace el cambio persistente tras reinicios. Sin -P solo es temporal. Consulta todos los booleanos con 'getsebool -a' o busca los de httpd con 'getsebool -a | grep httpd'.", command: "setsebool -P httpd_can_network_connect_db on" },
          { id: 40, category: "Repositorios y dnf", level: "medio", question: "¿Qué comando lista los módulos de aplicación disponibles y sus streams en RHEL 8/9?", options: ["dnf list modules", "dnf module list", "dnf info modules", "rpm -q modules"], correctAnswer: 1, explanation: "dnf module list muestra los módulos disponibles, sus streams (versiones) y profiles. Un módulo agrupa paquetes relacionados con diferentes versiones disponibles. Ej: nodejs:18, nodejs:20.", command: "dnf module list" },
          { id: 41, category: "Cron, at y timers", level: "básico", question: "¿Qué comando programa la ejecución de un script una sola vez en 10 minutos?", options: ["cron 10m /usr/local/bin/script.sh", "at now + 10 minutes", "schedule -t 10m /usr/local/bin/script.sh", "timeout 10m /usr/local/bin/script.sh"], correctAnswer: 1, explanation: "at programa tareas puntuales (una sola vez). 'at now + 10 minutes' abre un prompt donde introduces el comando, terminando con Ctrl+D. atq lista las tareas pendientes; atrm las cancela.", command: "at now + 10 minutes" },
          { id: 42, category: "Herramientas esenciales", level: "básico", question: "¿Qué comando sincroniza archivos entre dos directorios preservando permisos, timestamps y solo transfiriendo cambios?", options: ["cp -r origen destino", "rsync -av origen/ destino/", "scp -r origen destino", "tar -czf - origen | tar -xzf - -C destino"], correctAnswer: 1, explanation: "rsync -av (archive+verbose) sincroniza preservando permisos, propietarios, timestamps y enlaces. Solo transfiere diferencias, muy eficiente. El '/' final en origen es importante: copia el contenido, no el directorio.", command: "rsync -av /datos/ backup@server:/backup/" },
          { id: 43, category: "Herramientas esenciales", level: "básico", question: "¿Qué comando crea un enlace simbólico en /datos apuntando a /var/datos?", options: ["ln /var/datos /datos", "ln -s /var/datos /datos", "link /datos /var/datos", "symlink /var/datos /datos"], correctAnswer: 1, explanation: "ln -s crea un enlace simbólico (soft link). Sintaxis: ln -s DESTINO NOMBRE_ENLACE. Los enlaces simbólicos pueden cruzar sistemas de archivos. Un enlace duro (ln sin -s) no puede.", command: "ln -s /var/datos /datos" },
          { id: 44, category: "Repositorios y dnf", level: "básico", question: "¿Qué comando lista todos los paquetes RPM instalados en el sistema?", options: ["dnf list", "rpm -qa", "dnf installed", "dnf list installed"], correctAnswer: 1, explanation: "rpm -qa (query all) lista todos los paquetes RPM instalados. dnf list installed también funciona. rpm -qi paquete da información detallada de un paquete específico instalado.", command: "rpm -qa | grep -i httpd" },
          { id: 45, category: "Systemd", level: "medio", question: "¿Qué comando aplica el perfil de rendimiento 'throughput-performance' para optimizar el servidor?", options: ["systemctl set-profile throughput-performance", "tuned-adm profile throughput-performance", "sysctl -w performance=throughput", "performance-tune throughput"], correctAnswer: 1, explanation: "tuned-adm profile aplica perfiles de optimización del sistema. Perfiles comunes: throughput-performance (servidores), latency-performance (baja latencia), powersave, virtual-guest. tuned-adm active muestra el perfil activo.", command: "tuned-adm profile throughput-performance" },
          { id: 46, category: "Usuarios y grupos", level: "medio", question: "¿Qué comando configura que la contraseña del usuario 'alice' expire cada 60 días?", options: ["passwd -e 60 alice", "chage -M 60 alice", "usermod --max-days 60 alice", "password-policy -d 60 alice"], correctAnswer: 1, explanation: "chage -M establece el número máximo de días entre cambios de contraseña. chage -l usuario muestra la configuración actual. chage -d 0 fuerza el cambio en el siguiente login.", command: "chage -M 60 alice" },
          { id: 47, category: "Usuarios y grupos", level: "básico", question: "¿Qué comando bloquea la cuenta del usuario 'alice' impidiendo su acceso al sistema?", options: ["userdel alice", "usermod -L alice", "passwd --lock alice", "chage -E 0 alice"], correctAnswer: 1, explanation: "usermod -L (lock) bloquea la cuenta añadiendo '!' antes del hash de contraseña en /etc/shadow. usermod -U (unlock) la desbloquea. passwd -l también bloquea pero solo modifica la contraseña.", command: "usermod -L alice" },
          { id: 48, category: "Permisos Linux", level: "medio", question: "¿Qué umask garantiza que los archivos nuevos tengan permisos 640 y los directorios 750?", options: ["umask 022", "umask 027", "umask 137", "umask 117"], correctAnswer: 1, explanation: "umask 027: archivos = 666 - 027 = 640 (rw-r-----); directorios = 777 - 027 = 750 (rwxr-x---). umask 022 da 644/755. Se configura en ~/.bashrc, /etc/profile o /etc/profile.d/.", command: "umask 027" },
          { id: 49, category: "Almacenamiento", level: "medio", question: "¿Qué comando muestra los UUIDs de todos los dispositivos de bloque del sistema?", options: ["lsblk -a", "blkid", "fdisk -l", "pvdisplay"], correctAnswer: 1, explanation: "blkid lista dispositivos de bloque con su UUID, tipo de filesystem y LABEL. Es la forma correcta de obtener UUIDs para /etc/fstab. lsblk -f también muestra UUIDs en formato árbol.", command: "blkid" },
          { id: 50, category: "Almacenamiento", level: "básico", question: "¿Qué comando muestra una vista en árbol de todos los dispositivos de bloque, particiones y puntos de montaje?", options: ["fdisk -l", "lsblk", "df -h", "mount | column -t"], correctAnswer: 1, explanation: "lsblk muestra dispositivos de bloque en árbol jerárquico con tamaños, tipos y puntos de montaje. fdisk -l muestra solo particiones. df -h muestra espacio usado en filesystems ya montados.", command: "lsblk" },
          { id: 51, category: "Almacenamiento", level: "avanzado", question: "¿Qué opción de /etc/fstab evita que un fallo de montaje detenga el proceso de arranque?", options: ["noauto", "nofail", "optional", "x-systemd.automount"], correctAnswer: 1, explanation: "nofail hace que el sistema ignore errores de montaje durante el arranque, evitando el modo de emergencia. Ideal para discos externos, NFS o recursos no críticos. noauto impide el montaje automático.", command: "UUID=xxx /mnt/datos xfs defaults,nofail 0 0" },
          { id: 52, category: "Almacenamiento", level: "medio", question: "¿Qué comando formatea la partición /dev/sdb1 con el sistema de archivos ext4?", options: ["mkfs.xfs /dev/sdb1", "mkfs.ext4 /dev/sdb1", "format ext4 /dev/sdb1", "mke2fs -t xfs /dev/sdb1"], correctAnswer: 1, explanation: "mkfs.ext4 crea un filesystem ext4. Equivalente: mke2fs -t ext4. Para XFS usa mkfs.xfs. Tras crear ext4 se puede expandir con resize2fs; XFS se expande con xfs_growfs.", command: "mkfs.ext4 /dev/sdb1" },
          { id: 53, category: "LVM", level: "avanzado", question: "¿Qué secuencia de comandos añade el disco /dev/sdd al grupo de volúmenes vg_datos para ampliar espacio?", options: ["vgextend /dev/sdd vg_datos", "pvcreate /dev/sdd && vgextend vg_datos /dev/sdd", "lvcreate -d /dev/sdd vg_datos", "vgadd /dev/sdd vg_datos"], correctAnswer: 1, explanation: "Primero hay que inicializar el disco como PV con pvcreate, luego vgextend añade ese PV al VG existente ampliando el espacio disponible. pvs y vgs muestran el estado resultante.", command: "pvcreate /dev/sdd && vgextend vg_datos /dev/sdd" },
          { id: 54, category: "Almacenamiento", level: "medio", question: "¿Qué comando expande un filesystem ext4 para usar todo el espacio disponible en el dispositivo?", options: ["xfs_growfs /dev/sdb1", "resize2fs /dev/sdb1", "fsck.ext4 -r /dev/sdb1", "tune2fs -l /dev/sdb1"], correctAnswer: 1, explanation: "resize2fs expande o reduce un filesystem ext4. Sin argumentos de tamaño, usa todo el espacio disponible en el dispositivo. Para XFS usa xfs_growfs (funciona en caliente sin desmontar).", command: "resize2fs /dev/sdb1" },
          { id: 55, category: "Almacenamiento", level: "básico", question: "¿Qué comando muestra el estado y tamaño de todos los dispositivos swap activos?", options: ["free -h", "swapon -s", "df -h", "lsblk --swap"], correctAnswer: 1, explanation: "swapon -s (o swapon --show) muestra dispositivos swap activos, tamaño, uso y prioridad. free -h muestra un resumen de memoria incluyendo swap total/usada pero con menos detalle.", command: "swapon -s" },
          { id: 56, category: "Redes", level: "medio", question: "¿Qué comando moderno muestra los puertos TCP en escucha y los procesos asociados?", options: ["netstat -tlnp", "ss -tlnp", "lsof -i:tcp", "ip port list"], correctAnswer: 1, explanation: "ss -tlnp: -t=TCP, -l=listening (escucha), -n=numérico (no resolver nombres), -p=procesos. ss es el reemplazo moderno de netstat. Ambos muestran lo mismo pero ss es más rápido.", command: "ss -tlnp" },
          { id: 57, category: "Redes", level: "básico", question: "¿Qué comando muestra la tabla de rutas IP incluyendo la puerta de enlace predeterminada?", options: ["ip addr show", "ip route show", "nmcli route", "route print"], correctAnswer: 1, explanation: "ip route show (o ip r) muestra la tabla de rutas. La línea 'default via X.X.X.X dev ethX' muestra la puerta de enlace predeterminada. route y netstat -r también funcionan pero están obsoletos.", command: "ip route show" },
          { id: 58, category: "Redes", level: "básico", question: "¿Qué archivo contiene los servidores DNS que usa el sistema para la resolución de nombres?", options: ["/etc/hosts", "/etc/resolv.conf", "/etc/nsswitch.conf", "/etc/sysconfig/network"], correctAnswer: 1, explanation: "/etc/resolv.conf contiene las directivas 'nameserver IP'. En RHEL con NetworkManager se gestiona automáticamente según la conexión activa. /etc/hosts tiene resolución local estática sin DNS.", command: "cat /etc/resolv.conf" },
          { id: 59, category: "Redes", level: "básico", question: "¿Qué archivo permite resolver nombres de host localmente sin consultar DNS?", options: ["/etc/resolv.conf", "/etc/hosts", "/etc/hostname", "/etc/nsswitch.conf"], correctAnswer: 1, explanation: "/etc/hosts contiene entradas estáticas IP-hostname. Se consulta antes que DNS según /etc/nsswitch.conf (orden: files dns). Es útil en laboratorios y entornos sin DNS.", command: "echo '192.168.1.100 server.lab.local server' >> /etc/hosts" },
          { id: 60, category: "Herramientas esenciales", level: "medio", question: "¿Qué comando de una sola instrucción ordena /etc/passwd y elimina líneas duplicadas?", options: ["cat /etc/passwd | uniq | sort", "sort /etc/passwd | uniq", "uniq /etc/passwd | sort", "sort -u /etc/passwd"], correctAnswer: 3, explanation: "sort -u (unique) ordena y elimina duplicados en un solo paso. sort | uniq también funciona, pero uniq solo elimina duplicados consecutivos, por lo que sort debe ejecutarse primero.", command: "sort -u /etc/passwd" },
          { id: 61, category: "Herramientas esenciales", level: "medio", question: "¿Qué comando extrae el tercer campo de /etc/passwd usando ':' como separador?", options: ["awk -F: '{print $3}' /etc/passwd", "cut -d: -f3 /etc/passwd", "grep -o ':[0-9]*:' /etc/passwd", "sed 's/:.*//' /etc/passwd"], correctAnswer: 1, explanation: "cut -d: -f3 usa ':' como delimitador (-d:) y extrae el campo 3 (-f3). awk -F: '{print $3}' es equivalente y más flexible. cut es más sencillo para extracción de campos fijos.", command: "cut -d: -f1,3 /etc/passwd" },
          { id: 62, category: "Herramientas esenciales", level: "medio", question: "¿Qué comando reemplaza todas las ocurrencias de 'http' por 'https' directamente en el archivo /etc/app.conf?", options: ["sed 's/http/https/' /etc/app.conf", "sed -i 's/http/https/g' /etc/app.conf", "grep -r 'http' /etc/app.conf", "awk '{gsub(/http/,\"https\")} 1' /etc/app.conf"], correctAnswer: 1, explanation: "sed -i edita el archivo en lugar (in-place). La expresión 's/http/https/g' reemplaza todas las ocurrencias (flag g). Sin -i, sed imprime el resultado pero no modifica el archivo.", command: "sed -i 's/http/https/g' /etc/app.conf" },
          { id: 63, category: "Herramientas esenciales", level: "básico", question: "¿Qué comando muestra las últimas 20 líneas de /var/log/messages y continúa mostrando entradas nuevas en tiempo real?", options: ["head -n 20 /var/log/messages", "tail -f /var/log/messages", "tail -fn 20 /var/log/messages", "watch tail /var/log/messages"], correctAnswer: 2, explanation: "tail -fn 20 muestra las últimas 20 líneas (-n 20) y sigue mostrando nuevas líneas en tiempo real (-f). Solo -f muestra las últimas 10 líneas por defecto. Ctrl+C para salir.", command: "tail -fn 20 /var/log/messages" },
          { id: 64, category: "Herramientas esenciales", level: "básico", question: "¿Qué comando busca recursivamente la cadena 'error' (ignorando mayúsculas) en todos los archivos de /var/log?", options: ["find /var/log -name error", "grep -ri 'error' /var/log/", "grep -r 'error' /var/log/", "locate -i error /var/log"], correctAnswer: 1, explanation: "grep -r busca recursivamente en directorios. -i ignora mayúsculas/minúsculas (case-insensitive). Combinado -ri busca 'error', 'Error', 'ERROR', etc. en todos los archivos bajo /var/log.", command: "grep -ri 'error' /var/log/" },
          { id: 65, category: "Herramientas esenciales", level: "básico", question: "¿Qué comando cuenta el número de líneas del archivo /etc/passwd?", options: ["grep -c . /etc/passwd", "wc -l /etc/passwd", "cat /etc/passwd | count", "ls -l /etc/passwd"], correctAnswer: 1, explanation: "wc -l cuenta líneas (-l). wc -w cuenta palabras, wc -c cuenta bytes/caracteres. grep -c '' también cuenta líneas. wc es el comando estándar para contar líneas.", command: "wc -l /etc/passwd" },
          { id: 66, category: "Herramientas esenciales", level: "básico", question: "¿Qué comando transfiere de forma segura el archivo local report.txt al directorio /tmp de server.lab.local?", options: ["rsync report.txt user@server.lab.local:/tmp", "scp report.txt user@server.lab.local:/tmp/", "ssh user@server.lab.local 'cp report.txt /tmp'", "sftp report.txt user@server.lab.local:/tmp"], correctAnswer: 1, explanation: "scp (secure copy) usa SSH para transferir archivos de forma segura. Sintaxis: scp origen usuario@servidor:destino. Para directorios: scp -r. sftp también funciona pero es interactivo.", command: "scp report.txt user@server.lab.local:/tmp/" },
          { id: 67, category: "Herramientas esenciales", level: "básico", question: "¿Qué secuencia de teclas en vim guarda los cambios y cierra el archivo?", options: [":w", ":q", ":wq", ":save"], correctAnswer: 2, explanation: ":wq guarda (write) y cierra (quit) el archivo. También funciona :x o ZZ. Solo :w guarda sin cerrar. :q! cierra descartando cambios. La tecla i entra en modo inserción; Esc vuelve al modo normal.", command: "# En vim: Esc luego :wq Enter" },
          { id: 68, category: "Herramientas esenciales", level: "medio", question: "¿Qué comando encuentra archivos de más de 100 MB en el directorio /var?", options: ["find /var -size +100M -type f", "find /var -size 100M -type f", "ls -lR /var | grep 100M", "du -sh /var/* | grep 100M"], correctAnswer: 0, explanation: "find -size +100M busca archivos de MÁS de 100 megabytes. El '+' significa 'mayor que'. Sin '+' sería exactamente ese tamaño. Unidades: c(bytes), k(KB), M(MB), G(GB). -type f solo archivos regulares.", command: "find /var -size +100M -type f 2>/dev/null" },
          { id: 69, category: "Herramientas esenciales", level: "medio", question: "¿Qué comando busca todos los archivos con el bit SUID activado en el sistema?", options: ["find / -perm /4000 -type f 2>/dev/null", "find / -perm 4000 -type f 2>/dev/null", "find / -suid -type f", "ls -lR / | grep '^..s'"], correctAnswer: 0, explanation: "find -perm /4000 busca archivos donde al menos el bit SUID (4000) esté activado (el '/' significa OR con la máscara). -perm 4000 busca exactamente ese modo, excluyendo archivos con otros permisos adicionales.", command: "find / -perm /4000 -type f 2>/dev/null" },
          { id: 70, category: "Firewalld", level: "medio", question: "¿Qué comando añade una rich rule que acepta conexiones SSH solo desde la red 192.168.1.0/24?", options: ["firewall-cmd --permanent --add-source=192.168.1.0/24 --add-service=ssh", "firewall-cmd --permanent --add-rich-rule='rule family=ipv4 source address=192.168.1.0/24 service name=ssh accept'", "firewall-cmd --permanent --zone=trusted --add-source=192.168.1.0/24", "iptables -A INPUT -s 192.168.1.0/24 -p tcp --dport 22 -j ACCEPT"], correctAnswer: 1, explanation: "Las rich rules de firewalld permiten reglas complejas con múltiples criterios. La sintaxis incluye family, source, service/port y acción. Después ejecutar --reload para aplicar.", command: "firewall-cmd --permanent --add-rich-rule='rule family=ipv4 source address=192.168.1.0/24 service name=ssh accept' && firewall-cmd --reload" },
          { id: 71, category: "Firewalld", level: "medio", question: "¿Qué comando lista todas las zonas disponibles en firewalld?", options: ["firewall-cmd --get-zones", "firewall-cmd --list-zones", "firewall-cmd --get-active-zones", "systemctl status firewalld"], correctAnswer: 0, explanation: "--get-zones lista todas las zonas definidas (incluyendo las sin interfaces asignadas). --get-active-zones muestra solo las zonas con interfaces o fuentes actualmente asignadas.", command: "firewall-cmd --get-zones" },
          { id: 72, category: "Logs", level: "medio", question: "¿Qué comando muestra los mensajes del kernel del arranque actual del sistema?", options: ["journalctl -u kernel", "journalctl -b -k", "dmesg", "cat /var/log/boot.log"], correctAnswer: 2, explanation: "dmesg muestra el buffer de mensajes del kernel. journalctl -b -k también muestra mensajes del kernel del boot actual (más completo). dmesg | less permite navegar el output.", command: "dmesg | grep -i error" },
          { id: 73, category: "Systemd", level: "medio", question: "¿Qué comando muestra todos los servicios y unidades de systemd en estado fallido?", options: ["systemctl status all", "systemctl list-units --state=failed", "systemctl --failed", "journalctl --failed"], correctAnswer: 2, explanation: "systemctl --failed (equivalente a systemctl list-units --state=failed) muestra todas las unidades fallidas. Es el primer paso para diagnosticar problemas de arranque o servicio.", command: "systemctl --failed" },
          { id: 74, category: "Systemd", level: "avanzado", question: "¿Qué comando impide completamente que un servicio se inicie, incluso manualmente o como dependencia de otro?", options: ["systemctl disable servicio", "systemctl stop servicio", "systemctl mask servicio", "systemctl deactivate servicio"], correctAnswer: 2, explanation: "systemctl mask crea un enlace simbólico del unit file a /dev/null, impidiendo cualquier inicio. systemctl unmask revierte esto. disable solo elimina los enlaces de arranque automático pero permite el inicio manual.", command: "systemctl mask bluetooth" },
          { id: 75, category: "Bash scripting", level: "medio", question: "¿Qué construcción de Bash comprueba si el archivo /etc/hosts existe y es un archivo regular?", options: ["if [ /etc/hosts ]; then", "if [ -f /etc/hosts ]; then", "if exists /etc/hosts; then", "if test -e /etc/hosts; then"], correctAnswer: 1, explanation: "[ -f archivo ] devuelve verdadero si el archivo existe y es regular. -d comprueba directorio, -e cualquier tipo, -r legible, -w escribible, -x ejecutable, -s no vacío.", command: "if [ -f /etc/hosts ]; then echo 'Existe'; fi" },
          { id: 76, category: "Bash scripting", level: "medio", question: "¿Qué bucle Bash itera sobre todos los archivos .log del directorio /var/log?", options: ["for f in /var/log/*.log; do echo $f; done", "foreach f in /var/log/*.log; do echo $f; done", "loop /var/log/*.log do echo $f done", "for f=$(ls /var/log/*.log); do echo $f; done"], correctAnswer: 0, explanation: "El bucle for f in patrón; do ... done itera sobre los archivos que coinciden con el glob. El shell expande *.log a la lista de archivos automáticamente.", command: "for f in /var/log/*.log; do echo \"Procesando: $f\"; done" },
          { id: 77, category: "Bash scripting", level: "avanzado", question: "¿Qué variable especial de Bash contiene el código de salida del último comando ejecutado?", options: ["$$", "$?", "$!", "$#"], correctAnswer: 1, explanation: "$? contiene el código de retorno del último comando (0=éxito, distinto de 0=error). $0=nombre del script, $#=número de argumentos, $$=PID del script, $!=PID del último proceso en background.", command: "cp archivo.txt /backup/ ; if [ $? -ne 0 ]; then echo 'Error en copia'; fi" },
          { id: 78, category: "Herramientas esenciales", level: "básico", question: "¿Qué comando extrae el contenido de backup.tar.gz en el directorio /tmp/?", options: ["tar -czf backup.tar.gz -C /tmp", "tar -xzf backup.tar.gz -C /tmp/", "tar -tzf backup.tar.gz -C /tmp", "gzip -d backup.tar.gz -C /tmp"], correctAnswer: 1, explanation: "tar -xzf: -x=extraer, -z=gzip, -f=archivo. -C especifica el directorio de destino. Para ver el contenido sin extraer usa -tzf. Para bzip2 usa -xjf.", command: "tar -xzf backup.tar.gz -C /tmp/" },
          { id: 79, category: "Redes", level: "medio", question: "¿Qué herramienta proporciona una interfaz de texto interactiva (TUI) para configurar conexiones de red?", options: ["nmcli", "nmtui", "netconfig", "ip-setup"], correctAnswer: 1, explanation: "nmtui (NetworkManager Text User Interface) proporciona una interfaz de texto interactiva para configurar conexiones, hostname y DNS. Es más accesible que nmcli para usuarios con menos experiencia.", command: "nmtui" },
          { id: 80, category: "Herramientas esenciales", level: "básico", question: "¿Qué comando muestra información completa sobre el kernel, hostname y arquitectura del sistema?", options: ["hostname -a", "uname -a", "lsb_release -a", "systemctl status"], correctAnswer: 1, explanation: "uname -a (all) muestra toda la información del sistema: nombre kernel, hostname, versión kernel, fecha, arquitectura. uname -r solo el kernel. cat /etc/os-release muestra la distribución.", command: "uname -a" },
          { id: 81, category: "Repositorios y dnf", level: "medio", question: "¿Qué comando verifica la integridad de los archivos del paquete httpd comparando con la base de datos RPM?", options: ["rpm -q httpd", "rpm -V httpd", "dnf check httpd", "rpm -qi httpd"], correctAnswer: 1, explanation: "rpm -V (verify) comprueba que los archivos del paquete no han sido modificados. Muestra diferencias con letras: S=tamaño, M=permisos, T=timestamp, 5=checksum. Muy útil para detectar archivos modificados.", command: "rpm -V httpd" },
          { id: 82, category: "Repositorios y dnf", level: "básico", question: "¿Qué comando determina a qué paquete RPM pertenece el archivo /usr/sbin/httpd?", options: ["dnf provides /usr/sbin/httpd", "rpm -qf /usr/sbin/httpd", "dnf info httpd", "rpm -qi httpd"], correctAnswer: 1, explanation: "rpm -qf (query file) muestra el paquete que instaló ese archivo. dnf provides también funciona para buscar qué paquete proporciona un archivo o funcionalidad.", command: "rpm -qf /usr/sbin/httpd" },
          { id: 83, category: "Systemd", level: "avanzado", question: "¿Cómo se definen variables de entorno en un unit file de systemd para un servicio?", options: ["ENV=variable en /etc/environment", "Environment=\"KEY=value\" en la sección [Service]", "export KEY=value en /etc/profile.d/", "Variables en /etc/sysconfig/nombre_servicio"], correctAnswer: 1, explanation: "En los unit files de systemd se usa la directiva Environment=\"KEY=value\" en [Service]. Para cargar múltiples variables desde un archivo usa EnvironmentFile=/ruta/archivo.", command: "# En /etc/systemd/system/myapp.service:\n[Service]\nEnvironment=\"DB_HOST=localhost\"\nEnvironmentFile=/etc/myapp/config" },
          { id: 84, category: "Almacenamiento", level: "avanzado", question: "¿Qué opciones de /etc/fstab son recomendadas para recursos NFS para evitar fallos en el arranque si el servidor no está disponible?", options: ["nofail", "_netdev", "nofail,_netdev", "noauto,nofail"], correctAnswer: 2, explanation: "_netdev indica que el montaje requiere red (espera a que la red esté activa). nofail ignora errores de montaje. Juntos son ideales para NFS: espera a la red y no falla si el servidor no responde.", command: "server:/export /mnt/nfs nfs defaults,_netdev,nofail 0 0" },
          { id: 85, category: "SELinux", level: "avanzado", question: "¿Qué herramienta analiza los mensajes AVC de SELinux y sugiere comandos o módulos de política para resolver las denegaciones?", options: ["audit2deny", "audit2allow", "sealert", "semodule"], correctAnswer: 1, explanation: "audit2allow lee logs de denegación AVC de /var/log/audit/audit.log y genera módulos de política SELinux o sugiere setsebool/semanage para resolver las denegaciones.", command: "ausearch -m avc -ts recent | audit2allow -m mypolicy" },
          { id: 86, category: "Herramientas esenciales", level: "básico", question: "¿Qué comando muestra el espacio en disco usado por cada subdirectorio inmediato de /var de forma legible?", options: ["df /var", "du -sh /var/*", "ls -lR /var", "find /var -type d -size"], correctAnswer: 1, explanation: "du -sh /var/*: -s=summary (un total por directorio), -h=human readable (KB, MB, GB). df muestra el uso del filesystem completo. Du es la herramienta correcta para ver uso por directorio.", command: "du -sh /var/*" },
          { id: 87, category: "Procesos", level: "medio", question: "¿Qué señal de kill fuerza la terminación inmediata del proceso sin permitirle hacer limpieza?", options: ["kill -15 PID (SIGTERM)", "kill -9 PID (SIGKILL)", "kill -1 PID (SIGHUP)", "kill -2 PID (SIGINT)"], correctAnswer: 1, explanation: "SIGKILL (9) mata el proceso inmediatamente, el kernel lo termina sin darle oportunidad de limpieza. SIGTERM (15) es la señal normal que el proceso puede capturar y manejar. SIGHUP (1) recarga configuración.", command: "kill -9 1234" },
          { id: 88, category: "Procesos", level: "básico", question: "¿Qué símbolo al final de un comando lo lanza en segundo plano (background)?", options: ["comando &", "bg comando", "nohup comando", "daemon comando"], correctAnswer: 0, explanation: "El símbolo '&' al final lanza el proceso en background. El shell muestra el job number y PID. 'jobs' lista procesos en background; 'fg %1' trae el job 1 al foreground; 'bg %1' lo reanuda en background.", command: "sleep 1000 &" },
          { id: 89, category: "Usuarios y grupos", level: "medio", question: "¿Qué archivo de configuración define políticas por defecto como PASS_MAX_DAYS y UID_MIN para nuevas cuentas?", options: ["/etc/sudoers", "/etc/login.defs", "/etc/passwd", "/etc/pam.d/system-auth"], correctAnswer: 1, explanation: "/etc/login.defs define parámetros por defecto: PASS_MAX_DAYS (días máx contraseña), PASS_MIN_DAYS (días mín), PASS_MIN_LEN (longitud mínima), UID_MIN (UID mínimo para usuarios), CREATE_HOME yes.", command: "grep PASS_MAX_DAYS /etc/login.defs" },
          { id: 90, category: "Redes", level: "básico", question: "¿Qué comando muestra el hostname estático actual del sistema junto con información del tipo de máquina?", options: ["hostname", "hostnamectl status", "cat /etc/hostname", "uname -n"], correctAnswer: 1, explanation: "hostnamectl status muestra hostname estático, transitorio y bonito, tipo de máquina (physical/vm), OS y kernel. hostname muestra solo el nombre. cat /etc/hostname muestra el hostname estático guardado.", command: "hostnamectl status" },
          { id: 91, category: "LVM", level: "básico", question: "¿Qué comando muestra un resumen compacto de todos los volúmenes lógicos del sistema?", options: ["lvdisplay", "lvs", "lvm list", "vgs -l"], correctAnswer: 1, explanation: "lvs muestra un resumen compacto: nombre LV, VG, atributos, tamaño. lvdisplay muestra información detallada de cada LV. vgs resume grupos de volúmenes; pvs resume volúmenes físicos.", command: "lvs" },
          { id: 92, category: "Herramientas esenciales", level: "básico", question: "¿Qué comando muestra la página del manual del comando systemctl?", options: ["info systemctl", "man systemctl", "help systemctl", "systemctl --help"], correctAnswer: 1, explanation: "man muestra la página completa del manual (más completa que --help). 'man -k palabra' busca por palabra en los títulos de man pages. En la página man: q=salir, /<texto>=buscar, n=siguiente.", command: "man systemctl" },
          { id: 93, category: "Herramientas esenciales", level: "básico", question: "¿Qué comando muestra la ruta completa del ejecutable 'httpd' según el PATH actual?", options: ["which httpd", "locate httpd", "find / -name httpd", "whereis httpd"], correctAnswer: 0, explanation: "which busca el ejecutable en el PATH y muestra su ruta completa. whereis también muestra binario, fuentes y man page. type en bash puede indicar si es alias, función o builtin.", command: "which httpd" },
          { id: 94, category: "Bash scripting", level: "avanzado", question: "¿Qué comando de Bash lee una línea desde la entrada estándar y la guarda en la variable NOMBRE?", options: ["input NOMBRE", "read NOMBRE", "get NOMBRE", "scan NOMBRE"], correctAnswer: 1, explanation: "read lee una línea de stdin y la asigna a la variable. read -p 'Texto: ' VAR muestra un prompt. read -s lee sin mostrar los caracteres (útil para contraseñas). read -t 10 VAR espera 10 segundos.", command: "read -p 'Tu nombre: ' NOMBRE && echo \"Hola, $NOMBRE\"" },
          { id: 95, category: "SELinux", level: "medio", question: "¿Cómo se configura SELinux en modo enforcing de forma permanente, que persista tras reinicios?", options: ["setenforce 1", "Editar /etc/selinux/config: SELINUX=enforcing", "systemctl enable selinux", "echo enforcing > /sys/fs/selinux/enforce"], correctAnswer: 1, explanation: "setenforce 1 cambia a enforcing solo hasta el siguiente reinicio. Para persistencia permanente, editar /etc/selinux/config y establecer SELINUX=enforcing. getenforce muestra el estado actual.", command: "# Editar /etc/selinux/config:\nSELINUX=enforcing" },
          { id: 96, category: "Herramientas esenciales", level: "medio", question: "¿Qué comando muestra los usuarios conectados actualmente, su terminal y el comando que ejecutan?", options: ["users", "w", "who", "last"], correctAnswer: 1, explanation: "w muestra usuarios conectados, su terminal, host de origen, tiempo de login y el comando que están ejecutando actualmente. who muestra solo usuarios y terminales. last muestra historial de logins.", command: "w" },
          { id: 97, category: "Redes", level: "avanzado", question: "¿Qué sintaxis de nmcli añade un servidor DNS adicional 8.8.4.4 a la conexión 'eth0' sin eliminar los existentes?", options: ["nmcli con modify eth0 ipv4.dns '8.8.4.4'", "nmcli con modify eth0 ipv4.dns +8.8.4.4", "nmcli con modify eth0 +ipv4.dns '8.8.4.4'", "nmcli con append eth0 dns 8.8.4.4"], correctAnswer: 2, explanation: "El prefijo '+' antes del nombre de la propiedad en nmcli añade el valor a los existentes sin reemplazarlos. Sin '+', el valor reemplaza todos los DNS actuales. Después ejecutar 'nmcli con up eth0'.", command: "nmcli con modify eth0 +ipv4.dns '8.8.4.4' && nmcli con up eth0" },
          { id: 98, category: "Almacenamiento", level: "avanzado", question: "¿Qué comando copia exactamente los primeros 512 bytes de /dev/sda (MBR) a un archivo de respaldo?", options: ["cp /dev/sda mbr.img", "dd if=/dev/sda of=mbr.img bs=512 count=1", "tar -czf mbr.img /dev/sda", "sfdisk -d /dev/sda > mbr.img"], correctAnswer: 1, explanation: "dd copia datos a nivel de bloque. if=fuente, of=destino, bs=tamaño bloque, count=número bloques. bs=512 count=1 copia exactamente el MBR. Para restaurar: dd if=mbr.img of=/dev/sda bs=512 count=1.", command: "dd if=/dev/sda of=mbr.img bs=512 count=1" },
          { id: 99, category: "Logs", level: "medio", question: "¿Qué opción de journalctl muestra los logs del boot anterior al actual?", options: ["journalctl -b -1", "journalctl --previous-boot", "journalctl -b 0", "journalctl --last-boot"], correctAnswer: 0, explanation: "journalctl -b -1 muestra logs del boot anterior. -b 0 o -b solo es el boot actual. -b -2 es dos boots atrás. journalctl --list-boots muestra todos los boots disponibles con sus IDs.", command: "journalctl -b -1 -u sshd" },
          { id: 100, category: "Systemd", level: "avanzado", question: "¿Qué directiva en la sección [Unit] de un unit file garantiza que el servicio arranque después de network.target?", options: ["After=network.target", "Requires=network.target", "Before=network.target", "WantedBy=network.target"], correctAnswer: 0, explanation: "After=network.target ordena el inicio: el servicio arranca después de network.target. Requires= añade dependencia fuerte (si falla la dependencia, falla el servicio). WantedBy va en [Install], no en [Unit].", command: "# En [Unit]:\nAfter=network.target\n# En [Install]:\nWantedBy=multi-user.target" }
        ],
        concepts: [
          { title: "Usuarios y grupos", description: "Gestión de cuentas de usuario y grupos en RHEL. Crear, modificar, eliminar y configurar permisos de sudo.", commands: ["useradd -m -s /bin/bash -G wheel usuario", "usermod -aG wheel usuario", "passwd usuario", "chage -M 90 usuario", "id usuario", "visudo"], typicalError: "Olvidar usar -a (append) en usermod -G, lo que elimina todos los grupos secundarios existentes del usuario.", checklist: ["Crear usuario con home y shell correctos", "Añadir a grupo wheel con -aG (no solo -G)", "Establecer contraseña con passwd", "Configurar expiración con chage", "Verificar con id usuario"] },
          { title: "Permisos Linux", description: "Permisos tradicionales de Linux: lectura, escritura, ejecución. Bits especiales SUID, SGID y sticky bit.", commands: ["chmod 755 archivo", "chmod 2775 directorio", "chmod 1777 /tmp", "chown usuario:grupo archivo", "umask 0027"], typicalError: "Confundir SUID (4) con SGID (2). SUID afecta a archivos ejecutables; SGID en directorios hace que los archivos nuevos hereden el grupo del directorio.", checklist: ["Verificar permisos con ls -l", "Usar chmod octal o simbólico", "Configurar SGID en directorios compartidos", "Ajustar umask para nuevos archivos", "Revisar propietario con chown"] },
          { title: "SELinux", description: "Security-Enhanced Linux controla el acceso mediante contextos de seguridad. Un contexto incorrecto puede bloquear un servicio aunque los permisos Linux sean correctos.", commands: ["getenforce", "setenforce 1", "ls -Z", "semanage fcontext -a -t httpd_sys_content_t '/web(/.*)?'", "restorecon -Rv /web", "ausearch -m avc -ts recent"], typicalError: "Configurar bien permisos y firewall, pero olvidar restaurar el contexto SELinux. El servicio no funciona y no se entiende por qué.", checklist: ["Revisar modo con getenforce", "Verificar contextos con ls -Z", "Añadir reglas persistentes con semanage fcontext", "Aplicar cambios con restorecon -Rv", "Consultar logs de denegación en /var/log/audit/audit.log"] },
          { title: "Firewalld", description: "Firewall dinámico de RHEL. Gestiona zonas, servicios, puertos y reglas rich. Las reglas permanentes requieren reload.", commands: ["firewall-cmd --get-active-zones", "firewall-cmd --list-all", "firewall-cmd --permanent --add-service=http", "firewall-cmd --permanent --add-port=8080/tcp", "firewall-cmd --reload"], typicalError: "Añadir una regla sin --permanent y reiniciar: la regla desaparece. O añadir con --permanent pero olvidar --reload para aplicar en la sesión actual.", checklist: ["Verificar zona activa", "Añadir reglas con --permanent", "Recargar con --reload", "Verificar con --list-all", "Comprobar conectividad"] },
          { title: "Systemd", description: "Sistema de inicio y gestión de servicios de RHEL. Unidades, targets, timers, journal y logs.", commands: ["systemctl start|stop|restart|status servicio", "systemctl enable --now servicio", "systemctl list-units --type=service --state=failed", "systemctl mask servicio", "systemctl set-default multi-user.target"], typicalError: "Habilitar un servicio con systemctl enable pero no iniciarlo. El servicio arrancará en el próximo boot, pero no está activo ahora.", checklist: ["Verificar estado con systemctl status", "Habilitar e iniciar con enable --now", "Revisar unidades fallidas", "Consultar logs con journalctl -u servicio", "Configurar target por defecto"] },
          { title: "Redes", description: "Configuración de red con NetworkManager. Conexiones, IP estática, DNS, hostname persistente.", commands: ["nmcli con show --active", "nmcli con modify eth1 ipv4.addresses 192.168.1.10/24 ipv4.method manual", "nmcli con up eth1", "hostnamectl set-hostname server.example.com", "ip addr show"], typicalError: "Configurar IP con nmcli pero olvidar ipv4.method manual, por lo que sigue usando DHCP y la IP estática no se aplica.", checklist: ["Identificar conexión activa", "Configurar IP, gateway, DNS", "Establecer método manual", "Activar conexión con con up", "Verificar con ip addr y ping"] },
          { title: "Almacenamiento y particiones", description: "Crear particiones, formatear con XFS/ext4, montar y configurar /etc/fstab para montaje persistente.", commands: ["parted /dev/sdb mklabel gpt", "parted /dev/sdb mkpart primary xfs 0% 100%", "mkfs.xfs /dev/sdb1", "blkid /dev/sdb1", "mount UUID=xxx /mnt/data"], typicalError: "Usar /dev/sdb1 en /etc/fstab en lugar de UUID. Si cambia el orden de los discos, el montaje falla o se monta en el dispositivo equivocado.", checklist: ["Crear partición con parted/fdisk", "Formatear con mkfs.xfs", "Obtener UUID con blkid", "Añadir a /etc/fstab con UUID", "Probar con mount -a"] },
          { title: "LVM", description: "Logical Volume Manager permite gestionar almacenamiento de forma flexible: PV, VG, LV, extensión en caliente.", commands: ["pvcreate /dev/sdb1", "vgcreate vg_datos /dev/sdb1", "lvcreate -L 5G -n lv_web vg_datos", "lvextend -L +2G /dev/vg_datos/lv_web", "xfs_growfs /mnt/web"], typicalError: "Extender el LV con lvextend pero olvidar expandir el filesystem. El LV tiene más espacio pero el filesystem sigue con el tamaño antiguo.", checklist: ["Crear PV, VG, LV", "Formatear y montar", "Extender LV con lvextend", "Expandir filesystem (xfs_growfs o resize2fs)", "Verificar con df -h y lvs"] },
          { title: "Swap", description: "Creación y activación de espacio de intercambio (swap). Puede ser una partición o un archivo.", commands: ["mkswap /dev/sdc1", "swapon /dev/sdc1", "echo '/dev/sdc1 swap swap defaults 0 0' >> /etc/fstab", "dd if=/dev/zero of=/swapfile bs=1M count=2048", "mkswap /swapfile && swapon /swapfile"], typicalError: "Crear un archivo swap pero olvidar ajustar los permisos a 600. Swap inseguro puede ser rechazado por el kernel.", checklist: ["Crear partición o archivo swap", "Formatear con mkswap", "Activar con swapon", "Añadir a /etc/fstab", "Verificar con swapon -s o free -h"] },
          { title: "Repositorios y dnf", description: "Gestión de paquetes con dnf. Repositorios, instalación, actualización, grupos de paquetes.", commands: ["dnf repolist", "dnf install -y httpd", "dnf groupinstall 'Development Tools'", "dnf module list nodejs", "dnf clean all"], typicalError: "Intentar instalar un paquete sin configurar repositorios. En el examen, puede ser necesario montar un DVD o configurar un repo local.", checklist: ["Verificar repositorios con dnf repolist", "Instalar paquetes con dnf install", "Usar grupos con dnf groupinstall", "Configurar repos en /etc/yum.repos.d/", "Actualizar caché si es necesario"] },
          { title: "SSH", description: "Secure Shell para acceso remoto. Configuración de claves públicas, restricciones de root, puerto.", commands: ["ssh-keygen -t rsa -b 4096", "ssh-copy-id user@remote", "ssh -p 2222 user@remote", "scp archivo user@remote:/ruta", "# /etc/ssh/sshd_config: PermitRootLogin no"], typicalError: "Generar clave SSH pero no copiarla al servidor con ssh-copy-id. El acceso sin contraseña no funciona hasta que la clave pública esté en ~/.ssh/authorized_keys.", checklist: ["Generar par de claves", "Copiar clave pública al servidor", "Verificar permisos de .ssh (700) y authorized_keys (600)", "Configurar sshd_config si es necesario", "Reiniciar sshd"] },
          { title: "Cron, at y timers", description: "Programación de tareas periódicas con cron, tareas puntuales con at, y timers de systemd.", commands: ["crontab -e", "echo '0 2 * * * /usr/local/bin/backup.sh' | crontab -", "at now + 5 minutes", "systemctl list-timers --all", "systemctl enable backup.timer"], typicalError: "Editar /etc/crontab directamente en lugar de usar crontab -e, cometiendo errores de formato o permisos.", checklist: ["Usar crontab -e para tareas de usuario", "Verificar formato: min hora día mes semana", "Usar at para tareas puntuales", "Crear timers systemd para tareas complejas", "Verificar ejecución con logs"] },
          { title: "Logs con journalctl", description: "Sistema de logs de systemd. Consulta por servicio, tiempo, prioridad, kernel.", commands: ["journalctl -u httpd", "journalctl --since '1 hour ago'", "journalctl -k", "journalctl --disk-usage", "journalctl --vacuum-time=7d"], typicalError: "Buscar logs en /var/log/messages cuando el servicio usa journald. journalctl -u servicio es la herramienta correcta.", checklist: ["Filtrar por servicio con -u", "Usar rangos de tiempo con --since/--until", "Ver logs del kernel con -k", "Gestionar espacio con --vacuum-time", "Usar -xe para ver errores recientes"] },
          { title: "NFS y autofs", description: "Montaje de recursos de red. NFS para compartir directorios, autofs para montaje automático bajo demanda.", commands: ["showmount -e server", "mount server:/export /mnt/nfs", "# /etc/auto.master: /misc /etc/auto.misc", "# /etc/auto.misc: share -rw,sync server:/exported", "systemctl enable --now autofs"], typicalError: "Configurar autofs pero olvidar activar el servicio. Los puntos de montaje no aparecen hasta que se accede a ellos y autofs está activo.", checklist: ["Verificar exportaciones con showmount", "Montar manualmente para probar", "Configurar /etc/auto.master", "Crear mapa de montajes", "Activar autofs"] },
          { title: "Recuperación del sistema", description: "Recuperar acceso root olvidado mediante rd.break, modo rescue o DVD de instalación.", commands: ["# GRUB: añadir rd.break al kernel", "mount -o remount,rw /sysroot", "chroot /sysroot", "passwd root", "touch /.autorelabel"], typicalError: "Cambiar la contraseña de root en rd.break pero olvidar touch /.autorelabel cuando SELinux está en enforcing. El sistema no arranca correctamente.", checklist: ["Editar GRUB y añadir rd.break", "Remontar /sysroot en rw", "Entrar en chroot", "Cambiar contraseña", "Forzar relabelado de SELinux"] },
          { title: "Bash scripting básico", description: "Scripts de shell para automatizar tareas. Variables, condiciones, bucles, parámetros.", commands: ["#!/bin/bash", "echo $1 $2", "if [ -f /etc/passwd ]; then ... fi", "for f in *.txt; do echo $f; done", "chmod +x script.sh"], typicalError: "Olvidar dar permisos de ejecución (chmod +x) al script. Al intentar ejecutarlo directamente sale 'Permission denied'.", checklist: ["Añadir shebang #!/bin/bash", "Usar variables y parámetros", "Verificar condiciones con if", "Dar permisos de ejecución", "Probar el script antes del examen"] },
          { title: "Procesos", description: "Gestión de procesos en Linux. Listar, terminar, priorizar y monitorizar.", commands: ["ps aux | grep httpd", "top", "kill -9 PID", "pkill -f httpd", "nice -n 10 comando"], typicalError: "Usar kill sin verificar el PID correcto. Es mejor usar pkill con el nombre del proceso para evitar matar procesos equivocados.", checklist: ["Listar procesos con ps o top", "Identificar PID correcto", "Usar kill o pkill según convenga", "Ajustar prioridad con nice/renice", "Verificar con systemctl si es un servicio"] }
        ],
        scenarios: [
          { id: 1, title: "Crear usuario con grupo secundario y permisos sudo", category: "Usuarios y grupos", difficulty: "básico", context: "Necesitas crear una cuenta para el desarrollador 'ana' con acceso administrativo mediante sudo.", objective: "Crear el usuario 'ana' con home, shell bash, grupo wheel y contraseña. Verificar que puede usar sudo.", steps: ["Crear usuario con home y shell: useradd -m -s /bin/bash ana", "Añadir al grupo wheel: usermod -aG wheel ana", "Establecer contraseña: passwd ana", "Verificar configuración: id ana", "Comprobar sudo: su - ana -c 'sudo whoami'"], recommendedCommands: ["useradd -m -s /bin/bash ana", "usermod -aG wheel ana", "passwd ana", "id ana", "visudo # verificar %wheel ALL=(ALL) ALL"], validation: "El usuario ana debe existir, pertenecer al grupo wheel y poder ejecutar sudo whoami.", commonErrors: ["Usar usermod -G wheel ana sin -a, eliminando otros grupos secundarios.", "Olvidar establecer contraseña con passwd.", "No verificar que %wheel esté descomentado en /etc/sudoers."] },
          { id: 2, title: "Crear directorio compartido con permisos especiales", category: "Permisos", difficulty: "medio", context: "Necesitas un directorio /compartido donde todos los miembros del grupo 'dev' puedan crear y editar archivos.", objective: "Crear /compartido, asignar grupo 'dev', establecer SGID y permisos 2775. Verificar que archivos nuevos heredan el grupo.", steps: ["Crear grupo: groupadd dev", "Crear directorio: mkdir /compartido", "Cambiar grupo propietario: chown :dev /compartido", "Establecer SGID + permisos: chmod 2775 /compartido", "Verificar: ls -ld /compartido y crear un archivo de prueba"], recommendedCommands: ["groupadd dev", "mkdir /compartido", "chown :dev /compartido", "chmod 2775 /compartido", "ls -ld /compartido"], validation: "ls -ld debe mostrar drwxrwsr-x. Un archivo creado por cualquier usuario debe tener grupo 'dev'.", commonErrors: ["Olvidar SGID (chmod 775 sin el 2). Los archivos nuevos heredan el grupo primario del creador.", "No crear el grupo 'dev' antes de asignarlo.", "Confundir chown usuario:grupo con chown :grupo."] },
          { id: 3, title: "Configurar IP estática con nmcli", category: "Redes", difficulty: "medio", context: "La interfaz eth1 debe tener IP estática 192.168.50.10/24, gateway 192.168.50.1 y DNS 8.8.8.8.", objective: "Configurar conexión eth1 con IP estática usando nmcli, activarla y verificar conectividad.", steps: ["Modificar IP: nmcli con modify eth1 ipv4.addresses 192.168.50.10/24", "Añadir gateway: nmcli con modify eth1 ipv4.gateway 192.168.50.1", "Añadir DNS: nmcli con modify eth1 ipv4.dns 8.8.8.8", "Deshabilitar DHCP: nmcli con modify eth1 ipv4.method manual", "Activar: nmcli con up eth1", "Verificar: ip addr show y ping 8.8.8.8"], recommendedCommands: ["nmcli con modify eth1 ipv4.addresses 192.168.50.10/24", "nmcli con modify eth1 ipv4.gateway 192.168.50.1", "nmcli con modify eth1 ipv4.dns 8.8.8.8", "nmcli con modify eth1 ipv4.method manual", "nmcli con up eth1"], validation: "ip addr show eth1 debe mostrar 192.168.50.10/24. ping a gateway y DNS debe funcionar.", commonErrors: ["Olvidar ipv4.method manual; la IP estática no se aplica porque sigue usando DHCP.", "No ejecutar nmcli con up tras modificar; los cambios no se aplican en caliente.", "Confundir la máscara: /24 no es lo mismo que /16."] },
          { id: 4, title: "Cambiar hostname de forma persistente", category: "Redes", difficulty: "básico", context: "El servidor debe llamarse server1.ejemplo.com.", objective: "Cambiar el hostname de forma persistente y actualizar /etc/hosts para que resuelva a 127.0.0.1.", steps: ["Cambiar hostname: hostnamectl set-hostname server1.ejemplo.com", "Editar /etc/hosts: añadir '127.0.0.1 server1.ejemplo.com server1'", "Verificar: hostnamectl status", "Reiniciar para confirmar persistencia (opcional en examen)"], recommendedCommands: ["hostnamectl set-hostname server1.ejemplo.com", "echo '127.0.0.1 server1.ejemplo.com server1' >> /etc/hosts", "hostnamectl status"], validation: "hostnamectl debe mostrar server1.ejemplo.com. hostname -f debe resolver correctamente.", commonErrors: ["Usar hostname sin hostnamectl; el cambio no es persistente tras reiniciar.", "No actualizar /etc/hosts; algunos servicios fallan al no resolver el propio hostname.", "Olvidar reiniciar servicios que dependen del hostname."] },
          { id: 5, title: "Crear partición, formatear y montarla en fstab", category: "Almacenamiento", difficulty: "medio", context: "Tienes un disco /dev/sdb sin particionar. Debes crear una partición, formatearla en XFS y montarla en /mnt/datos persistentemente.", objective: "Crear partición GPT en /dev/sdb, formatear en XFS, montar en /mnt/datos vía UUID en /etc/fstab.", steps: ["Crear tabla GPT: parted /dev/sdb mklabel gpt", "Crear partición: parted /dev/sdb mkpart primary xfs 0% 100%", "Formatear: mkfs.xfs /dev/sdb1", "Obtener UUID: blkid /dev/sdb1", "Crear punto de montaje: mkdir /mnt/datos", "Añadir a /etc/fstab: UUID=xxx /mnt/datos xfs defaults 0 0", "Probar: mount -a"], recommendedCommands: ["parted /dev/sdb mklabel gpt", "parted /dev/sdb mkpart primary xfs 0% 100%", "mkfs.xfs /dev/sdb1", "blkid /dev/sdb1", "mkdir /mnt/datos", "mount -a"], validation: "df -h /mnt/datos debe mostrar el filesystem. mount | grep /mnt/datos debe mostrar /dev/sdb1.", commonErrors: ["Usar /dev/sdb1 en fstab en lugar de UUID; el montaje puede fallar si cambian los nombres de dispositivo.", "No crear el punto de montaje antes de montar.", "Olvidar ejecutar mount -a para probar fstab sin reiniciar."] },
          { id: 6, title: "Crear volumen lógico LVM y extenderlo", category: "LVM", difficulty: "medio", context: "Tienes /dev/sdc sin usar. Crea un PV, un VG vg_apps, un LV lv_web de 3 GB, fórmalo en XFS y monta en /var/www. Luego extiéndelo a 5 GB.", objective: "Crear LVM completo y extenderlo en caliente, expandiendo también el filesystem XFS.", steps: ["Crear PV: pvcreate /dev/sdc", "Crear VG: vgcreate vg_apps /dev/sdc", "Crear LV: lvcreate -L 3G -n lv_web vg_apps", "Formatear: mkfs.xfs /dev/vg_apps/lv_web", "Montar: mkdir /var/www; mount /dev/vg_apps/lv_web /var/www", "Añadir a fstab con /dev/mapper/vg_apps-lv_web", "Extender: lvextend -L 5G /dev/vg_apps/lv_web", "Expandir filesystem: xfs_growfs /var/www"], recommendedCommands: ["pvcreate /dev/sdc", "vgcreate vg_apps /dev/sdc", "lvcreate -L 3G -n lv_web vg_apps", "mkfs.xfs /dev/vg_apps/lv_web", "lvextend -L 5G /dev/vg_apps/lv_web", "xfs_growfs /var/www"], validation: "lvs debe mostrar lv_web con 5G. df -h /var/www debe reflejar el nuevo tamaño.", commonErrors: ["Extender el LV pero olvidar xfs_growfs. El filesystem sigue con el tamaño original.", "Usar resize2fs en lugar de xfs_growfs para XFS.", "No añadir a /etc/fstab; el montaje desaparece al reiniciar."] },
          { id: 7, title: "Crear swap persistente", category: "Almacenamiento", difficulty: "medio", context: "Necesitas añadir 2 GB de swap usando un archivo /swapfile.", objective: "Crear archivo swap de 2 GB, activarlo y configurarlo en /etc/fstab para que sea persistente.", steps: ["Crear archivo: dd if=/dev/zero of=/swapfile bs=1M count=2048", "Permisos seguros: chmod 600 /swapfile", "Formatear: mkswap /swapfile", "Activar: swapon /swapfile", "Añadir a fstab: /swapfile swap swap defaults 0 0", "Verificar: swapon -s o free -h"], recommendedCommands: ["dd if=/dev/zero of=/swapfile bs=1M count=2048", "chmod 600 /swapfile", "mkswap /swapfile", "swapon /swapfile", "echo '/swapfile swap swap defaults 0 0' >> /etc/fstab"], validation: "swapon -s debe mostrar /swapfile. free -h debe mostrar swap aumentada.", commonErrors: ["Olvidar chmod 600 /swapfile. El kernel puede rechazar swap inseguro.", "No añadir a /etc/fstab; el swap desaparece al reiniciar.", "Usar count=2048 con bs=1M para 2GB, no count=2."] },
          { id: 8, title: "Configurar servicio httpd con firewalld", category: "Firewalld", difficulty: "básico", context: "Instala y configura Apache (httpd). Debe estar activo y accesible a través del firewall.", objective: "Instalar httpd, iniciarlo, habilitarlo en el boot y abrir el servicio en firewalld.", steps: ["Instalar: dnf install -y httpd", "Iniciar y habilitar: systemctl enable --now httpd", "Abrir firewall: firewall-cmd --permanent --add-service=http", "Recargar firewall: firewall-cmd --reload", "Verificar: curl http://localhost"], recommendedCommands: ["dnf install -y httpd", "systemctl enable --now httpd", "firewall-cmd --permanent --add-service=http", "firewall-cmd --reload", "curl http://localhost"], validation: "systemctl status httpd debe estar active. curl debe devolver HTML de la página por defecto.", commonErrors: ["Olvidar --permanent en firewall-cmd; al reiniciar el puerto se cierra.", "No ejecutar --reload tras cambios permanentes.", "No habilitar httpd con systemctl enable; no arranca en el boot."] },
          { id: 9, title: "Corregir contexto SELinux en ruta web", category: "SELinux", difficulty: "medio", context: "Has creado /webcontent para servir con Apache, pero SELinux bloquea el acceso. Los permisos Linux son correctos.", objective: "Diagnosticar el problema SELinux, añadir contexto persistente y aplicarlo.", steps: ["Verificar contexto: ls -Zd /webcontent", "Verificar logs: ausearch -m avc -ts recent", "Añadir regla persistente: semanage fcontext -a -t httpd_sys_content_t '/webcontent(/.*)?'", "Aplicar: restorecon -Rv /webcontent", "Verificar: ls -Zd /webcontent y curl http://localhost/webcontent"], recommendedCommands: ["ls -Zd /webcontent", "ausearch -m avc -ts recent", "semanage fcontext -a -t httpd_sys_content_t '/webcontent(/.*)?'", "restorecon -Rv /webcontent"], validation: "ls -Zd debe mostrar httpd_sys_content_t. curl debe acceder al contenido sin errores 403.", commonErrors: ["Usar chcon en lugar de semanage fcontext; el cambio es temporal y se pierde con restorecon.", "Olvidar la expresión regular (/.*)? que cubre subdirectorios.", "No revisar logs de SELinux para confirmar que el problema es de contexto."] },
          { id: 10, title: "Permitir puerto no estándar con SELinux y firewalld", category: "SELinux + Firewalld", difficulty: "avanzado", context: "Apache debe escuchar en el puerto 8080. Necesitas abrir el puerto en firewalld y permitirlo en SELinux.", objective: "Configurar httpd en puerto 8080, abrir firewalld, permitir el puerto en SELinux y verificar acceso.", steps: ["Editar /etc/httpd/conf.d/listen.conf: Listen 8080", "Reiniciar httpd: systemctl restart httpd", "Abrir firewalld: firewall-cmd --permanent --add-port=8080/tcp", "Recargar firewalld: firewall-cmd --reload", "Permitir SELinux: semanage port -a -t http_port_t -p tcp 8080", "Verificar: curl http://localhost:8080"], recommendedCommands: ["echo 'Listen 8080' > /etc/httpd/conf.d/listen.conf", "systemctl restart httpd", "firewall-cmd --permanent --add-port=8080/tcp", "firewall-cmd --reload", "semanage port -a -t http_port_t -p tcp 8080"], validation: "ss -tlnp debe mostrar :8080. curl a localhost:8080 debe funcionar. getenforce debe estar enforcing.", commonErrors: ["Olvidar semanage port; SELinux bloquea httpd en 8080 aunque firewall esté abierto.", "No reiniciar httpd tras cambiar la configuración de puerto.", "Usar --permanent sin --reload en firewalld."] },
          { id: 11, title: "Programar tarea con cron", category: "Tareas programadas", difficulty: "básico", context: "Necesitas que /usr/local/bin/backup.sh se ejecute todos los días a las 2:30 AM.", objective: "Programar la tarea en crontab de root y verificar que está configurada.", steps: ["Editar crontab: crontab -e", "Añadir línea: 30 2 * * * /usr/local/bin/backup.sh", "Verificar: crontab -l", "Asegurar que el script tiene permisos de ejecución: chmod +x /usr/local/bin/backup.sh"], recommendedCommands: ["crontab -e", "30 2 * * * /usr/local/bin/backup.sh", "crontab -l", "chmod +x /usr/local/bin/backup.sh"], validation: "crontab -l debe mostrar la línea. El script debe existir y ser ejecutable.", commonErrors: ["Usar /etc/crontab sin el formato correcto (requiere usuario).", "Olvidar permisos de ejecución del script.", "Error de formato: 2 30 en lugar de 30 2 (primero minutos, luego horas)."] },
          { id: 12, title: "Crear timer básico de systemd", category: "Tareas programadas", difficulty: "medio", context: "Crea un timer de systemd que ejecute /usr/local/bin/cleanup.sh cada hora.", objective: "Crear unidad .service y .timer, habilitar el timer y verificar su estado.", steps: ["Crear /etc/systemd/system/cleanup.service con [Service] ExecStart=/usr/local/bin/cleanup.sh", "Crear /etc/systemd/system/cleanup.timer con [Timer] OnCalendar=hourly", "Recargar systemd: systemctl daemon-reload", "Habilitar timer: systemctl enable --now cleanup.timer", "Verificar: systemctl list-timers --all"], recommendedCommands: ["systemctl daemon-reload", "systemctl enable --now cleanup.timer", "systemctl list-timers --all", "systemctl status cleanup.timer"], validation: "systemctl list-timers debe mostrar cleanup.timer. systemctl status debe estar active (waiting).", commonErrors: ["Olvidar systemctl daemon-reload tras crear nuevas unidades.", "No habilitar el timer (solo el service).", "Error en OnCalendar (ej. OnCalendar=*:00 en lugar de hourly)."] },
          { id: 13, title: "Configurar repositorio local con dnf", category: "Software", difficulty: "medio", context: "Montaste el DVD de RHEL en /mnt/dvd. Configura un repositorio local llamado 'dvd' para instalar paquetes sin internet.", objective: "Crear archivo .repo en /etc/yum.repos.d/ apuntando al DVD montado. Verificar con dnf repolist.", steps: ["Crear /etc/yum.repos.d/dvd.repo:\n[dvd]\nname=DVD Local\nbaseurl=file:///mnt/dvd/BaseOS\ngpgcheck=0\nenabled=1", "Verificar: dnf repolist", "Probar: dnf list available | head", "Si hay AppStream, crear segunda sección o usar --setopt"], recommendedCommands: ["dnf repolist", "dnf list available", "dnf install -y paquete"], validation: "dnf repolist debe mostrar el repositorio 'dvd'. dnf install debe poder instalar paquetes.", commonErrors: ["Ruta incorrecta en baseurl; debe apuntar al directorio que contiene repodata/.", "Olvidar gpgcheck=0 cuando no hay clave GPG disponible.", "No montar el DVD antes de usar dnf."] },
          { id: 14, title: "Montar recurso NFS", category: "NFS", difficulty: "medio", context: "El servidor nfs.ejemplo.com exporta /shared. Monta este recurso en /mnt/nfs de forma persistente.", objective: "Instalar nfs-utils, montar manualmente, añadir a /etc/fstab y verificar.", steps: ["Instalar cliente NFS: dnf install -y nfs-utils", "Crear punto de montaje: mkdir /mnt/nfs", "Montar manualmente: mount nfs.ejemplo.com:/shared /mnt/nfs", "Añadir a /etc/fstab: nfs.ejemplo.com:/shared /mnt/nfs nfs defaults 0 0", "Probar: mount -a; df -h /mnt/nfs"], recommendedCommands: ["dnf install -y nfs-utils", "mount nfs.ejemplo.com:/shared /mnt/nfs", "echo 'nfs.ejemplo.com:/shared /mnt/nfs nfs defaults 0 0' >> /etc/fstab", "mount -a"], validation: "df -h /mnt/nfs debe mostrar el recurso montado. Se debe poder leer/escribir según permisos.", commonErrors: ["No instalar nfs-utils; mount falla con 'nfs unknown filesystem type'.", "Olvidar añadir a /etc/fstab; el montaje no es persistente.", "No verificar que el servidor exporta el recurso con showmount -e."] },
          { id: 15, title: "Configurar autofs", category: "NFS", difficulty: "avanzado", context: "Configura autofs para que /misc/nfs se monte automáticamente desde nfs.ejemplo.com:/shared cuando un usuario acceda a /misc/nfs.", objective: "Configurar /etc/auto.master, crear mapa /etc/auto.misc, activar autofs y probar.", steps: ["Editar /etc/auto.master: añadir /misc /etc/auto.misc", "Crear /etc/auto.misc: nfs -rw,sync nfs.ejemplo.com:/shared", "Activar autofs: systemctl enable --now autofs", "Probar: cd /misc/nfs; ls", "Verificar: df -h /misc/nfs"], recommendedCommands: ["echo '/misc /etc/auto.misc' >> /etc/auto.master", "echo 'nfs -rw,sync nfs.ejemplo.com:/shared' > /etc/auto.misc", "systemctl enable --now autofs", "cd /misc/nfs; ls"], validation: "cd /misc/nfs debe montar automáticamente. df -h debe mostrar el recurso NFS.", commonErrors: ["No activar autofs con systemctl enable --now.", "Error en el formato del mapa (olvidar las opciones -rw,sync).", "No crear /misc antes; autofs gestiona el punto padre, no la subcarpeta."] },
          { id: 16, title: "Recuperar contraseña de root desde modo rescue", category: "Recuperación", difficulty: "avanzado", context: "Has olvidado la contraseña de root. El sistema usa SELinux en enforcing.", objective: "Usar rd.break para acceder al sistema, cambiar la contraseña de root y forzar relabelado de SELinux.", steps: ["Reiniciar, editar GRUB (e), añadir rd.break al kernel, arrancar (Ctrl+X)", "Remontar: mount -o remount,rw /sysroot", "Chroot: chroot /sysroot", "Cambiar contraseña: passwd root", "Forzar relabelado: touch /.autorelabel", "Salir: exit; exit"], recommendedCommands: ["mount -o remount,rw /sysroot", "chroot /sysroot", "passwd root", "touch /.autorelabel", "exit"], validation: "El sistema debe arrancar correctamente. Debe poder iniciar sesión como root con la nueva contraseña.", commonErrors: ["Olvidar touch /.autorelabel; SELinux impide el arranque porque /etc/shadow cambió.", "No hacer chroot /sysroot; passwd cambia la contraseña del initramfs, no del sistema real.", "No remontar /sysroot en rw; passwd falla al no poder escribir."] },
          { id: 17, title: "Consultar logs con journalctl", category: "Logs", difficulty: "básico", context: "El servicio sshd está fallando. Necesitas ver los logs recientes para diagnosticar.", objective: "Usar journalctl para ver logs de sshd, filtrar por tiempo y prioridad.", steps: ["Ver logs del servicio: journalctl -u sshd", "Ver últimos errores: journalctl -u sshd -xe", "Filtrar por tiempo: journalctl -u sshd --since '30 min ago'", "Ver todo el boot actual: journalctl -b", "Limpiar logs antiguos: journalctl --vacuum-time=7d"], recommendedCommands: ["journalctl -u sshd", "journalctl -u sshd -xe", "journalctl -u sshd --since '30 min ago'", "journalctl -b"], validation: "Debe poder identificar el error en los logs y corregir la causa (ej. permisos, configuración).", commonErrors: ["Buscar en /var/log/messages en lugar de usar journalctl para servicios systemd.", "No usar -xe para ver explicaciones de errores.", "Olvidar --since para acotar la búsqueda."] },
          { id: 18, title: "Activar servicio al arranque con systemctl", category: "Systemd", difficulty: "básico", context: "El servicio mariadb debe iniciar automáticamente cada vez que el sistema arranca.", objective: "Habilitar mariadb para el arranque y verificar que está activo.", steps: ["Habilitar e iniciar: systemctl enable --now mariadb", "Verificar estado: systemctl status mariadb", "Verificar que está enabled: systemctl is-enabled mariadb", "Comprobar que arranca en boot: ls -l /etc/systemd/system/multi-user.target.wants/mariadb.service"], recommendedCommands: ["systemctl enable --now mariadb", "systemctl status mariadb", "systemctl is-enabled mariadb"], validation: "systemctl is-enabled debe devolver 'enabled'. systemctl status debe mostrar active (running).", commonErrors: ["Usar systemctl start sin enable; el servicio no arranca en el próximo boot.", "Confundir enable con mask; mask impide totalmente el arranque.", "No verificar el estado tras habilitar."] },
          { id: 19, title: "Crear script Bash simple con parámetros", category: "Bash", difficulty: "medio", context: "Crea un script /usr/local/bin/saluda.sh que reciba un nombre como parámetro y muestre 'Hola, nombre'.", objective: "Crear script con shebang, usar parámetro $1, dar permisos de ejecución y probar.", steps: ["Crear script:\n#!/bin/bash\necho \"Hola, $1\"", "Dar permisos: chmod +x /usr/local/bin/saluda.sh", "Probar: /usr/local/bin/saluda.sh Mundo", "Verificar salida: Hola, Mundo"], recommendedCommands: ["cat > /usr/local/bin/saluda.sh << 'EOF'\n#!/bin/bash\necho \"Hola, $1\"\nEOF", "chmod +x /usr/local/bin/saluda.sh", "/usr/local/bin/saluda.sh Mundo"], validation: "El script debe ejecutarse y mostrar 'Hola, Mundo'. Debe tener permisos de ejecución.", commonErrors: ["Olvidar el shebang #!/bin/bash; el script se ejecuta con la shell actual.", "No dar permisos de ejecución con chmod +x.", "Usar $0 en lugar de $1; $0 es el nombre del script."] },
          { id: 20, title: "Configurar acceso SSH por clave pública", category: "SSH", difficulty: "medio", context: "El usuario 'developer' debe poder acceder al servidor via SSH sin contraseña usando clave pública.", objective: "Generar clave SSH, copiarla al servidor, verificar permisos y probar acceso.", steps: ["Generar clave (como developer): ssh-keygen -t rsa -b 4096", "Copiar al servidor: ssh-copy-id developer@server", "Verificar permisos en servidor: ~/.ssh debe ser 700, authorized_keys debe ser 600", "Probar: ssh developer@server (sin pedir contraseña)", "Deshabilitar password auth en /etc/ssh/sshd_config si se requiere"], recommendedCommands: ["ssh-keygen -t rsa -b 4096", "ssh-copy-id developer@server", "chmod 700 ~/.ssh", "chmod 600 ~/.ssh/authorized_keys", "ssh developer@server"], validation: "ssh developer@server debe conectar sin pedir contraseña. La clave pública debe estar en authorized_keys.", commonErrors: ["Permisos incorrectos en ~/.ssh (debe ser 700) o authorized_keys (debe ser 600).", "No copiar la clave pública (.pub) sino la privada.", "Olvidar reiniciar sshd tras cambiar sshd_config."] }
        ],
        practiceCommands: [
          { id: 1, category: "Servicios", title: "systemctl - Gestionar servicios", command: "systemctl enable --now httpd", prompt: "[root@server ~]#", description: "Habilita el servicio httpd para que inicie en el boot y lo arranca inmediatamente.", usage: "systemctl [OPTIONS...] {COMMAND} [NAME...]", examples: ["systemctl start httpd","systemctl stop httpd","systemctl restart httpd","systemctl status httpd","systemctl enable httpd","systemctl disable httpd","systemctl list-units --type=service","systemctl mask httpd","systemctl unmask httpd"], simulatedOutput: `● httpd.service - The Apache HTTP Server\n   Loaded: loaded (/usr/lib/systemd/system/httpd.service; enabled; vendor preset: disabled)\n   Active: active (running) since Mon 2024-01-15 09:23:14 EST; 2s ago\n Main PID: 4521 (httpd)\n   Status: "Started, listening on: port 80"\n    Tasks: 213 (limit: 11120)\n   Memory: 24.5M\n   CGroup: /system.slice/httpd.service\n           ├─4521 /usr/sbin/httpd -DFOREGROUND\n           ├─4522 /usr/sbin/httpd -DFOREGROUND\n           └─4523 /usr/sbin/httpd -DFOREGROUND`, manPage: `SYSTEMCTL(1)                    systemctl                    SYSTEMCTL(1)\n\nNAME\n       systemctl - Control the systemd system and service manager\n\nSYNOPSIS\n       systemctl [OPTIONS...] COMMAND [NAME...]\n\nDESCRIPTION\n       systemctl may be used to introspect and control the state of the\n       systemd system and service manager.\n\n       --now\n           Also start or stop the unit after enabling or disabling it.\n\n       enable UNIT...\n           Enable one or more units. This creates symlinks in\n           /etc/systemd/system/.\n\n       disable UNIT...\n           Disable one or more units. Removes symlinks.\n\n       start UNIT...\n           Start (activate) one or more units.\n\n       stop UNIT...\n           Stop (deactivate) one or more units.\n\n       status UNIT...\n           Show runtime status of one or more units.\n\nEXAMPLES\n       systemctl enable --now httpd\n           Enable httpd and start it immediately.\n\n       systemctl restart sshd\n           Restart the sshd service.\n\nSEE ALSO\n       systemd(1), service(8), chkconfig(8)` },
          { id: 2, category: "Red", title: "nmcli - Configurar conexiones de red", command: "nmcli con add type ethernet con-name eth1 ifname eth1 ip4 192.168.1.50/24 gw4 192.168.1.1", prompt: "[root@server ~]#", description: "Crea una conexión ethernet estática con IP, máscara y gateway.", usage: "nmcli [OPTIONS] OBJECT { COMMAND | help }", examples: ["nmcli con show --active","nmcli con modify 'Wired connection 1' ipv4.addresses 10.0.0.5/24","nmcli con modify eth1 ipv4.method manual","nmcli con modify eth1 ipv4.dns '8.8.8.8,1.1.1.1'","nmcli con up eth1","nmcli dev status","nmcli con reload"], simulatedOutput: `Connection 'eth1' (a1b2c3d4-e5f6-7890-abcd-ef1234567890) successfully added.`, manPage: `NMCLI(1)                        NetworkManager                        NMCLI(1)\n\nNAME\n       nmcli - command-line tool for controlling NetworkManager\n\nSYNOPSIS\n       nmcli [OPTIONS...] {general | networking | radio | connection |\n              device | agent | monitor} [COMMAND] [ARGUMENTS...]\n\nDESCRIPTION\n       nmcli is a command-line tool for controlling NetworkManager and\n       reporting network status.\n\n       con add\n           Add a new connection profile.\n\n       con modify ID [SETTING.PROPERTY VALUE]...\n           Modify properties of a connection profile.\n\n       con up ID\n           Activate a connection profile.\n\n       con show --active\n           Show active connection profiles.\n\nEXAMPLES\n       nmcli con add type ethernet con-name eth1 ifname eth1 ip4 192.168.1.50/24 gw4 192.168.1.1\n           Create a static ethernet connection.\n\n       nmcli con modify eth1 ipv4.dns '8.8.8.8'\n           Set DNS servers for the connection.\n\nSEE ALSO\n       NetworkManager(8), nmcli-examples(7), ip(8)` },
          { id: 3, category: "Almacenamiento", title: "LVM - Crear volumen lógico completo", command: "lvcreate -L 2G -n lv_docs vg_datos", prompt: "[root@server ~]#", description: "Crea un volumen lógico de 2 GB llamado lv_docs dentro del grupo vg_datos.", usage: "lvcreate [OPTIONS] VG_NAME", examples: ["pvcreate /dev/sdb1","vgcreate vg_datos /dev/sdb1","lvcreate -L 5G -n lv_web vg_datos","lvcreate -l 100%FREE -n lv_all vg_datos","lvextend -L +2G /dev/vg_datos/lv_docs","xfs_growfs /mnt/docs","lvs","vgs","pvs"], simulatedOutput: `Logical volume "lv_docs" created.`, manPage: `LVCREATE(8)                    LVM2 Manual                    LVCREATE(8)\n\nNAME\n       lvcreate - create a logical volume in an existing volume group\n\nSYNOPSIS\n       lvcreate [OPTIONS] VG_NAME\n\nDESCRIPTION\n       lvcreate creates a new logical volume in a volume group.\n\n       -L, --size Size[m|UNIT]\n           Gives the size to allocate for the new logical volume.\n\n       -l, --extents Number[PERCENT]\n           Gives the number of logical extents to allocate.\n\n       -n, --name String\n           The name for the new logical volume.\n\n       -l 100%FREE\n           Use all remaining free space in the volume group.\n\nEXAMPLES\n       lvcreate -L 2G -n lv_docs vg_datos\n           Create a 2GB logical volume named lv_docs.\n\n       lvcreate -l 100%FREE -n lv_all vg_datos\n           Use all remaining space.\n\nSEE ALSO\n       pvcreate(8), vgcreate(8), lvextend(8), xfs_growfs(8)` },
          { id: 4, category: "SELinux", title: "semanage + restorecon - Contexto persistente", command: "semanage fcontext -a -t httpd_sys_content_t '/webcontent(/.*)?'", prompt: "[root@server ~]#", description: "Añade una regla de contexto SELinux persistente para un directorio web personalizado.", usage: "semanage fcontext [OPTIONS] [-F file] file_spec", examples: ["semanage fcontext -a -t httpd_sys_content_t '/web(/.*)?'","semanage fcontext -m -t public_content_t '/shared(/.*)?'","restorecon -Rv /webcontent","ls -Zd /webcontent","getenforce","setenforce 1","setsebool -P httpd_enable_homedirs on"], simulatedOutput: `Relabeled /webcontent from unconfined_u:object_r:default_t:s0 to unconfined_u:object_r:httpd_sys_content_t:s0`, manPage: `SEMANAGE-FCONTEXT(8)           SELinux Policy           SEMANAGE-FCONTEXT(8)\n\nNAME\n       semanage-fcontext - SELinux Policy Management file context tool\n\nSYNOPSIS\n       semanage fcontext [OPTIONS] [-F file] file_spec\n\nDESCRIPTION\n       semanage is used to configure certain elements of SELinux policy\n       without requiring modification to or recompilation from policy\n       sources.\n\n       -a, --add\n           Add a record of the specified object type.\n\n       -m, --modify\n           Modify a record of the specified object type.\n\n       -t, --type TYPE\n           SELinux type.\n\n       -d, --delete\n           Delete a record.\n\nEXAMPLES\n       semanage fcontext -a -t httpd_sys_content_t '/web(/.*)?'\n           Add persistent context for web directory.\n\n       restorecon -Rv /web\n           Apply the context recursively.\n\nSEE ALSO\n       restorecon(8), chcon(1), setsebool(8), getenforce(8)` },
          { id: 5, category: "Firewall", title: "firewall-cmd - Gestionar reglas de firewalld", command: "firewall-cmd --permanent --add-port=8080/tcp", prompt: "[root@server ~]#", description: "Abre el puerto 8080/tcp de forma permanente en firewalld.", usage: "firewall-cmd [OPTIONS...]", examples: ["firewall-cmd --get-active-zones","firewall-cmd --list-all","firewall-cmd --permanent --add-service=http","firewall-cmd --permanent --add-port=8080/tcp","firewall-cmd --reload","firewall-cmd --remove-service=ftp","firewall-cmd --permanent --add-rich-rule='rule family=ipv4 source address=192.168.1.0/24 accept'"], simulatedOutput: `success`, manPage: `FIREWALL-CMD(1)                    firewalld                    FIREWALL-CMD(1)\n\nNAME\n       firewall-cmd - firewalld command line client\n\nSYNOPSIS\n       firewall-cmd [OPTIONS...]\n\nDESCRIPTION\n       firewall-cmd is the command line client of the firewalld daemon.\n\n       --permanent\n           Make the change permanent. Changes are applied after reload.\n\n       --add-service=service\n           Add a service to the default zone permanently or temporarily.\n\n       --add-port=portid[-portid]/protocol\n           Add a port to the default zone.\n\n       --reload\n           Reload firewalld and apply permanent changes.\n\n       --list-all\n           List everything added for the default zone.\n\nEXAMPLES\n       firewall-cmd --permanent --add-port=8080/tcp\n           Open port 8080/tcp permanently.\n\n       firewall-cmd --reload\n           Apply permanent changes.\n\nSEE ALSO\n       firewalld(1), firewall-cmd(1), firewall-config(1)` },
          { id: 6, category: "Usuarios", title: "useradd + usermod - Crear y modificar usuarios", command: "useradd -m -G wheel -c 'John Doe' johndoe", prompt: "[root@server ~]#", description: "Crea el usuario johndoe con directorio home, lo añade al grupo wheel y establece el nombre completo.", usage: "useradd [OPTIONS] LOGIN", examples: ["useradd -m -s /bin/bash alice","usermod -aG wheel alice","usermod -L alice","usermod -U alice","passwd alice","chage -M 90 alice","id alice","groups alice"], simulatedOutput: `[root@server ~]# id johndoe\nuid=1001(johndoe) gid=1001(johndoe) groups=1001(johndoe),10(wheel)`, manPage: `USERADD(8)                    System Management                    USERADD(8)\n\nNAME\n       useradd - create a new user or update default new user information\n\nSYNOPSIS\n       useradd [OPTIONS] LOGIN\n\nDESCRIPTION\n       useradd creates a new user account using the values specified on\n       the command line plus the default values from the system.\n\n       -m, --create-home\n           Create the user's home directory if it does not exist.\n\n       -G, --groups GROUP1[,GROUP2,...]\n           A list of supplementary groups which the user is also a member of.\n\n       -c, --comment COMMENT\n           Any text string, usually the user's full name.\n\n       -s, --shell SHELL\n           The name of the user's login shell.\n\n       -u, --uid UID\n           The numerical value of the user's ID.\n\nEXAMPLES\n       useradd -m -G wheel -c 'John Doe' johndoe\n           Create user with home, wheel group and full name.\n\nSEE ALSO\n       usermod(8), userdel(8), passwd(1), groupadd(8)` },
          { id: 7, category: "Permisos", title: "chmod + chown - Gestionar permisos y propiedad", command: "chmod 2775 /shared && chown :developers /shared", prompt: "[root@server ~]#", description: "Establece permisos SGID (2) + rwxrwxr-x en /shared y cambia el grupo propietario a developers.", usage: "chmod [OPTION]... MODE[,MODE]... FILE...", examples: ["chmod 755 script.sh","chmod u+x file","chmod g+s directory","chmod o+t directory","chown user:group file","chown -R user:group /directory","chmod 600 /etc/ssh/ssh_host_rsa_key","umask 0027"], simulatedOutput: `[root@server ~]# ls -ld /shared\ndrwxrwsr-x. 2 root developers 4096 Jan 15 10:00 /shared`, manPage: `CHMOD(1)                       User Commands                       CHMOD(1)\n\nNAME\n       chmod - change file mode bits\n\nSYNOPSIS\n       chmod [OPTION]... MODE[,MODE]... FILE...\n       chmod [OPTION]... OCTAL-MODE FILE...\n\nDESCRIPTION\n       chmod changes the file mode bits of each given file.\n\n       The format of a symbolic mode is [ugoa...][[+-=][perms...]...].\n\n       OCTAL-MODE:\n         4 = read (r)\n         2 = write (w)\n         1 = execute (x)\n\n       Special bits:\n         4 = SUID\n         2 = SGID\n         1 = sticky bit\n\nEXAMPLES\n       chmod 2775 /shared\n           SGID bit + rwxrwxr-x.\n\n       chmod 1777 /tmp\n           Sticky bit + rwxrwxrwx.\n\nSEE ALSO\n       chown(1), chgrp(1), umask(2), ls(1)` },
          { id: 8, category: "Recuperación", title: "rd.break - Recuperar contraseña de root", command: "mount -o remount,rw /sysroot", prompt: "switch_root:/#", description: "En modo rd.break, remonta /sysroot en lectura/escritura para poder cambiar la contraseña de root.", usage: "mount [OPTION] DEVICE DIRECTORY", examples: ["mount -o remount,rw /sysroot","chroot /sysroot","passwd root","touch /.autorelabel","exit","exit"], simulatedOutput: `switch_root:/# chroot /sysroot\nsh-5.1# passwd root\nChanging password for user root.\nNew password: ********\nRetype new password: ********\npasswd: all authentication tokens updated successfully.\nsh-5.1# touch /.autorelabel\nsh-5.1# exit\nswitch_root:/# exit`, manPage: `RD.BREAK(7)                    Kernel Boot                    RD.BREAK(7)\n\nNAME\n       rd.break - interrupt early userspace boot\n\nDESCRIPTION\n       rd.break is a kernel boot parameter that stops the initramfs boot\n       process before switching to the real root filesystem.\n\n       This allows system recovery operations such as resetting the root\n       password.\n\nRECOVERY PROCEDURE\n       1. Reboot and edit the GRUB entry (press 'e').\n       2. Append rd.break to the linux line.\n       3. Press Ctrl+X to boot.\n       4. Remount /sysroot read-write:\n          mount -o remount,rw /sysroot\n       5. Enter chroot:\n          chroot /sysroot\n       6. Change root password:\n          passwd root\n       7. Force SELinux relabel:\n          touch /.autorelabel\n       8. Exit twice to continue boot.\n\nSEE ALSO\n       grub2(8), passwd(1), chroot(1), mount(8)` },
          { id: 9, category: "Tareas programadas", title: "crontab - Programar tareas recurrentes", command: "crontab -e", prompt: "[root@server ~]#", description: "Edita la tabla de tareas cron del usuario actual para programar scripts.", usage: "crontab [OPTIONS] [FILE]", examples: ["crontab -e","crontab -l","crontab -r","echo '0 2 * * * /usr/local/bin/backup.sh' | crontab -","cat /etc/cron.d/custom","systemctl status crond"], simulatedOutput: `[root@server ~]# crontab -l\n0 2 * * * /usr/local/bin/backup.sh\n*/15 * * * * /usr/local/bin/monitor.sh`, manPage: `CRONTAB(1)                     User Commands                     CRONTAB(1)\n\nNAME\n       crontab - maintain crontab files for individual users\n\nSYNOPSIS\n       crontab [OPTIONS] [FILE]\n\nDESCRIPTION\n       crontab is the program used to install, deinstall or list the\n       tables used to drive the cron daemon.\n\n       -e     Edit the current crontab.\n       -l     List the current crontab.\n       -r     Remove the current crontab.\n\n       Format: minute hour day month weekday command\n\n       *      Any value\n       */n    Every n units\n       n      Exact value\n\nEXAMPLES\n       0 2 * * * /usr/local/bin/backup.sh\n           Run backup.sh every day at 2:00 AM.\n\n       */15 * * * * /usr/local/bin/monitor.sh\n           Run every 15 minutes.\n\nSEE ALSO\n       cron(8), crond(8), at(1)` },
          { id: 10, category: "Procesos", title: "ps + kill - Gestionar procesos", command: "ps aux | grep httpd", prompt: "[root@server ~]#", description: "Lista todos los procesos y filtra los relacionados con httpd.", usage: "ps [OPTIONS]", examples: ["ps aux","ps -ef","ps -o pid,ppid,cmd -u apache","top","kill 1234","kill -9 1234","killall httpd","pkill -f httpd","systemctl status httpd"], simulatedOutput: `root      4521  0.0  0.5  21524  5420 ?        Ss   09:23   0:00 /usr/sbin/httpd -DFOREGROUND\napache    4522  0.0  0.3  21524  3120 ?        S    09:23   0:00 /usr/sbin/httpd -DFOREGROUND\napache    4523  0.0  0.3  21524  3120 ?        S    09:23   0:00 /usr/sbin/httpd -DFOREGROUND`, manPage: `PS(1)                          User Commands                          PS(1)\n\nNAME\n       ps - report a snapshot of the current processes\n\nSYNOPSIS\n       ps [OPTIONS]\n\nDESCRIPTION\n       ps displays information about a selection of the active processes.\n\n       a      Lift the BSD-style "only yourself" restriction.\n       u      Display user-oriented format.\n       x      Lift the BSD-style "must have a tty" restriction.\n       e      Show the environment after the command.\n       f      ASCII art process hierarchy (forest).\n\n       aux    Show all processes for all users in user-oriented format.\n       -ef    Show every process in full format.\n\nEXAMPLES\n       ps aux | grep httpd\n           Find httpd processes.\n\n       kill -9 PID\n           Forcefully terminate a process.\n\nSEE ALSO\n       top(1), kill(1), pgrep(1), pkill(1), systemctl(1)` },
          { id: 11, category: "Logs", title: "journalctl - Consultar logs de systemd", command: "journalctl -u httpd --since '1 hour ago'", prompt: "[root@server ~]#", description: "Muestra los logs del servicio httpd de la última hora.", usage: "journalctl [OPTIONS...] [MATCHES...]", examples: ["journalctl","journalctl -xe","journalctl -u sshd","journalctl --since '2024-01-15 08:00' --until '2024-01-15 12:00'","journalctl -k","journalctl --disk-usage","journalctl --vacuum-time=7d"], simulatedOutput: `Jan 15 09:23:14 server httpd[4521]: AH00558: httpd: Could not reliably determine the server's fully qualified domain name\nJan 15 09:23:14 server httpd[4521]: Server configured, listening on: port 80`, manPage: `JOURNALCTL(1)                    journalctl                    JOURNALCTL(1)\n\nNAME\n       journalctl - Query the systemd journal\n\nSYNOPSIS\n       journalctl [OPTIONS...] [MATCHES...]\n\nDESCRIPTION\n       journalctl may be used to query the contents of the systemd(1)\n       journal.\n\n       -u, --unit=UNIT\n           Show logs for the specified systemd unit.\n\n       -xe\n           Show the most recent journal entries and explain errors.\n\n       --since, --until\n           Show entries newer or older than the specified time.\n\n       -k\n           Show only kernel messages.\n\nEXAMPLES\n       journalctl -u httpd --since '1 hour ago'\n           Show httpd logs from the last hour.\n\n       journalctl --vacuum-time=7d\n           Remove journal entries older than 7 days.\n\nSEE ALSO\n       systemd-journald(8), systemctl(1), dmesg(1)` },
          { id: 12, category: "SSH", title: "ssh-keygen + ssh-copy-id - Claves SSH", command: "ssh-keygen -t rsa -b 4096 -C 'admin@server'", prompt: "[student@server ~]$", description: "Genera un par de claves RSA de 4096 bits para autenticación sin contraseña.", usage: "ssh-keygen [OPTIONS]", examples: ["ssh-keygen -t ed25519","ssh-keygen -t rsa -b 4096","ssh-copy-id user@remote","ssh -i ~/.ssh/id_rsa user@remote","cat ~/.ssh/id_rsa.pub","chmod 600 ~/.ssh/id_rsa","chmod 700 ~/.ssh"], simulatedOutput: `Generating public/private rsa key pair.\nEnter file in which to save the key (/home/student/.ssh/id_rsa):\nCreated directory '/home/student/.ssh'.\nEnter passphrase (empty for no passphrase):\nYour identification has been saved in /home/student/.ssh/id_rsa\nYour public key has been saved in /home/student/.ssh/id_rsa.pub\nThe key fingerprint is:\nSHA256:abc123... admin@server`, manPage: `SSH-KEYGEN(1)                  OpenSSH tools                  SSH-KEYGEN(1)\n\nNAME\n       ssh-keygen - authentication key generation, management and conversion\n\nSYNOPSIS\n       ssh-keygen [OPTIONS]\n\nDESCRIPTION\n       ssh-keygen generates, manages and converts authentication keys for\n       ssh(1).\n\n       -t type\n           Specifies the type of key to create (rsa, dsa, ecdsa, ed25519).\n\n       -b bits\n           Specifies the number of bits in the key.\n\n       -C comment\n           Provides a comment for the key.\n\n       -f filename\n           Specifies the filename of the key file.\n\nEXAMPLES\n       ssh-keygen -t rsa -b 4096 -C 'admin@server'\n           Generate a 4096-bit RSA key.\n\n       ssh-copy-id user@remote\n           Copy public key to remote server.\n\nSEE ALSO\n       ssh(1), ssh-copy-id(1), sshd(8), authorized_keys(5)` }
        ],
        consoleMissions: [
          { id: 1, title: "Habilitar y arrancar un servicio", category: "Systemd", prompt: "[root@server ~]#", mission: "Habilita el servicio httpd para que inicie automáticamente en el arranque y arráncalo ahora mismo.", hints: ["Usa systemctl para gestionar servicios.","Necesitas dos acciones: enable y start.","Prueba con: man systemctl"], validCommands: ["systemctl enable --now httpd","systemctl enable httpd && systemctl start httpd"], manPages: { "systemctl": `SYSTEMCTL(1)                    systemctl                    SYSTEMCTL(1)\n\nNAME\n       systemctl - Control the systemd system and service manager\n\nSYNOPSIS\n       systemctl [OPTIONS...] COMMAND [NAME...]\n\nDESCRIPTION\n       systemctl may be used to introspect and control the state of the\n       systemd system and service manager.\n\n       start UNIT...     Start (activate) one or more units.\n       stop UNIT...      Stop (deactivate) one or more units.\n       enable UNIT...    Enable one or more units to start at boot.\n       --now             Also start or stop the unit after enabling/disabling.\n\nEXAMPLES\n       systemctl enable --now httpd\n           Enable httpd at boot and start it immediately.\n\nSEE ALSO\n       systemd(1), service(8)` }, successMessage: "✓ Servicio httpd habilitado y arrancado correctamente.", simulatedOutput: `Created symlink /etc/systemd/system/multi-user.target.wants/httpd.service → /usr/lib/systemd/system/httpd.service.` },
          { id: 2, title: "Configurar IP estática con nmcli", category: "Red", prompt: "[root@server ~]#", mission: "Configura la conexión 'eth1' con IP estática 192.168.1.50/24, gateway 192.168.1.1 y DNS 8.8.8.8. Luego actívala.", hints: ["Usa nmcli con modify para cambiar propiedades.","Las propiedades son ipv4.addresses, ipv4.gateway, ipv4.dns, ipv4.method.","Prueba con: man nmcli"], validCommands: ["nmcli con modify eth1 ipv4.addresses 192.168.1.50/24 ipv4.gateway 192.168.1.1 ipv4.dns 8.8.8.8 ipv4.method manual && nmcli con up eth1","nmcli con modify eth1 ipv4.addresses 192.168.1.50/24 && nmcli con modify eth1 ipv4.gateway 192.168.1.1 && nmcli con modify eth1 ipv4.dns 8.8.8.8 && nmcli con modify eth1 ipv4.method manual && nmcli con up eth1"], manPages: { "nmcli": `NMCLI(1)                        NetworkManager                        NMCLI(1)\n\nNAME\n       nmcli - command-line tool for controlling NetworkManager\n\nSYNOPSIS\n       nmcli [OPTIONS...] {general | networking | radio | connection | device | agent | monitor} [COMMAND] [ARGUMENTS...]\n\nDESCRIPTION\n       nmcli is a command-line tool for controlling NetworkManager.\n\n       con modify ID [SETTING.PROPERTY VALUE]...\n           Modify one or more properties in the connection profile.\n\n       con up ID\n           Activate a connection.\n\n       ipv4.addresses    IP address with prefix (e.g. 192.168.1.10/24)\n       ipv4.gateway      Default gateway\n       ipv4.dns          DNS servers (comma-separated)\n       ipv4.method       manual | auto (dhcp)\n\nEXAMPLES\n       nmcli con modify eth1 ipv4.addresses 192.168.1.50/24\n       nmcli con modify eth1 ipv4.gateway 192.168.1.1\n       nmcli con modify eth1 ipv4.dns 8.8.8.8\n       nmcli con modify eth1 ipv4.method manual\n       nmcli con up eth1\n\nSEE ALSO\n       NetworkManager(8), ip(8)` }, successMessage: "✓ Conexión eth1 configurada con IP estática y activada.", simulatedOutput: `Connection successfully activated (D-Bus active path: /org/freedesktop/NetworkManager/ActiveConnection/5)` },
          { id: 3, title: "Crear un volumen lógico LVM", category: "Almacenamiento", prompt: "[root@server ~]#", mission: "Crea un volumen lógico de 2 GB llamado 'lv_docs' dentro del grupo de volúmenes 'vg_datos'.", hints: ["Primero necesitas un PV y un VG (asume que ya existen).","Usa lvcreate con la opción -L para tamaño y -n para nombre.","Prueba con: man lvcreate"], validCommands: ["lvcreate -L 2G -n lv_docs vg_datos","lvcreate --size 2G --name lv_docs vg_datos"], manPages: { "lvcreate": `LVCREATE(8)                    LVM2 Manual                    LVCREATE(8)\n\nNAME\n       lvcreate - create a logical volume in an existing volume group\n\nSYNOPSIS\n       lvcreate [OPTIONS] VG_NAME\n\nDESCRIPTION\n       lvcreate creates a new logical volume in a volume group.\n\n       -L, --size Size[m|UNIT]\n           Gives the size to allocate for the new logical volume.\n\n       -n, --name String\n           The name for the new logical volume.\n\n       -l, --extents Number[PERCENT]\n           Gives the number of logical extents to allocate.\n\nEXAMPLES\n       lvcreate -L 2G -n lv_docs vg_datos\n           Create a 2GB logical volume named lv_docs.\n\n       lvcreate -l 100%FREE -n lv_all vg_datos\n           Use all remaining free space.\n\nSEE ALSO\n       pvcreate(8), vgcreate(8), lvextend(8)` }, successMessage: "✓ Volumen lógico lv_docs de 2 GB creado correctamente.", simulatedOutput: `Logical volume "lv_docs" created.` },
          { id: 4, title: "Cambiar contraseña de root en rd.break", category: "Recuperación", prompt: "sh-5.1#", mission: "Estás en modo rd.break. Ya hiciste chroot /sysroot. Ahora cambia la contraseña de root.", hints: ["El comando para cambiar contraseña es passwd.","Escribe 'passwd root' y luego la nueva contraseña.","Prueba con: man passwd"], validCommands: ["passwd root","passwd"], manPages: { "passwd": `PASSWD(1)                      User Commands                      PASSWD(1)\n\nNAME\n       passwd - update user's authentication tokens\n\nSYNOPSIS\n       passwd [OPTIONS] [USERNAME]\n\nDESCRIPTION\n       The passwd utility is used to update user's authentication token(s).\n\n       root can change any user's password. Regular users can only change\n       their own password.\n\n       When run without arguments, changes the current user's password.\n       When run with a username as argument, changes that user's password.\n\nEXAMPLES\n       passwd root\n           Change root's password.\n\n       passwd\n           Change current user's password.\n\nSEE ALSO\n       chpasswd(8), usermod(8), shadow(5)` }, successMessage: "✓ Contraseña de root actualizada correctamente.", simulatedOutput: `Changing password for user root.\nNew password: ********\nRetype new password: ********\npasswd: all authentication tokens updated successfully.` },
          { id: 5, title: "Abrir puerto en firewalld", category: "Firewall", prompt: "[root@server ~]#", mission: "Abre permanentemente el puerto 8080/tcp en firewalld y recarga la configuración.", hints: ["Usa firewall-cmd con --permanent para que sea persistente.","Después de añadir la regla, debes recargar con --reload.","Prueba con: man firewall-cmd"], validCommands: ["firewall-cmd --permanent --add-port=8080/tcp && firewall-cmd --reload","firewall-cmd --permanent --add-port=8080/tcp; firewall-cmd --reload","firewall-cmd --permanent --add-port=8080/tcp","firewall-cmd --reload"], manPages: { "firewall-cmd": `FIREWALL-CMD(1)                    firewalld                    FIREWALL-CMD(1)\n\nNAME\n       firewall-cmd - firewalld command line client\n\nSYNOPSIS\n       firewall-cmd [OPTIONS...]\n\nDESCRIPTION\n       firewall-cmd is the command line client of the firewalld daemon.\n\n       --permanent\n           Make the change permanent. Changes are applied after reload.\n\n       --add-port=portid[-portid]/protocol\n           Add a port to the default zone.\n\n       --reload\n           Reload firewalld and apply permanent changes.\n\n       --list-all\n           List everything added for the default zone.\n\nEXAMPLES\n       firewall-cmd --permanent --add-port=8080/tcp\n           Open port 8080/tcp permanently.\n\n       firewall-cmd --reload\n           Apply permanent changes.\n\nSEE ALSO\n       firewalld(1), firewall-config(1)` }, successMessage: "✓ Puerto 8080/tcp abierto permanentemente y firewalld recargado.", simulatedOutput: `success` },
          { id: 6, title: "Contexto SELinux persistente", category: "SELinux", prompt: "[root@server ~]#", mission: "Añade una regla de contexto SELinux persistente para que /webcontent y todo su contenido tenga el tipo httpd_sys_content_t.", hints: ["Usa semanage fcontext para reglas persistentes.","La expresión regular '/webcontent(/.*)?' cubre el directorio y su contenido.","Después usa restorecon -Rv para aplicar.","Prueba con: man semanage-fcontext"], validCommands: ["semanage fcontext -a -t httpd_sys_content_t '/webcontent(/.*)?' && restorecon -Rv /webcontent","semanage fcontext -a -t httpd_sys_content_t '/webcontent(/.*)?'; restorecon -Rv /webcontent"], manPages: { "semanage-fcontext": `SEMANAGE-FCONTEXT(8)           SELinux Policy           SEMANAGE-FCONTEXT(8)\n\nNAME\n       semanage-fcontext - SELinux Policy Management file context tool\n\nSYNOPSIS\n       semanage fcontext [OPTIONS] [-F file] file_spec\n\nDESCRIPTION\n       semanage is used to configure certain elements of SELinux policy.\n\n       -a, --add\n           Add a record of the specified object type.\n\n       -t, --type TYPE\n           SELinux type for the file context.\n\n       -m, --modify\n           Modify a record.\n\n       -d, --delete\n           Delete a record.\n\n       Regular expressions:\n           (/.*)?  matches the directory and all files/subdirectories.\n\nEXAMPLES\n       semanage fcontext -a -t httpd_sys_content_t '/web(/.*)?'\n           Add persistent context for web directory.\n\n       restorecon -Rv /web\n           Apply the context recursively.\n\nSEE ALSO\n       restorecon(8), chcon(1), setsebool(8)` }, successMessage: "✓ Contexto SELinux persistente añadido y aplicado correctamente.", simulatedOutput: `Relabeled /webcontent from unconfined_u:object_r:default_t:s0 to unconfined_u:object_r:httpd_sys_content_t:s0` },
          { id: 7, title: "Crear usuario con home y grupo wheel", category: "Usuarios", prompt: "[root@server ~]#", mission: "Crea el usuario 'developer' con directorio home, shell /bin/bash y añádelo al grupo wheel.", hints: ["Usa useradd con -m para crear home, -s para shell y -G para grupos.","El grupo wheel permite usar sudo.","Prueba con: man useradd"], validCommands: ["useradd -m -s /bin/bash -G wheel developer","useradd -m -G wheel -s /bin/bash developer"], manPages: { "useradd": `USERADD(8)                    System Management                    USERADD(8)\n\nNAME\n       useradd - create a new user or update default new user information\n\nSYNOPSIS\n       useradd [OPTIONS] LOGIN\n\nDESCRIPTION\n       useradd creates a new user account.\n\n       -m, --create-home\n           Create the user's home directory if it does not exist.\n\n       -s, --shell SHELL\n           The name of the user's login shell.\n\n       -G, --groups GROUP1[,GROUP2,...]\n           A list of supplementary groups.\n\n       -c, --comment COMMENT\n           Any text string, usually the full name.\n\nEXAMPLES\n       useradd -m -s /bin/bash -G wheel developer\n           Create user with home, bash shell and wheel group.\n\nSEE ALSO\n       usermod(8), passwd(1), groupadd(8)` }, successMessage: "✓ Usuario 'developer' creado con home, bash y grupo wheel.", simulatedOutput: `` },
          { id: 8, title: "Programar tarea cron", category: "Tareas programadas", prompt: "[root@server ~]#", mission: "Programa una tarea cron que ejecute /usr/local/bin/backup.sh cada día a las 2:00 AM para el usuario root.", hints: ["Usa crontab -e para editar las tareas del usuario actual.","El formato es: minuto hora día mes día_semana comando","Prueba con: man crontab"], validCommands: ["crontab -e","echo '0 2 * * * /usr/local/bin/backup.sh' | crontab -"], manPages: { "crontab": `CRONTAB(1)                     User Commands                     CRONTAB(1)\n\nNAME\n       crontab - maintain crontab files for individual users\n\nSYNOPSIS\n       crontab [OPTIONS] [FILE]\n\nDESCRIPTION\n       crontab is the program used to install, deinstall or list the\n       tables used to drive the cron daemon.\n\n       -e     Edit the current crontab using the editor.\n       -l     List the current crontab.\n       -r     Remove the current crontab.\n\n       Format: minute hour day month weekday command\n       *      Any value\n       0-59   Minutes\n       0-23   Hours\n\nEXAMPLES\n       0 2 * * * /usr/local/bin/backup.sh\n           Run backup.sh every day at 2:00 AM.\n\n       */15 * * * * /usr/local/bin/monitor.sh\n           Run every 15 minutes.\n\nSEE ALSO\n       cron(8), at(1)` }, successMessage: "✓ Tarea cron programada correctamente.", simulatedOutput: `no crontab for root - using an empty one\ncrontab: installing new crontab` },
          { id: 9, title: "Crear partición y formatear en XFS", category: "Almacenamiento", prompt: "[root@server ~]#", mission: "Crea una partición XFS en /dev/sdb1 (asume que /dev/sdb1 ya existe) y fórmatala.", hints: ["Usa mkfs.xfs para formatear.","Verifica con blkid después.","Prueba con: man mkfs.xfs"], validCommands: ["mkfs.xfs /dev/sdb1","mkfs -t xfs /dev/sdb1"], manPages: { "mkfs.xfs": `MKFS.XFS(8)                     System Manager                     MKFS.XFS(8)\n\nNAME\n       mkfs.xfs - construct an XFS filesystem\n\nSYNOPSIS\n       mkfs.xfs [OPTIONS] DEVICE\n\nDESCRIPTION\n       mkfs.xfs constructs an XFS filesystem by writing on a special\n       file using the values found in the arguments of the command line.\n\nEXAMPLES\n       mkfs.xfs /dev/sdb1\n           Create XFS filesystem on /dev/sdb1.\n\nSEE ALSO\n       xfs(5), mount(8), blkid(8)` }, successMessage: "✓ Filesystem XFS creado correctamente en /dev/sdb1.", simulatedOutput: `meta-data=/dev/sdb1              isize=512    agcount=4, agsize=65536 blks\n         =                       sectsz=512   attr=2, projid32bit=1\n         =                       crc=1        finobt=1, sparse=1, rmapbt=0\n         =                       reflink=1    bigtime=1 inobtcount=1\ndata     =                       bsize=4096   blocks=262144, imaxpct=25\n         =                       sunit=0      swidth=0 blks\nnaming   =version 2              bsize=4096   ascii-ci=0, ftype=1\nlog      =internal log           bsize=4096   blocks=2560, version=2\n         =                       sectsz=512   sunit=0 blks, lazy-count=1\nrealtime =none                   extsz=4096   blocks=0, rtextents=0\ndiscard=none` },
          { id: 10, title: "Montar por UUID en /etc/fstab", category: "Montajes", prompt: "[root@server ~]#", mission: "Añade /dev/sdb1 (UUID=abc123) al /etc/fstab para que se monte en /mnt/datos al arrancar.", hints: ["Usa echo para añadir la línea a /etc/fstab.","El formato es: UUID=xxx punto_montaje tipo opciones dump pass.","Prueba con: man fstab"], validCommands: ["echo 'UUID=abc123 /mnt/datos xfs defaults 0 0' >> /etc/fstab","echo '/dev/sdb1 /mnt/datos xfs defaults 0 0' >> /etc/fstab"], manPages: { "fstab": `FSTAB(5)                        File formats                        FSTAB(5)\n\nNAME\n       fstab - static information about the filesystems\n\nSYNOPSIS\n       /etc/fstab\n\nDESCRIPTION\n       The file fstab contains descriptive information about the filesystems.\n\n       Fields: fs_spec fs_file fs_vfstype fs_mntops fs_freq fs_passno\n\n       UUID=xxx   Use UUID instead of device name.\n       defaults   Use default mount options.\n       0 0        No dump, no fsck.\n\nEXAMPLES\n       UUID=abc123 /mnt/datos xfs defaults 0 0\n           Mount by UUID at boot.\n\nSEE ALSO\n       mount(8), blkid(8), uuid(1)` }, successMessage: "✓ Entrada añadida a /etc/fstab correctamente.", simulatedOutput: `` }
        ],
        livePracticeTasks: [
          { id: 1, title: "Crear un usuario", category: "Usuarios y grupos", task: "Crea el usuario 'ana' con directorio home y shell /bin/bash.", hints: ["Usa useradd con -m para crear el directorio home.","La opción -s establece la shell del usuario.","Ejemplo: useradd -m -s /bin/bash nombre"], validCommands: ["useradd -m -s /bin/bash ana","useradd -ms /bin/bash ana"], solution: "useradd -m -s /bin/bash ana" },
          { id: 2, title: "Añadir usuario a grupo wheel", category: "Usuarios y grupos", task: "Añade el usuario 'ana' al grupo wheel como grupo secundario.", hints: ["Usa usermod para modificar un usuario existente.","La opción -G establece grupos secundarios.","¡Importante! Usa -a (append) para no borrar otros grupos."], validCommands: ["usermod -aG wheel ana","usermod --append --groups wheel ana"], solution: "usermod -aG wheel ana" },
          { id: 3, title: "Crear un directorio", category: "Permisos", task: "Crea el directorio /datos.", hints: ["Usa mkdir para crear directorios.","Necesitas permisos de root o sudo."], validCommands: ["mkdir /datos","mkdir -p /datos"], solution: "mkdir /datos" },
          { id: 4, title: "Dar permisos 770", category: "Permisos", task: "Establece permisos 770 en el directorio /datos.", hints: ["chmod cambia permisos.","7 = rwx, 6 = rw-, 5 = r-x, 4 = r--","770 significa: rwx para propietario, rwx para grupo, --- para otros."], validCommands: ["chmod 770 /datos","chmod u=rwx,g=rwx,o= /datos"], solution: "chmod 770 /datos" },
          { id: 5, title: "Cambiar propietario de /datos", category: "Permisos", task: "Cambia el propietario de /datos al usuario 'ana' y al grupo 'dev'.", hints: ["Usa chown para cambiar propietario y grupo.","Sintaxis: chown usuario:grupo ruta","Solo root puede cambiar propietarios."], validCommands: ["chown ana:dev /datos","chown ana /datos && chgrp dev /datos"], solution: "chown ana:dev /datos" },
          { id: 6, title: "Instalar httpd", category: "Software", task: "Instala el paquete httpd (Apache) sin pedir confirmación.", hints: ["Usa dnf install.","La opción -y responde automáticamente 'yes'.","Necesitas permisos de root."], validCommands: ["dnf install -y httpd","dnf -y install httpd","dnf install httpd -y"], solution: "dnf install -y httpd" },
          { id: 7, title: "Activar httpd al arranque", category: "Systemd", task: "Habilita el servicio httpd para que arranque automáticamente y inícialo ahora.", hints: ["Usa systemctl.","enable habilita el arranque automático.","--now también lo inicia inmediatamente."], validCommands: ["systemctl enable --now httpd","systemctl enable httpd && systemctl start httpd"], solution: "systemctl enable --now httpd" },
          { id: 8, title: "Abrir http en firewalld", category: "Firewalld", task: "Abre permanentemente el servicio http en firewalld y recarga.", hints: ["Usa firewall-cmd.","--permanent hace que la regla sea persistente.","Después usa --reload para aplicar."], validCommands: ["firewall-cmd --permanent --add-service=http && firewall-cmd --reload","firewall-cmd --permanent --add-service=http; firewall-cmd --reload"], solution: "firewall-cmd --permanent --add-service=http && firewall-cmd --reload" },
          { id: 9, title: "Crear un volumen lógico", category: "LVM", task: "Crea un volumen lógico de 3 GB llamado 'lv_web' en el grupo 'vg_datos'.", hints: ["Usa lvcreate.","-L establece el tamaño (ej. 3G).","-n establece el nombre."], validCommands: ["lvcreate -L 3G -n lv_web vg_datos","lvcreate --size 3G --name lv_web vg_datos"], solution: "lvcreate -L 3G -n lv_web vg_datos" },
          { id: 10, title: "Formatear volumen en XFS", category: "Almacenamiento", task: "Formatea el volumen lógico /dev/vg_datos/lv_web con filesystem XFS.", hints: ["Usa mkfs.xfs.","Asegúrate de usar la ruta completa del dispositivo.","¡Cuidado! Esto borra cualquier dato existente."], validCommands: ["mkfs.xfs /dev/vg_datos/lv_web","mkfs -t xfs /dev/vg_datos/lv_web"], solution: "mkfs.xfs /dev/vg_datos/lv_web" },
          { id: 11, title: "Montar por UUID en fstab", category: "Montajes", task: "Añade una entrada en /etc/fstab para montar automáticamente /dev/sdb1 (UUID=abc123) en /mnt/backup con XFS.", hints: ["Usa echo para añadir la línea al archivo.","El formato es: UUID=xxx punto_montaje tipo opciones dump pass.","Usa >> para añadir al final sin sobrescribir."], validCommands: ["echo 'UUID=abc123 /mnt/backup xfs defaults 0 0' >> /etc/fstab","echo '/dev/sdb1 /mnt/backup xfs defaults 0 0' >> /etc/fstab"], solution: "echo 'UUID=abc123 /mnt/backup xfs defaults 0 0' >> /etc/fstab" },
          { id: 12, title: "Configurar IP estática", category: "Redes", task: "Configura la conexión 'eth1' con IP 192.168.10.5/24, gateway 192.168.10.1 y método manual.", hints: ["Usa nmcli con modify.","ipv4.addresses para la IP con prefijo.","ipv4.gateway para la puerta de enlace.","ipv4.method manual para desactivar DHCP."], validCommands: ["nmcli con modify eth1 ipv4.addresses 192.168.10.5/24 ipv4.gateway 192.168.10.1 ipv4.method manual","nmcli con modify eth1 ipv4.addresses 192.168.10.5/24 && nmcli con modify eth1 ipv4.gateway 192.168.10.1 && nmcli con modify eth1 ipv4.method manual"], solution: "nmcli con modify eth1 ipv4.addresses 192.168.10.5/24 ipv4.gateway 192.168.10.1 ipv4.method manual" },
          { id: 13, title: "Cambiar hostname persistente", category: "Redes", task: "Cambia el hostname del sistema a 'server1.ejemplo.com' de forma persistente.", hints: ["Usa hostnamectl.","set-hostname establece el nombre de forma persistente.","También actualiza /etc/hosts si es necesario."], validCommands: ["hostnamectl set-hostname server1.ejemplo.com","hostnamectl set-hostname server1.ejemplo.com && echo '127.0.0.1 server1.ejemplo.com server1' >> /etc/hosts"], solution: "hostnamectl set-hostname server1.ejemplo.com" },
          { id: 14, title: "Programar backup con cron", category: "Tareas programadas", task: "Programa una tarea cron para ejecutar /usr/local/bin/backup.sh todos los días a las 3:00 AM.", hints: ["Usa crontab -e para editar.","Formato: minuto hora día mes semana comando.","0 3 * * * ejecuta a las 3:00 AM diariamente."], validCommands: ["echo '0 3 * * * /usr/local/bin/backup.sh' | crontab -","crontab -e  # y añadir la línea manualmente"], solution: "echo '0 3 * * * /usr/local/bin/backup.sh' | crontab -" },
          { id: 15, title: "Crear clave SSH", category: "SSH", task: "Genera un par de claves RSA de 4096 bits para el usuario actual.", hints: ["Usa ssh-keygen.","-t rsa establece el tipo.","-b 4096 establece los bits."], validCommands: ["ssh-keygen -t rsa -b 4096","ssh-keygen -t rsa -b 4096 -C 'usuario@servidor'"], solution: "ssh-keygen -t rsa -b 4096" }
        ]
      }
    }
  },
  microsoft: {
    id: 'microsoft',
    name: 'Microsoft',
    icon: '🔷',
    certifications: {
      ai900: {
        id: 'ai900',
        name: 'AI-900 - Azure AI Fundamentals',
        shortName: 'AI-900',
        displayName: 'AI-900 / I900',
        description: 'Fundamentos de Azure AI: Machine Learning, Computer Vision, NLP, Responsible AI, Generative AI y Azure AI Services.',
        hasPractice: false,
        hasScenarios: false,
        hasConsole: false,
        hasLivePractice: false,
        questions: [
          { id: 1, certification: "ai900", category: "Conceptos básicos de IA", difficulty: "Fácil", question: "¿Qué tipo de aprendizaje automático se usa cuando el modelo aprende a partir de datos etiquetados?", options: ["Aprendizaje supervisado", "Aprendizaje no supervisado", "Aprendizaje por refuerzo", "Clustering"], correctAnswer: 0, explanation: "El aprendizaje supervisado utiliza datos etiquetados para entrenar modelos que pueden hacer predicciones o clasificaciones." },
          { id: 2, certification: "ai900", category: "Conceptos básicos de IA", difficulty: "Fácil", question: "¿Cuál de las siguientes es una técnica de aprendizaje no supervisado?", options: ["Regresión lineal", "Clasificación binaria", "Clustering", "Predicción de series temporales"], correctAnswer: 2, explanation: "El clustering es una técnica de aprendizaje no supervisado que agrupa datos similares sin etiquetas previas. La regresión, clasificación y predicción de series temporales son supervisadas." },
          { id: 3, certification: "ai900", category: "Conceptos básicos de IA", difficulty: "Fácil", question: "¿Qué es el Deep Learning?", options: ["Un algoritmo de búsqueda en grafos", "Un subconjunto de Machine Learning basado en redes neuronales profundas", "Una técnica de procesamiento de bases de datos", "Un modelo de computación cuántica"], correctAnswer: 1, explanation: "El Deep Learning es un subconjunto de Machine Learning que utiliza redes neuronales con múltiples capas (profundas) para aprender representaciones complejas de los datos." },
          { id: 4, certification: "ai900", category: "Conceptos básicos de IA", difficulty: "Fácil", question: "¿Qué tarea de Machine Learning se utiliza para predecir un valor numérico continuo?", options: ["Clasificación", "Regresión", "Clustering", "Detección de anomalías"], correctAnswer: 1, explanation: "La regresión predice valores numéricos continuos (ej. precio de una casa). La clasificación predice categorías discretas." },
          { id: 5, certification: "ai900", category: "Conceptos básicos de IA", difficulty: "Medio", question: "¿Qué tipo de modelo de IA genera nuevo contenido como texto, imágenes o código?", options: ["Modelo predictivo", "Modelo de clasificación", "IA generativa", "Modelo de detección de anomalías"], correctAnswer: 2, explanation: "La IA generativa crea nuevo contenido original basado en patrones aprendidos de datos de entrenamiento. Ejemplos: GPT, DALL-E." },
          { id: 6, certification: "ai900", category: "Conceptos básicos de IA", difficulty: "Medio", question: "En un problema de clasificación, ¿qué mide la métrica 'accuracy' (exactitud)?", options: ["La proporción de predicciones correctas sobre el total de predicciones", "La capacidad del modelo para detectar todos los positivos", "La proporción de verdaderos positivos entre todos los predichos como positivos", "El error cuadrático medio de las predicciones"], correctAnswer: 0, explanation: "La exactitud (accuracy) mide el porcentaje total de predicciones correctas (verdaderos positivos + verdaderos negativos) sobre el total de casos." },
          { id: 7, certification: "ai900", category: "Cargas de trabajo de IA en Azure", difficulty: "Fácil", question: "¿Qué servicio de Azure se utiliza para analizar y comprender el contenido de imágenes?", options: ["Azure AI Language", "Azure AI Vision", "Azure AI Speech", "Azure AI Translator"], correctAnswer: 1, explanation: "Azure AI Vision (anteriormente Computer Vision) proporciona capacidades para analizar imágenes, extraer texto (OCR), detectar objetos y describir contenido visual." },
          { id: 8, certification: "ai900", category: "Cargas de trabajo de IA en Azure", difficulty: "Fácil", question: "¿Qué carga de trabajo de IA permite a las aplicaciones comprender y responder en lenguaje natural?", options: ["Computer Vision", "Natural Language Processing (NLP)", "Azure AI Search", "Document Intelligence"], correctAnswer: 1, explanation: "El Natural Language Processing (NLP) permite a las máquinas comprender, interpretar y generar lenguaje humano. Azure AI Language es el servicio principal para NLP en Azure." },
          { id: 9, certification: "ai900", category: "Cargas de trabajo de IA en Azure", difficulty: "Medio", question: "¿Qué servicio de Azure permite crear bots conversacionales inteligentes?", options: ["Azure AI Speech", "Azure Bot Service", "Azure OpenAI Service", "Azure AI Search"], correctAnswer: 1, explanation: "Azure Bot Service permite crear, probar e implementar bots conversacionales que pueden interactuar con usuarios a través de múltiples canales." },
          { id: 10, certification: "ai900", category: "Cargas de trabajo de IA en Azure", difficulty: "Medio", question: "¿Qué es Knowledge Mining en el contexto de Azure?", options: ["Una técnica de extracción de conocimiento no estructurado de grandes volúmenes de datos", "Un algoritmo de clustering para bases de datos SQL", "Un servicio de traducción automática de documentos técnicos", "Un modelo de predicción de precios de acciones"], correctAnswer: 0, explanation: "Knowledge Mining utiliza Azure AI Search para extraer información valiosa de datos no estructurados (documentos, imágenes, etc.) aplicando IA." },
          { id: 11, certification: "ai900", category: "Cargas de trabajo de IA en Azure", difficulty: "Medio", question: "¿Qué servicio de Azure extrae información estructurada de documentos como facturas, recibos y formularios?", options: ["Azure AI Vision", "Azure AI Document Intelligence", "Azure AI Language", "Azure AI Translator"], correctAnswer: 1, explanation: "Azure AI Document Intelligence (anteriormente Form Recognizer) extrae texto, pares clave-valor, tablas y estructuras de documentos escaneados y digitales." },
          { id: 12, certification: "ai900", category: "Cargas de trabajo de IA en Azure", difficulty: "Fácil", question: "¿Qué servicio de Azure convierte audio hablado en texto escrito?", options: ["Azure AI Vision", "Azure AI Speech", "Azure AI Language", "Azure OpenAI Service"], correctAnswer: 1, explanation: "Azure AI Speech proporciona capacidades de reconocimiento de voz (speech-to-text), síntesis de voz (text-to-speech) y traducción de voz." },
          { id: 13, certification: "ai900", category: "Principios de IA responsable", difficulty: "Fácil", question: "¿Cuál de los siguientes NO es uno de los seis principios de IA responsable de Microsoft?", options: ["Equidad", "Fiabilidad y seguridad", "Velocidad de procesamiento", "Privacidad y seguridad"], correctAnswer: 2, explanation: "Los seis principios de IA responsable de Microsoft son: Equidad, Fiabilidad y seguridad, Privacidad y seguridad, Inclusión, Transparencia y Responsabilidad. La velocidad no es un principio de IA responsable." },
          { id: 14, certification: "ai900", category: "Principios de IA responsable", difficulty: "Medio", question: "¿Qué principio de IA responsable garantiza que los sistemas de IA funcionen correctamente para todos los grupos demográficos?", options: ["Transparencia", "Equidad", "Responsabilidad", "Inclusión"], correctAnswer: 1, explanation: "El principio de Equidad (Fairness) busca que los sistemas de IA traten a todas las personas de manera justa y no discriminen por razones de género, raza, edad o discapacidad." },
          { id: 15, certification: "ai900", category: "Principios de IA responsable", difficulty: "Medio", question: "¿Qué principio de IA responsable implica que los sistemas de IA sean comprensibles y explicables?", options: ["Privacidad", "Transparencia", "Fiabilidad", "Responsabilidad"], correctAnswer: 1, explanation: "La Transparencia requiere que los sistemas de IA sean comprensibles, explicables y que los usuarios comprendan cómo se toman las decisiones." },
          { id: 16, certification: "ai900", category: "Principios de IA responsable", difficulty: "Medio", question: "¿Qué principio de IA responsable asegura que las personas puedan supervisar y controlar los sistemas de IA?", options: ["Inclusión", "Responsabilidad", "Privacidad y seguridad", "Equidad"], correctAnswer: 1, explanation: "La Responsabilidad establece que las personas deben ser responsables de los sistemas de IA, con mecanismos de supervisión humana y control sobre las decisiones automatizadas." },
          { id: 17, certification: "ai900", category: "Azure Machine Learning", difficulty: "Fácil", question: "¿Qué es Azure Machine Learning?", options: ["Un servicio de base de datos relacional en la nube", "Una plataforma de servicios en la nube para entrenar, implementar y gestionar modelos de Machine Learning", "Una herramienta de visualización de datos", "Un servicio de traducción automática"], correctAnswer: 1, explanation: "Azure Machine Learning es un servicio en la nube que permite a los científicos de datos y desarrolladores construir, entrenar, implementar y gestionar modelos de ML de forma escalable." },
          { id: 18, certification: "ai900", category: "Azure Machine Learning", difficulty: "Fácil", question: "¿Qué es AutoML en Azure Machine Learning?", options: ["Un servicio de automatización de infraestructura", "Una capacidad que automatiza el proceso de selección y entrenamiento de algoritmos de ML", "Una herramienta de copia de seguridad automática", "Un servicio de monitorización de redes"], correctAnswer: 1, explanation: "AutoML (Automated Machine Learning) automatiza tareas como la selección de algoritmos, el preprocesamiento de datos y el ajuste de hiperparámetros, permitiendo crear modelos sin código o con poco código." },
          { id: 19, certification: "ai900", category: "Azure Machine Learning", difficulty: "Medio", question: "¿Qué componente de Azure Machine Learning permite crear flujos de trabajo de ML arrastrando y soltando componentes visuales?", options: ["Azure ML CLI", "Azure ML Designer", "Azure ML SDK", "Azure ML Pipelines (YAML)"], correctAnswer: 1, explanation: "Azure ML Designer es una interfaz visual de arrastrar y soltar para crear flujos de trabajo de Machine Learning sin necesidad de escribir código." },
          { id: 20, certification: "ai900", category: "Azure Machine Learning", difficulty: "Medio", question: "¿Qué métrica se utiliza comúnmente para evaluar un modelo de clasificación binaria cuando las clases están desbalanceadas?", options: ["Accuracy", "F1 Score", "R-squared", "Mean Absolute Error"], correctAnswer: 1, explanation: "El F1 Score es la media armónica de precision y recall. Es más adecuado que accuracy cuando las clases están desbalanceadas, ya que accuracy puede ser engañosa en esos casos." },
          { id: 21, certification: "ai900", category: "Azure Machine Learning", difficulty: "Medio", question: "En Azure Machine Learning, ¿qué es un 'dataset'?", options: ["Una tabla de base de datos SQL", "Una referencia a los datos utilizados para entrenar modelos, que puede provenir de diversas fuentes", "Un tipo de máquina virtual", "Un servicio de almacenamiento de blobs"], correctAnswer: 1, explanation: "Un dataset en Azure ML es una referencia abstracta a los datos que facilita su exploración, versionado y uso en experimentos de entrenamiento, sin duplicar los datos subyacentes." },
          { id: 22, certification: "ai900", category: "Azure AI Services", difficulty: "Fácil", question: "¿Qué servicio de Azure AI se utiliza para detectar el sentimiento de un texto?", options: ["Azure AI Vision", "Azure AI Language", "Azure AI Speech", "Azure AI Translator"], correctAnswer: 1, explanation: "Azure AI Language incluye capacidades de análisis de sentimiento, extracción de frases clave, reconocimiento de entidades y detección de idioma." },
          { id: 23, certification: "ai900", category: "Azure AI Services", difficulty: "Fácil", question: "¿Qué servicio de Azure permite traducir texto entre múltiples idiomas en tiempo real?", options: ["Azure AI Language", "Azure AI Translator", "Azure AI Speech", "Azure OpenAI Service"], correctAnswer: 1, explanation: "Azure AI Translator proporciona traducción automática de texto entre más de 100 idiomas, incluyendo detección de idioma y transliteración." },
          { id: 24, certification: "ai900", category: "Azure AI Services", difficulty: "Medio", question: "¿Qué servicio de Azure permite buscar información en grandes volúmenes de datos no estructurados aplicando enriquecimiento con IA?", options: ["Azure AI Vision", "Azure AI Search", "Azure AI Document Intelligence", "Azure AI Language"], correctAnswer: 1, explanation: "Azure AI Search (anteriormente Azure Cognitive Search) indexa y enriquece datos no estructurados con capacidades de IA (OCR, análisis de sentimiento, extracción de entidades) para búsquedas avanzadas." },
          { id: 25, certification: "ai900", category: "Azure AI Services", difficulty: "Medio", question: "¿Qué servicio de Azure AI se utiliza para convertir texto en voz natural?", options: ["Azure AI Speech (Text-to-Speech)", "Azure AI Language", "Azure AI Translator", "Azure OpenAI Service"], correctAnswer: 0, explanation: "Azure AI Speech incluye Text-to-Speech (TTS) que convierte texto en voz natural con múltiples voces y idiomas, incluyendo voces neuronales de alta calidad." },
          { id: 26, certification: "ai900", category: "Azure AI Services", difficulty: "Medio", question: "¿Qué servicio de Azure permite analizar documentos escaneados para extraer texto, tablas y estructuras de selección?", options: ["Azure AI Vision", "Azure AI Document Intelligence", "Azure AI Language", "Azure AI Search"], correctAnswer: 1, explanation: "Azure AI Document Intelligence utiliza modelos de ML para extraer texto, tablas, pares clave-valor y estructuras de selección de documentos escaneados, PDFs e imágenes." },
          { id: 27, certification: "ai900", category: "Azure AI Services", difficulty: "Medio", question: "¿Qué servicio de Azure proporciona acceso a modelos de lenguaje grandes (LLMs) como GPT-4?", options: ["Azure AI Language", "Azure OpenAI Service", "Azure AI Speech", "Azure Bot Service"], correctAnswer: 1, explanation: "Azure OpenAI Service proporciona acceso a modelos de OpenAI (GPT-4, GPT-3.5, DALL-E, Whisper) con la seguridad y escalabilidad de Azure." },
          { id: 28, certification: "ai900", category: "IA generativa", difficulty: "Fácil", question: "¿Qué es un 'prompt' en el contexto de la IA generativa?", options: ["Una alerta de seguridad del sistema", "La instrucción o entrada de texto que se proporciona a un modelo generativo para obtener una respuesta", "Un protocolo de red para transferencia de datos", "Un tipo de base de datos NoSQL"], correctAnswer: 1, explanation: "Un prompt es la entrada de texto que el usuario proporciona a un modelo de IA generativa (como GPT) para guiar la generación de una respuesta o contenido." },
          { id: 29, certification: "ai900", category: "IA generativa", difficulty: "Fácil", question: "¿Qué son los 'tokens' en el contexto de los modelos de lenguaje como GPT?", options: ["Unidades de autenticación de seguridad", "Unidades de texto que el modelo procesa, que pueden ser palabras, partes de palabras o caracteres", "Certificados digitales de Azure", "Tipos de máquinas virtuales"], correctAnswer: 1, explanation: "Los tokens son las unidades básicas de texto que los modelos de lenguaje procesan. Pueden ser palabras completas, subpalabras o incluso caracteres individuales. El costo y los límites de contexto se miden en tokens." },
          { id: 30, certification: "ai900", category: "IA generativa", difficulty: "Medio", question: "¿Qué es RAG (Retrieval Augmented Generation) en el contexto de la IA generativa?", options: ["Un protocolo de red para IA", "Una técnica que combina la recuperación de información de una base de datos con la generación de texto para producir respuestas más precisas", "Un algoritmo de compresión de datos", "Un tipo de hardware especializado para entrenar modelos"], correctAnswer: 1, explanation: "RAG combina un sistema de recuperación de información (que busca documentos relevantes) con un modelo generativo (que produce respuestas basadas en esos documentos), reduciendo alucinaciones y mejorando la precisión." },
          { id: 31, certification: "ai900", category: "IA generativa", difficulty: "Medio", question: "¿Qué es el 'grounding' en el contexto de la IA generativa?", options: ["Un proceso de entrenamiento de modelos de visión por computadora", "La técnica de anclar las respuestas de un modelo a datos específicos y verificables", "Un método de cifrado de datos", "Un protocolo de comunicación entre servidores"], correctAnswer: 1, explanation: "El grounding ancla las respuestas del modelo a datos específicos y verificables (como documentos o bases de conocimiento), reduciendo alucinaciones y aumentando la fiabilidad." },
          { id: 32, certification: "ai900", category: "IA generativa", difficulty: "Medio", question: "¿Qué medida de seguridad en IA generativa ayuda a prevenir que el modelo genere contenido dañino o inapropiado?", options: ["Content filtering", "Data sharding", "Load balancing", "Token encryption"], correctAnswer: 0, explanation: "El content filtering (filtrado de contenido) detecta y bloquea contenido dañino, ofensivo o no deseado en las entradas y salidas de los modelos de IA generativa, como parte de las medidas de seguridad de Azure OpenAI." },
          { id: 33, certification: "ai900", category: "Computer Vision", difficulty: "Fácil", question: "¿Cuál es la diferencia entre clasificación de imágenes y detección de objetos en Computer Vision?", options: ["No hay diferencia entre ambas técnicas", "La clasificación asigna una etiqueta a toda la imagen; la detección localiza múltiples objetos con cuadros delimitadores", "La detección es siempre más precisa que la clasificación", "La clasificación usa deep learning y la detección usa reglas manuales"], correctAnswer: 1, explanation: "La clasificación de imágenes asigna una o más etiquetas a la imagen completa (ej. 'gato'). La detección de objetos localiza múltiples objetos en la imagen con bounding boxes y etiquetas para cada uno." },
          { id: 34, certification: "ai900", category: "Computer Vision", difficulty: "Medio", question: "¿Qué servicio de Azure permite entrenar modelos de visión personalizados con imágenes propias etiquetadas?", options: ["Azure AI Vision", "Azure Custom Vision", "Azure ML Designer", "Azure AI Document Intelligence"], correctAnswer: 1, explanation: "Azure Custom Vision permite entrenar modelos personalizados de clasificación de imágenes y detección de objetos usando tus propias imágenes etiquetadas, sin necesidad de experiencia profunda en Machine Learning." },
          { id: 35, certification: "ai900", category: "Computer Vision", difficulty: "Medio", question: "¿Qué capacidad de Azure AI Vision extrae texto impreso y manuscrito de imágenes y documentos?", options: ["Object Detection", "Image Analysis", "OCR (Read API)", "Spatial Analysis"], correctAnswer: 2, explanation: "La capacidad OCR de Azure AI Vision (Read API) extrae texto impreso y manuscrito de imágenes y documentos PDF. Admite múltiples idiomas y puede procesar documentos multipágina con diseños complejos." },
          { id: 36, certification: "ai900", category: "Computer Vision", difficulty: "Medio", question: "¿Qué servicio de Azure AI detecta, analiza y puede reconocer rostros en imágenes?", options: ["Azure AI Vision", "Azure AI Face", "Azure Custom Vision", "Azure AI Document Intelligence"], correctAnswer: 1, explanation: "Azure AI Face proporciona detección facial (localiza rostros), análisis de atributos faciales (edad estimada, expresión) y verificación/identificación facial para reconocimiento de personas." },
          { id: 37, certification: "ai900", category: "Azure AI Services", difficulty: "Medio", question: "¿Qué característica de Azure AI Language extrae los conceptos y frases más importantes de un texto?", options: ["Análisis de sentimiento", "Reconocimiento de entidades", "Extracción de frases clave", "Detección de idioma"], correctAnswer: 2, explanation: "La extracción de frases clave identifica los conceptos principales de un texto. El análisis de sentimiento evalúa positividad/negatividad. El NER identifica personas, lugares y organizaciones en el texto." },
          { id: 38, certification: "ai900", category: "Azure AI Services", difficulty: "Fácil", question: "¿Qué es el Reconocimiento de Entidades con Nombre (NER) en Azure AI Language?", options: ["Un método para detectar el idioma de un texto", "La capacidad de identificar y categorizar entidades como personas, lugares u organizaciones en texto", "La traducción automática de nombres propios", "Un algoritmo de cifrado de datos personales"], correctAnswer: 1, explanation: "NER identifica y categoriza entidades en texto: personas, organizaciones, lugares, fechas, cantidades, correos, URLs, etc. Es fundamental para extraer información estructurada de texto no estructurado." },
          { id: 39, certification: "ai900", category: "Azure AI Services", difficulty: "Medio", question: "¿Qué capacidad de Azure AI Language permite entrenar modelos personalizados para reconocer intenciones y entidades en conversaciones?", options: ["CLU (Conversational Language Understanding)", "Azure AI Speech", "Azure AI Translator", "Azure Bot Service"], correctAnswer: 0, explanation: "CLU (Conversational Language Understanding), parte de Azure AI Language, permite entrenar modelos para reconocer intenciones (intents) y extraer entidades de expresiones de usuario en aplicaciones conversacionales." },
          { id: 40, certification: "ai900", category: "Azure AI Services", difficulty: "Medio", question: "¿Qué servicio de Azure permite crear una base de conocimiento de preguntas y respuestas para responder consultas en lenguaje natural?", options: ["Custom Question Answering (Azure AI Language)", "Azure OpenAI Service", "Azure AI Translator", "Azure Bot Service"], correctAnswer: 0, explanation: "Custom Question Answering, parte de Azure AI Language, crea bases de conocimiento a partir de documentos o FAQs y responde preguntas en lenguaje natural. Anteriormente conocido como QnA Maker." },
          { id: 41, certification: "ai900", category: "Azure AI Services", difficulty: "Fácil", question: "¿Qué función de Azure AI Speech genera audio hablado a partir de texto escrito?", options: ["Text-to-Speech (TTS)", "Speech-to-Text (STT)", "Speech Translation", "Custom Speech"], correctAnswer: 0, explanation: "Text-to-Speech (TTS) convierte texto en audio hablado con voces neurales de alta calidad en múltiples idiomas. Custom Neural Voice permite crear voces personalizadas. Es parte de Azure AI Speech." },
          { id: 42, certification: "ai900", category: "Azure AI Services", difficulty: "Medio", question: "¿Qué función de Azure AI Speech traduce audio hablado de un idioma a texto en otro idioma en tiempo real?", options: ["Speech-to-Text", "Text-to-Speech", "Speech Translation", "Custom Speech"], correctAnswer: 2, explanation: "Speech Translation convierte audio hablado de un idioma directamente al texto de otro idioma, o incluso a audio en el idioma destino. Ideal para aplicaciones de traducción simultánea en tiempo real." },
          { id: 43, certification: "ai900", category: "Azure Machine Learning", difficulty: "Medio", question: "¿Qué técnica de evaluación de ML divide los datos en k subconjuntos para obtener una estimación más robusta del rendimiento del modelo?", options: ["Train-test split simple", "Validación cruzada (k-fold cross-validation)", "Bootstrap sampling", "Hold-out validation"], correctAnswer: 1, explanation: "La validación cruzada (k-fold) divide el dataset en k partes. El modelo se entrena k veces: cada vez usa k-1 partes para entrenamiento y 1 para validación. El resultado final es la media de las k evaluaciones." },
          { id: 44, certification: "ai900", category: "Azure Machine Learning", difficulty: "Medio", question: "¿Qué problema ocurre cuando un modelo aprende tan bien los datos de entrenamiento que pierde capacidad de generalizar con datos nuevos?", options: ["Underfitting (subajuste)", "Overfitting (sobreajuste)", "Data leakage", "Class imbalance"], correctAnswer: 1, explanation: "El overfitting ocurre cuando el modelo 'memoriza' los datos de entrenamiento (incluyendo el ruido) en lugar de aprender patrones generales. Resultado: alta precisión en train, baja en datos de validación o nuevos." },
          { id: 45, certification: "ai900", category: "Azure Machine Learning", difficulty: "Medio", question: "¿Qué métrica mide la proporción de casos positivos predichos correctamente sobre todos los predichos como positivos?", options: ["Recall (sensibilidad)", "Precision (precisión)", "F1 Score", "Accuracy (exactitud)"], correctAnswer: 1, explanation: "Precision = VP / (VP + FP). Alta precision significa pocos falsos positivos. Recall = VP / (VP + FN), mide cuántos positivos reales se detectaron. F1 es la media armónica de ambos." },
          { id: 46, certification: "ai900", category: "Azure Machine Learning", difficulty: "Medio", question: "¿Qué métrica de regresión calcula el error promedio entre predicciones y valores reales en las mismas unidades que la variable objetivo?", options: ["R-squared (R²)", "Mean Absolute Error (MAE)", "Root Mean Squared Error (RMSE)", "F1 Score"], correctAnswer: 1, explanation: "MAE calcula el promedio de los errores absolutos, en las mismas unidades que la variable objetivo. RMSE penaliza más los errores grandes. R² mide qué proporción de la varianza explica el modelo (0 a 1)." },
          { id: 47, certification: "ai900", category: "Azure Machine Learning", difficulty: "Avanzado", question: "¿Qué representa el AUC (Area Under the Curve) de la curva ROC en clasificación binaria?", options: ["El error total del modelo de clasificación", "La capacidad discriminatoria del modelo: cuánto mejor que el azar clasifica (AUC=1 perfecto, AUC=0.5 aleatorio)", "El tiempo de entrenamiento del modelo", "El número de características usadas por el modelo"], correctAnswer: 1, explanation: "La curva ROC muestra el tradeoff entre True Positive Rate (sensibilidad) y False Positive Rate a diferentes umbrales. El AUC mide el área bajo esa curva: 1=clasificación perfecta, 0.5=clasificación aleatoria." },
          { id: 48, certification: "ai900", category: "Principios de IA responsable", difficulty: "Medio", question: "¿Qué herramienta de código abierto de Microsoft ayuda a evaluar y mitigar sesgos de equidad en modelos de ML?", options: ["Azure ML Monitoring", "Fairlearn", "Azure Content Safety", "Azure AI Metrics Advisor"], correctAnswer: 1, explanation: "Fairlearn es una herramienta de código abierto que ayuda a los desarrolladores a evaluar y mitigar problemas de equidad (fairness) en modelos de ML, analizando métricas de rendimiento por grupos demográficos." },
          { id: 49, certification: "ai900", category: "Principios de IA responsable", difficulty: "Medio", question: "¿Qué principio de IA responsable garantiza que los sistemas funcionen correctamente incluso en condiciones inesperadas o adversariales?", options: ["Equidad", "Fiabilidad y seguridad", "Transparencia", "Responsabilidad"], correctAnswer: 1, explanation: "Fiabilidad y seguridad garantiza que los sistemas de IA sean robustos, funcionen correctamente en condiciones inesperadas y tengan salvaguardas ante fallos, minimizando riesgos para personas." },
          { id: 50, certification: "ai900", category: "Principios de IA responsable", difficulty: "Medio", question: "¿Qué principio de IA responsable garantiza que los sistemas respeten la privacidad de los usuarios y protejan sus datos personales?", options: ["Inclusión", "Responsabilidad", "Privacidad y seguridad", "Transparencia"], correctAnswer: 2, explanation: "Privacidad y seguridad garantiza que los sistemas de IA protejan datos personales, cumplan regulaciones (GDPR, etc.) y apliquen técnicas como anonimización, datos sintéticos y control de acceso." },
          { id: 51, certification: "ai900", category: "Principios de IA responsable", difficulty: "Medio", question: "¿Qué significa el principio de Inclusión en la IA responsable de Microsoft?", options: ["Que todos los empleados participen en el desarrollo de IA", "Que los sistemas de IA empoderen y beneficien a todas las personas, incluyendo las que tienen discapacidades", "Que la IA soporte múltiples idiomas", "Que los datos de entrenamiento sean balanceados por género"], correctAnswer: 1, explanation: "Inclusión significa que los sistemas de IA deben ser diseñados para empoderar y beneficiar a todas las personas, considerando diversidad de habilidades, culturas, idiomas y necesidades de accesibilidad." },
          { id: 52, certification: "ai900", category: "IA generativa", difficulty: "Fácil", question: "¿Qué tipo de modelo de IA puede generar imágenes realistas a partir de descripciones de texto?", options: ["Modelos de clasificación de imágenes", "Modelos de difusión como DALL-E", "Modelos de regresión lineal", "Modelos de detección de anomalías"], correctAnswer: 1, explanation: "Los modelos de difusión como DALL-E (disponible en Azure OpenAI) generan imágenes de alta calidad a partir de descripciones textuales (text-to-image). También pueden editar imágenes existentes." },
          { id: 53, certification: "ai900", category: "IA generativa", difficulty: "Medio", question: "¿Qué es el 'prompt injection' en aplicaciones de IA generativa?", options: ["Un método para inyectar nuevas capacidades en modelos de ML", "Un ataque donde entradas maliciosas intentan manipular el comportamiento del modelo o eludir sus restricciones", "Un protocolo de actualización automática de modelos", "Una técnica de fine-tuning de modelos de lenguaje"], correctAnswer: 1, explanation: "El prompt injection es un ataque de seguridad donde entradas maliciosas intentan anular las instrucciones del sistema o manipular el comportamiento del modelo para realizar acciones no autorizadas." },
          { id: 54, certification: "ai900", category: "IA generativa", difficulty: "Medio", question: "¿Qué es el 'fine-tuning' de un modelo de lenguaje grande como GPT?", options: ["Optimizar los hiperparámetros del modelo original", "Entrenar adicionalmente un modelo preentrenado con datos específicos de dominio para adaptarlo a una tarea concreta", "La calibración de los parámetros de temperatura y top-p", "El proceso de comprimir el modelo para uso en edge computing"], correctAnswer: 1, explanation: "El fine-tuning adapta un modelo preentrenado (como GPT) a un caso de uso específico entrenándolo con datos adicionales del dominio. Mejora el rendimiento para tareas especializadas sin entrenar desde cero." },
          { id: 55, certification: "ai900", category: "IA generativa", difficulty: "Medio", question: "¿Qué parámetro de un modelo de lenguaje controla el nivel de aleatoriedad o creatividad en las respuestas?", options: ["Context window", "Temperature", "Token limit", "Embedding size"], correctAnswer: 1, explanation: "La temperatura (0-2 típicamente) controla la aleatoriedad: valores bajos (0-0.3) dan respuestas más deterministas y precisas; valores altos (0.7-1.5) generan respuestas más variadas y creativas." },
          { id: 56, certification: "ai900", category: "IA generativa", difficulty: "Avanzado", question: "¿Qué son los 'embeddings' en el contexto de los modelos de lenguaje?", options: ["El proceso de incrustar código dentro de un modelo", "Representaciones vectoriales numéricas del texto que capturan su significado semántico en un espacio de alta dimensión", "Un tipo de capa en una red neuronal convolucional", "Un método de compresión de datos de entrenamiento"], correctAnswer: 1, explanation: "Los embeddings son vectores numéricos de texto (palabras, frases, documentos) donde textos semánticamente similares tienen vectores cercanos. Son la base de la búsqueda semántica, RAG y tareas de similitud." },
          { id: 57, certification: "ai900", category: "Azure AI Services", difficulty: "Fácil", question: "¿Cómo se autentican las llamadas a la API de Azure AI Services?", options: ["Solo con Azure Active Directory (Entra ID)", "Con una clave de suscripción (API key) y el endpoint del servicio", "Con nombre de usuario y contraseña del portal de Azure", "Solo con certificados SSL/TLS"], correctAnswer: 1, explanation: "Azure AI Services se autentican principalmente con una clave de suscripción (API key) en el header Ocp-Apim-Subscription-Key y el endpoint. También se puede usar autenticación con Azure AD para mayor seguridad." },
          { id: 58, certification: "ai900", category: "Azure AI Services", difficulty: "Medio", question: "¿Cuál es la ventaja de un recurso 'Azure AI Services' multi-servicio frente a recursos de servicio único?", options: ["El multi-servicio siempre es más económico", "Un solo endpoint y clave de API para acceder a múltiples servicios de Azure AI, simplificando la gestión", "El multi-servicio tiene mayor rendimiento", "El multi-servicio permite fine-tuning de más modelos"], correctAnswer: 1, explanation: "Un recurso multi-servicio proporciona un único endpoint y clave para acceder a múltiples servicios (Language, Vision, Speech, etc.), simplificando la integración. Los recursos de servicio único se configuran y facturan independientemente." },
          { id: 59, certification: "ai900", category: "Cargas de trabajo de IA en Azure", difficulty: "Medio", question: "¿Qué es el análisis de sentimientos por aspecto (opinion mining) en Azure AI Language?", options: ["Detectar el idioma predominante en un texto", "Identificar opiniones dirigidas a aspectos específicos dentro del texto, como 'el servicio era rápido pero la comida estaba fría'", "Analizar el tono emocional general de un documento completo", "Extraer todas las frases positivas de una reseña"], correctAnswer: 1, explanation: "Opinion mining identifica sentimientos dirigidos a entidades o aspectos específicos. Ej: en 'la habitación estaba limpia pero el wifi era lento', detecta habitación:positivo y wifi:negativo de forma independiente." },
          { id: 60, certification: "ai900", category: "Cargas de trabajo de IA en Azure", difficulty: "Medio", question: "¿Qué es Azure AI Content Safety?", options: ["Un sistema de antivirus para proteger modelos de IA", "Un servicio que detecta y modera contenido potencialmente dañino en texto e imágenes", "Un firewall de red para APIs de Azure AI", "Un servicio de cifrado de datos en tránsito para Azure AI"], correctAnswer: 1, explanation: "Azure AI Content Safety detecta contenido dañino en texto e imágenes: violencia, contenido sexual, odio y autolesiones. Es fundamental para implementaciones seguras de IA generativa y aplicaciones con UGC." },
          { id: 61, certification: "ai900", category: "Cargas de trabajo de IA en Azure", difficulty: "Fácil", question: "¿Qué servicio de Microsoft permite crear chatbots conversacionales sin necesidad de escribir código mediante una interfaz gráfica?", options: ["Azure Bot Service con Bot Framework", "Microsoft Copilot Studio (antes Power Virtual Agents)", "Azure OpenAI Service", "Azure AI Language con CLU"], correctAnswer: 1, explanation: "Microsoft Copilot Studio (anteriormente Power Virtual Agents) permite crear bots conversacionales sin código mediante una interfaz gráfica de arrastrar y soltar, integrable con múltiples canales." },
          { id: 62, certification: "ai900", category: "Cargas de trabajo de IA en Azure", difficulty: "Medio", question: "¿Qué tipo de IA es más adecuado para detectar si una transacción bancaria es fraudulenta basándose en patrones históricos etiquetados?", options: ["Clasificación supervisada", "Clustering no supervisado", "IA generativa con GPT", "Aprendizaje por refuerzo"], correctAnswer: 0, explanation: "La detección de fraude con datos etiquetados (fraude/no fraude) es un problema de clasificación binaria supervisada. También puede usarse detección de anomalías no supervisada cuando no hay etiquetas disponibles." },
          { id: 63, certification: "ai900", category: "Azure Machine Learning", difficulty: "Medio", question: "¿Qué es el Model Registry en Azure Machine Learning?", options: ["Una lista de precios de los modelos de Azure AI", "Un repositorio centralizado para almacenar, versionar y gestionar el ciclo de vida de los modelos de ML entrenados", "Un sistema de monitorización de modelos en producción en tiempo real", "Un catálogo de modelos preentrenados de Microsoft"], correctAnswer: 1, explanation: "El Model Registry en Azure ML permite versionar, gestionar y hacer seguimiento de modelos entrenados. Facilita comparar versiones, revertir a versiones anteriores y gestionar el despliegue a endpoints." },
          { id: 64, certification: "ai900", category: "Azure Machine Learning", difficulty: "Medio", question: "¿Qué es MLOps en el contexto de Azure Machine Learning?", options: ["Un lenguaje de programación especializado en Machine Learning", "La aplicación de prácticas DevOps (CI/CD, automatización) al ciclo de vida completo del Machine Learning", "Un protocolo de seguridad específico para modelos de ML", "Un tipo especial de algoritmo de deep learning"], correctAnswer: 1, explanation: "MLOps combina ML con prácticas DevOps para gestionar el ciclo de vida del ML de forma eficiente, reproducible y escalable: preparación de datos, entrenamiento, evaluación, despliegue y monitorización continuos." },
          { id: 65, certification: "ai900", category: "Azure Machine Learning", difficulty: "Avanzado", question: "¿Qué es el 'data drift' en modelos de ML desplegados en producción?", options: ["Un error crítico en el proceso de recopilación de datos de entrenamiento", "La degradación del rendimiento del modelo cuando la distribución de los datos reales cambia respecto a los datos de entrenamiento", "Un tipo de ataque adversarial contra modelos de ML en producción", "El sobrecalentamiento del hardware GPU durante el entrenamiento de modelos"], correctAnswer: 1, explanation: "El data drift ocurre cuando la distribución de los datos en producción cambia respecto al entrenamiento, causando degradación del rendimiento. Azure ML ofrece monitorización de data drift con alertas automáticas." },
          { id: 66, certification: "ai900", category: "IA generativa", difficulty: "Fácil", question: "¿Qué son los modelos fundacionales (foundation models) en IA?", options: ["Modelos básicos entrenados desde cero para cada tarea específica", "Modelos de gran escala preentrenados con enormes cantidades de datos que pueden adaptarse a múltiples tareas mediante prompting o fine-tuning", "Modelos diseñados exclusivamente para tareas de visión computacional", "Modelos simples de regresión estadística"], correctAnswer: 1, explanation: "Los modelos fundacionales son modelos de gran escala preentrenados con cantidades masivas de datos que pueden adaptarse a múltiples tareas sin reentrenamiento completo. Ejemplos: GPT-4, Gemini, Claude, LLaMA." },
          { id: 67, certification: "ai900", category: "IA generativa", difficulty: "Medio", question: "¿Qué API de Azure OpenAI permite crear asistentes con herramientas como intérprete de código y búsqueda en archivos?", options: ["Azure OpenAI Assistants API", "Azure OpenAI Fine-tuning API", "Azure OpenAI Embeddings API", "Azure OpenAI DALL-E API"], correctAnswer: 0, explanation: "La Assistants API permite crear asistentes con instrucciones personalizadas, herramientas integradas (code interpreter, file search) y gestión de hilos de conversación, manteniendo el estado de la sesión." },
          { id: 68, certification: "ai900", category: "Cargas de trabajo de IA en Azure", difficulty: "Medio", question: "¿Qué es la búsqueda semántica en Azure AI Search a diferencia de la búsqueda por palabras clave?", options: ["Una búsqueda que solo funciona con documentos en inglés", "Una búsqueda que comprende el significado e intención de la consulta, no solo palabras exactas", "Un tipo de búsqueda que requiere programación avanzada", "Una búsqueda cifrada para datos confidenciales"], correctAnswer: 1, explanation: "La búsqueda semántica usa modelos de lenguaje para entender el significado de la consulta y los documentos, devolviendo resultados relevantes aunque no contengan las palabras exactas de la consulta." },
          { id: 69, certification: "ai900", category: "Azure Machine Learning", difficulty: "Fácil", question: "¿Qué herramienta de Azure ML proporciona un entorno de Jupyter Notebooks gestionado para experimentación?", options: ["Azure ML Notebooks", "Azure ML Designer", "Azure ML Pipelines", "Azure ML Endpoints"], correctAnswer: 0, explanation: "Azure ML Notebooks proporciona un entorno Jupyter Notebooks gestionado en la nube, integrado con Azure ML para ejecutar experimentos, acceder a datasets y registrar modelos directamente desde el notebook." },
          { id: 70, certification: "ai900", category: "Conceptos básicos de IA", difficulty: "Medio", question: "¿Qué es el aprendizaje por refuerzo (Reinforcement Learning)?", options: ["Aprendizaje con datos etiquetados positiva y negativamente", "Un tipo de ML donde un agente aprende a tomar decisiones en un entorno mediante recompensas y penalizaciones", "Aprendizaje sin ningún tipo de retroalimentación", "Un método para aprender idiomas automáticamente"], correctAnswer: 1, explanation: "En el aprendizaje por refuerzo, un agente aprende a tomar decisiones en un entorno recibiendo recompensas (acciones buenas) o penalizaciones (acciones malas). Se usa en juegos, robótica y optimización." },
          { id: 71, certification: "ai900", category: "Conceptos básicos de IA", difficulty: "Medio", question: "¿En qué se aplica la detección de anomalías como caso de uso de Machine Learning?", options: ["Solo en detección de fraude bancario", "En mantenimiento predictivo, detección de fraude, seguridad de red y control de calidad industrial", "Exclusivamente en aplicaciones médicas", "Solo en análisis de redes sociales"], correctAnswer: 1, explanation: "La detección de anomalías identifica observaciones atípicas que se desvían del patrón normal. Aplicaciones: fraude bancario, fallos en maquinaria (mantenimiento predictivo), intrusiones de red, defectos de fabricación." },
          { id: 72, certification: "ai900", category: "Conceptos básicos de IA", difficulty: "Fácil", question: "¿Qué es una red neuronal artificial en el contexto del Machine Learning?", options: ["Una red física de computadores especializados", "Un modelo de ML compuesto de capas de nodos (neuronas artificiales) inspirado en el cerebro biológico", "Un protocolo de comunicación entre servidores de IA", "Un tipo de base de datos distribuida para almacenar modelos"], correctAnswer: 1, explanation: "Una red neuronal artificial está formada por capas de nodos (neuronas): capa de entrada, capas ocultas y capa de salida. Cada conexión tiene un peso que se ajusta durante el entrenamiento." },
          { id: 73, certification: "ai900", category: "Conceptos básicos de IA", difficulty: "Medio", question: "¿En qué consiste el transfer learning o aprendizaje por transferencia?", options: ["Transferir datos entre dos servicios de Azure Storage", "Reutilizar un modelo preentrenado para una tarea relacionada pero diferente, ahorrando tiempo y datos de entrenamiento", "Mover modelos entrenados entre regiones de Azure", "Compartir modelos entre diferentes organizaciones mediante APIs"], correctAnswer: 1, explanation: "El transfer learning aprovecha el conocimiento aprendido por un modelo preentrenado (en una tarea grande) y lo aplica a una tarea nueva relacionada pero más pequeña. Reduce la necesidad de grandes datasets." },
          { id: 74, certification: "ai900", category: "Cargas de trabajo de IA en Azure", difficulty: "Medio", question: "¿Por qué es más adecuado Azure AI Document Intelligence que Azure AI Vision OCR para extraer datos de facturas?", options: ["Document Intelligence es más rápido en todos los casos", "Document Intelligence entiende la estructura de documentos y extrae campos específicos (como importe total, fecha, proveedor) no solo texto", "Document Intelligence es gratuito y Vision OCR no", "Document Intelligence funciona offline"], correctAnswer: 1, explanation: "Azure AI Document Intelligence usa modelos especializados que comprenden la estructura de documentos como facturas, recibos y formularios, extrayendo campos con significado (no solo texto), incluyendo tablas y pares clave-valor." },
          { id: 75, certification: "ai900", category: "Azure AI Services", difficulty: "Fácil", question: "¿Cuántos idiomas puede traducir aproximadamente Azure AI Translator?", options: ["Menos de 20 idiomas", "Más de 100 idiomas", "Exactamente 50 idiomas", "Solo los 10 idiomas más hablados"], correctAnswer: 1, explanation: "Azure AI Translator soporta más de 100 idiomas para traducción de texto, con detección automática del idioma origen, transliteración (cambio de sistema de escritura) y traducción de documentos completos." },
          { id: 76, certification: "ai900", category: "Azure Machine Learning", difficulty: "Avanzado", question: "¿Qué son los pipelines de Azure Machine Learning?", options: ["Tuberías físicas de datos en los centros de datos de Azure", "Flujos de trabajo reutilizables que encadenan pasos independientes de ML: preparación de datos, entrenamiento, evaluación y registro", "Conexiones de red entre servicios de Azure AI", "Canales de comunicación entre diferentes instancias de modelos de IA"], correctAnswer: 1, explanation: "Los pipelines de Azure ML orquestan flujos de trabajo de ML en pasos independientes y reutilizables. Permiten automatización, paralelismo, reutilización de pasos y reproducibilidad del proceso de ML." },
          { id: 77, certification: "ai900", category: "IA generativa", difficulty: "Medio", question: "¿Cuál es el riesgo de las 'alucinaciones' en los modelos de lenguaje grandes (LLMs)?", options: ["Que el modelo se sobrecaliente y deje de funcionar", "Que el modelo genere información falsa, inventada o incorrecta presentada con aparente confianza", "Que el modelo tarde demasiado en generar respuestas", "Que el modelo no comprenda el idioma del usuario"], correctAnswer: 1, explanation: "Las alucinaciones son cuando un LLM genera información falsa o inventada de forma convincente. Es un riesgo crítico en aplicaciones donde la precisión es esencial. RAG y grounding ayudan a reducirlas." },
          { id: 78, certification: "ai900", category: "Principios de IA responsable", difficulty: "Medio", question: "¿Qué herramienta/técnica explica las predicciones de un modelo ML mostrando la contribución de cada característica?", options: ["Fairlearn", "SHAP / InterpretML", "Azure Content Safety", "Azure ML Data Labeling"], correctAnswer: 1, explanation: "SHAP (SHapley Additive exPlanations) e InterpretML explican las predicciones de modelos de ML mostrando la importancia de cada característica. Implementan el principio de Transparencia de la IA responsable." },
          { id: 79, certification: "ai900", category: "Cargas de trabajo de IA en Azure", difficulty: "Fácil", question: "¿Qué componente de Azure AI Search aplica habilidades de IA para enriquecer documentos durante la indexación?", options: ["Índice (Index)", "Indexador (Indexer)", "Conjunto de aptitudes (Skillset)", "Knowledge Store"], correctAnswer: 2, explanation: "Un Skillset en Azure AI Search es un conjunto de habilidades cognitivas (OCR, detección de idioma, análisis de entidades, extracción de frases clave) que enriquecen los documentos durante el proceso de indexación." },
          { id: 80, certification: "ai900", category: "Cargas de trabajo de IA en Azure", difficulty: "Medio", question: "¿Qué es el Knowledge Store en Azure AI Search?", options: ["Una base de datos de grafos de conocimiento empresarial", "Un repositorio donde se almacenan los enriquecimientos de IA generados durante la indexación para su análisis posterior con otras herramientas", "El almacenamiento interno del índice de búsqueda de Azure AI Search", "Un servicio de Azure para gestionar ontologías y taxonomías"], correctAnswer: 1, explanation: "El Knowledge Store almacena las proyecciones de datos enriquecidos por IA en Azure Storage (tablas, blobs), permitiendo analizarlos con otras herramientas como Power BI, notebooks o aplicaciones personalizadas." },
          { id: 81, certification: "ai900", category: "Azure AI Vision", difficulty: "Medio", question: "¿Qué capacidad de Azure AI Vision permite extraer texto impreso y manuscrito de imágenes y documentos PDF en múltiples idiomas?", options: ["Image Analysis", "OCR (Read API)", "Custom Vision", "Spatial Analysis"], correctAnswer: 1, explanation: "La API OCR (Read API) de Azure AI Vision extrae texto impreso y manuscrito de imágenes y documentos PDF, soportando múltiples idiomas y diseños complejos incluyendo tablas y columnas." },
          { id: 82, certification: "ai900", category: "Azure AI Speech", difficulty: "Medio", question: "¿Qué función de Azure AI Speech permite crear una voz sintética personalizada a partir de muestras de audio de un hablante específico?", options: ["Text-to-Speech estándar", "Custom Neural Voice", "Speech Translation", "Speaker Recognition"], correctAnswer: 1, explanation: "Custom Neural Voice permite crear voces sintéticas personalizadas entrenando un modelo con muestras de audio de un hablante específico. Requiere consentimiento explícito del hablante por razones éticas y legales." },
          { id: 83, certification: "ai900", category: "Azure AI Language", difficulty: "Medio", question: "¿Qué servicio de Azure AI Language permite crear una base de conocimiento de preguntas y respuestas a partir de documentos o FAQs?", options: ["Conversational Language Understanding (CLU)", "Custom Question Answering", "Text Analytics", "Language Detection"], correctAnswer: 1, explanation: "Custom Question Answering, parte de Azure AI Language, crea bases de conocimiento que responden preguntas en lenguaje natural a partir de documentos, manuales o FAQs predefinidos." },
          { id: 84, certification: "ai900", category: "Azure OpenAI", difficulty: "Avanzado", question: "¿Qué técnica de Azure OpenAI permite que un modelo LLM llame a funciones externas (APIs, bases de datos) para obtener datos actualizados?", options: ["Prompt injection", "Function calling", "Grounding", "RAG"], correctAnswer: 1, explanation: "Function calling permite que el modelo LLM genere llamadas a funciones externas definidas por el desarrollador, obteniendo datos actualizados o realizando acciones fuera del modelo." },
          { id: 85, certification: "ai900", category: "Principios de IA responsable", difficulty: "Medio", question: "¿Qué técnica se utiliza para garantizar que los datos de entrenamiento no puedan ser identificados individualmente, protegiendo la privacidad?", options: ["Data augmentation", "Differential privacy", "Cross-validation", "Feature scaling"], correctAnswer: 1, explanation: "La privacidad diferencial (differential privacy) añade ruido matemáticamente calculado a los datos para garantizar que no se pueda identificar información individual, protegiendo la privacidad sin perder utilidad estadística." },
          { id: 86, certification: "ai900", category: "Azure Machine Learning", difficulty: "Medio", question: "¿Cuál es la diferencia principal entre un endpoint de inferencia en tiempo real (real-time) y uno por lotes (batch)?", options: ["El real-time es más barato siempre", "El real-time responde inmediatamente a cada solicitud; el batch procesa grandes volúmenes de datos de forma programada", "El batch solo funciona con imágenes", "No hay diferencia funcional, solo de precio"], correctAnswer: 1, explanation: "Los endpoints real-time responden a solicitudes individuales con baja latencia. Los endpoints batch procesan grandes conjuntos de datos de forma asíncrona y programada, ideal para tareas no urgentes como informes diarios." },
          { id: 87, certification: "ai900", category: "IA generativa", difficulty: "Medio", question: "¿Qué tipo de modelo de IA puede procesar y generar simultáneamente texto, imágenes y audio?", options: ["Modelo unimodal", "Modelo multimodal", "Modelo de regresión", "Modelo de clustering"], correctAnswer: 1, explanation: "Los modelos multimodales pueden entender y generar contenido en múltiples formatos (texto, imagen, audio, vídeo). GPT-4V y Gemini son ejemplos de modelos multimodales." },
          { id: 88, certification: "ai900", category: "Azure AI Document Intelligence", difficulty: "Medio", question: "¿Qué modelo preentrenado de Azure AI Document Intelligence está especializado en extraer información de recibos y tickets de compra?", options: ["Invoice model", "Receipt model", "ID document model", "Layout model"], correctAnswer: 1, explanation: "El modelo preentrenado de recibos (Receipt model) extrae automáticamente campos como comerciante, fecha, importe total, impuestos y artículos de tickets y recibos." },
          { id: 89, certification: "ai900", category: "Azure AI Vision", difficulty: "Avanzado", question: "¿Qué servicio de Azure AI Vision analiza vídeo en tiempo real para detectar movimiento de personas en espacios físicos?", options: ["Custom Vision", "Spatial Analysis", "Image Analysis", "OCR"], correctAnswer: 1, explanation: "Spatial Analysis es una característica de Azure AI Vision que analiza vídeo de cámaras para detectar la presencia y movimiento de personas, distanciamiento social y flujo de tráfico en espacios físicos." },
          { id: 90, certification: "ai900", category: "Azure AI Speech", difficulty: "Medio", question: "¿Qué servicio de Azure AI Speech permite adaptar un modelo de reconocimiento de voz a vocabulario técnico específico de un dominio?", options: ["Text-to-Speech", "Custom Speech", "Speech Translation", "Voice Assistant"], correctAnswer: 1, explanation: "Custom Speech permite entrenar modelos de reconocimiento de voz (STT) personalizados con vocabulario, frases y datos de audio específicos de un dominio, mejorando la precisión en jerga técnica." },
          { id: 91, certification: "ai900", category: "Azure OpenAI", difficulty: "Fácil", question: "¿En qué unidades se mide el consumo y el coste de los modelos de Azure OpenAI?", options: ["Por hora de procesamiento", "Por tokens de entrada y salida", "Por número de peticiones HTTP", "Por gigabytes de datos procesados"], correctAnswer: 1, explanation: "El coste de Azure OpenAI se calcula por tokens consumidos: tokens de entrada (prompt) y tokens de salida (completado). Un token equivale aproximadamente a 4 caracteres en inglés." },
          { id: 92, certification: "ai900", category: "Azure Machine Learning", difficulty: "Avanzado", question: "¿Qué componente de Azure Machine Learning permite compartir y reutilizar características (features) entre diferentes equipos y proyectos?", options: ["Model Registry", "Feature Store", "Dataset Store", "Pipeline Cache"], correctAnswer: 1, explanation: "El Feature Store de Azure ML permite centralizar, versionar y compartir características de ML entre equipos, evitando duplicación de trabajo y garantizando consistencia entre entrenamiento e inferencia." },
          { id: 93, certification: "ai900", category: "Principios de IA responsable", difficulty: "Medio", question: "¿Qué práctica consiste en someter un modelo de IA a ataques simulados para descubrir vulnerabilidades antes de su despliegue?", options: ["Data drift monitoring", "Red teaming", "A/B testing", "Blue-green deployment"], correctAnswer: 1, explanation: "El red teaming en IA consiste en que equipos especializados intenten hacer fallar o manipular el modelo (prompt injection, jailbreaking, generación de contenido dañino) para descubrir y mitigar vulnerabilidades antes del despliegue." },
          { id: 94, certification: "ai900", category: "Azure AI Language", difficulty: "Fácil", question: "¿Qué tipo de entidad identifica el NER (Reconocimiento de Entidades con Nombre) como 'Microsoft' o 'Amazon'?", options: ["Persona", "Organización", "Ubicación", "Cantidad"], correctAnswer: 1, explanation: "NER clasifica entidades en categorías como Persona, Organización, Ubicación, Fecha, Cantidad, Correo electrónico, URL, etc. 'Microsoft' y 'Amazon' se identifican como entidades de tipo Organización." },
          { id: 95, certification: "ai900", category: "Azure AI Search", difficulty: "Avanzado", question: "¿Qué tipo de búsqueda en Azure AI Search utiliza embeddings vectoriales para encontrar resultados conceptualmente similares aunque no contengan las mismas palabras?", options: ["Búsqueda por palabras clave", "Búsqueda semántica", "Búsqueda vectorial", "Búsqueda facetada"], correctAnswer: 2, explanation: "La búsqueda vectorial (vector search) almacena y consulta embeddings numéricos de texto, permitiendo encontrar documentos conceptualmente similares independientemente de las palabras exactas usadas en la consulta." },
          { id: 96, certification: "ai900", category: "IA generativa", difficulty: "Medio", question: "¿Cuál es la diferencia principal entre un 'assistant' de Azure OpenAI y un 'agent' autónomo de IA?", options: ["No hay diferencia, son sinónimos", "El assistant responde a prompts del usuario; el agent puede planificar y ejecutar tareas de forma autónoma con herramientas", "El agent solo funciona offline", "El assistant solo puede generar texto"], correctAnswer: 1, explanation: "Un assistant (como Assistants API) responde a instrucciones del usuario. Un agent autónomo puede planificar secuencias de acciones, usar herramientas externas y tomar decisiones sin intervención humana directa en cada paso." },
          { id: 97, certification: "ai900", category: "Azure AI Vision", difficulty: "Medio", question: "¿Qué versión de Image Analysis de Azure AI Vision proporciona descripciones detalladas de imágenes generadas en lenguaje natural?", options: ["Image Analysis 3.2", "Image Analysis 4.0", "Custom Vision 3.0", "Computer Vision 2.0"], correctAnswer: 1, explanation: "Image Analysis 4.0 introduce la capacidad de generar descripciones densas (dense captions) que describen en lenguaje natural no solo la imagen completa sino también regiones específicas detectadas." },
          { id: 98, certification: "ai900", category: "Azure OpenAI", difficulty: "Fácil", question: "¿Qué elemento de un mensaje enviado a Azure OpenAI define el comportamiento general y las instrucciones del sistema para el modelo?", options: ["User message", "System message", "Assistant message", "Function call"], correctAnswer: 1, explanation: "El system message establece el contexto, personalidad y reglas del asistente. Se envía al inicio de la conversación y guía todas las respuestas posteriores del modelo." },
          { id: 99, certification: "ai900", category: "Azure Machine Learning", difficulty: "Medio", question: "¿Qué tipo de endpoint de Azure Machine Learning está diseñado para servir predicciones de ML con baja latencia y alta disponibilidad?", options: ["Batch endpoint", "Online endpoint", "Pipeline endpoint", "Notebook endpoint"], correctAnswer: 1, explanation: "Los online endpoints de Azure ML despliegan modelos como servicios web REST con baja latencia, ideal para aplicaciones que necesitan respuestas inmediatas como chatbots o recomendaciones en tiempo real." },
          { id: 100, certification: "ai900", category: "Principios de IA responsable", difficulty: "Medio", question: "¿Qué principio de IA responsable se ve comprometido cuando un modelo de reconocimiento facial tiene mayor tasa de error para ciertos grupos étnicos?", options: ["Transparencia", "Equidad (Fairness)", "Privacidad", "Responsabilidad"], correctAnswer: 1, explanation: "La Equidad (Fairness) exige que los sistemas de IA funcionen correctamente para todos los grupos demográficos. Una mayor tasa de error para ciertos grupos étnicos viola este principio y debe mitigarse con datos de entrenamiento diversos y técnicas como Fairlearn." }
        ],
        concepts: [
          { title: "Machine Learning", description: "Rama de la IA que permite a los sistemas aprender patrones a partir de datos sin ser programados explícitamente. Incluye aprendizaje supervisado, no supervisado y por refuerzo.", keyPoints: ["Supervisado: datos etiquetados (clasificación, regresión)", "No supervisado: sin etiquetas (clustering, detección de anomalías)", "Por refuerzo: aprendizaje basado en recompensas y penalizaciones", "Métricas: accuracy, precision, recall, F1 score, RMSE"] },
          { title: "Computer Vision", description: "Campo de la IA que permite a las máquinas interpretar y comprender el contenido visual de imágenes y vídeos.", keyPoints: ["Azure AI Vision: análisis de imágenes, OCR, detección de objetos", "Azure AI Face: detección y reconocimiento facial", "Azure AI Spatial Analysis: análisis de espacios físicos", "Aplicaciones: diagnóstico médico, seguridad, inspección industrial"] },
          { title: "NLP (Natural Language Processing)", description: "Campo de la IA que permite a las máquinas comprender, interpretar y generar lenguaje humano.", keyPoints: ["Azure AI Language: análisis de sentimiento, extracción de entidades", "Azure AI Translator: traducción automática entre idiomas", "Azure AI Speech: reconocimiento y síntesis de voz", "Aplicaciones: chatbots, análisis de opiniones, resumen automático"] },
          { title: "Azure AI Services", description: "Conjunto de servicios cognitivos de Azure que permiten añadir capacidades de IA a las aplicaciones sin necesidad de ser experto en ML.", keyPoints: ["Azure AI Vision: análisis de imágenes y vídeo", "Azure AI Language: comprensión y generación de lenguaje", "Azure AI Speech: voz y audio", "Azure AI Document Intelligence: extracción de documentos", "Azure AI Search: búsqueda inteligente con enriquecimiento"] },
          { title: "Responsible AI", description: "Marco de principios y prácticas para desarrollar y desplegar sistemas de IA de manera ética, segura y transparente.", keyPoints: ["Equidad: trato justo para todos los grupos", "Fiabilidad y seguridad: funcionamiento consistente y seguro", "Privacidad y seguridad: protección de datos personales", "Inclusión: diseño accesible para todos", "Transparencia: comprensibilidad de las decisiones", "Responsabilidad: supervisión humana y control"] },
          { title: "Azure OpenAI", description: "Servicio de Azure que proporciona acceso a modelos de lenguaje grandes (LLMs) de OpenAI con la seguridad y escalabilidad de la nube de Microsoft.", keyPoints: ["Modelos: GPT-4, GPT-3.5, DALL-E, Whisper", "Funciones: chat, completado de texto, generación de imágenes", "Seguridad: content filtering, RBAC, redes privadas", "Casos de uso: asistentes virtuales, generación de contenido, análisis"] },
          { title: "RAG (Retrieval Augmented Generation)", description: "Técnica que combina la recuperación de información de una base de conocimientos con la generación de texto para producir respuestas precisas y fundamentadas.", keyPoints: ["Recupera documentos relevantes de una base de datos vectorial", "El modelo genera respuestas basadas en el contexto recuperado", "Reduce alucinaciones del modelo", "Implementable con Azure OpenAI + Azure AI Search"] },
          { title: "Prompt Engineering", description: "Diseño y optimización de instrucciones (prompts) para obtener respuestas más precisas y útiles de los modelos de IA generativa.", keyPoints: ["Ser específico y claro en las instrucciones", "Proporcionar ejemplos (few-shot learning)", "Definir el formato de salida deseado", "Usar delimitadores para separar contexto e instrucciones", "Iterar y refinar los prompts"] },
          { title: "Generative AI", description: "Tipo de IA capaz de crear contenido nuevo y original como texto, imágenes, audio, código y vídeo a partir de patrones aprendidos.", keyPoints: ["Modelos fundacionales: entrenados con grandes cantidades de datos", "Transformers: arquitectura clave detrás de GPT y modelos similares", "Aplicaciones: generación de código, diseño creativo, síntesis de datos", "Desafíos: alucinaciones, sesgos, propiedad intelectual"] },
          { title: "Document Intelligence", description: "Capacidad de la IA para extraer información estructurada de documentos escaneados, PDFs e imágenes sin necesidad de plantillas manuales.", keyPoints: ["Azure AI Document Intelligence: modelos preentrenados y personalizables", "Extracción de texto, tablas, pares clave-valor", "Modelos especializados: facturas, recibos, identidades, documentos", "Reduce la necesidad de entrada de datos manual"] },
          { title: "Azure AI Search", description: "Servicio de búsqueda en la nube que indexa datos no estructurados y aplica enriquecimiento con IA para búsquedas semánticas avanzadas.", keyPoints: ["Indexación de múltiples fuentes de datos", "Enriquecimiento con skills de IA: OCR, NLP, visión", "Búsqueda semántica y vectorial", "Integración con RAG para IA generativa"] },
          { title: "Azure Machine Learning", description: "Plataforma de servicios en la nube para el ciclo de vida completo del Machine Learning: preparación de datos, entrenamiento, implementación y monitorización.", keyPoints: ["AutoML: automatización del entrenamiento de modelos", "Designer: interfaz visual de arrastrar y soltar", "Notebooks: entornos de desarrollo con Jupyter", "MLOps: CI/CD para modelos de Machine Learning", "Model Registry y Feature Store"] },
          { title: "Data Drift", description: "Degradación del rendimiento de un modelo de ML cuando la distribución de los datos en producción cambia respecto a los datos de entrenamiento.", keyPoints: ["Causado por cambios en el comportamiento de los usuarios o el entorno", "Azure ML ofrece monitorización automática de data drift con alertas", "Requiere reentrenamiento periódico del modelo con datos actualizados", "Se mide comparando estadísticas entre datos de referencia y producción"] },
          { title: "Azure AI Content Safety", description: "Servicio de Azure que detecta y modera contenido potencialmente dañino en texto e imágenes, fundamental para implementaciones seguras de IA generativa.", keyPoints: ["Detecta violencia, contenido sexual, odio y autolesiones", "Aplicable a entradas y salidas de modelos generativos", "Proporciona puntuaciones de severidad por categoría", "Parte de las medidas de seguridad de Azure OpenAI"] },
          { title: "Embeddings y Búsqueda Vectorial", description: "Técnica que representa texto, imágenes o datos como vectores numéricos de alta dimensión para comparar similitud semántica y habilitar búsquedas inteligentes.", keyPoints: ["Textos semánticamente similares tienen vectores cercanos en el espacio", "Base de datos vectorial (Azure AI Search, Cosmos DB) almacena los embeddings", "Fundamental para RAG: recupera documentos relevantes antes de generar respuestas", "Usado en búsqueda semántica, recomendaciones y clustering"] }
        ]
      },
      pl900: {
        id: 'pl900',
        name: 'PL-900 - Microsoft Power Platform Fundamentals',
        shortName: 'PL-900',
        displayName: 'PL-900',
        description: 'Fundamentos de Microsoft Power Platform: Power Apps, Power Automate, Power BI, Power Pages, Copilot Studio y AI Builder.',
        hasPractice: false,
        hasScenarios: false,
        hasConsole: false,
        hasLivePractice: false,
        questions: [
          { id: 1, certification: "pl900", category: "Conceptos básicos de Power Platform", difficulty: "Fácil", question: "¿Qué es Microsoft Power Platform?", options: ["Una suite de herramientas de desarrollo de videojuegos", "Una suite de aplicaciones de bajo código para analizar datos, automatizar procesos y crear soluciones empresariales", "Un sistema operativo para servidores Windows", "Una plataforma de streaming de vídeo"], correctAnswer: 1, explanation: "Power Platform es una suite de aplicaciones de bajo código (low-code) que incluye Power BI, Power Apps, Power Automate, Power Pages y Copilot Studio, diseñada para crear soluciones empresariales sin necesidad de programación extensa." },
          { id: 2, certification: "pl900", category: "Conceptos básicos de Power Platform", difficulty: "Fácil", question: "¿Cuál de los siguientes NO es un componente principal de Microsoft Power Platform?", options: ["Power Apps", "Power Automate", "Power BI", "PowerShell"], correctAnswer: 3, explanation: "Los componentes principales de Power Platform son Power BI, Power Apps, Power Automate, Power Pages y Copilot Studio. PowerShell es una herramienta de scripting y automatización de línea de comandos de Windows, no parte de Power Platform." },
          { id: 3, certification: "pl900", category: "Conceptos básicos de Power Platform", difficulty: "Fácil", question: "¿Qué componente de Power Platform permite crear flujos de trabajo automatizados?", options: ["Power BI", "Power Apps", "Power Automate", "Power Pages"], correctAnswer: 2, explanation: "Power Automate permite crear flujos de trabajo automatizados que conectan aplicaciones y servicios para sincronizar archivos, obtener notificaciones y recopilar datos." },
          { id: 4, certification: "pl900", category: "Conceptos básicos de Power Platform", difficulty: "Fácil", question: "¿Qué componente de Power Platform se utiliza para crear visualizaciones de datos y dashboards interactivos?", options: ["Power Apps", "Power BI", "Power Automate", "Dataverse"], correctAnswer: 1, explanation: "Power BI es la herramienta de business intelligence de Microsoft que permite crear visualizaciones de datos, informes interactivos y dashboards a partir de múltiples fuentes de datos." },
          { id: 5, certification: "pl900", category: "Conceptos básicos de Power Platform", difficulty: "Fácil", question: "¿Qué es Dataverse en el contexto de Power Platform?", options: ["Un servicio de almacenamiento de archivos en la nube", "Una base de datos y plataforma de datos escalable diseñada para almacenar datos empresariales utilizados por aplicaciones de Power Platform", "Un motor de búsqueda empresarial", "Un servicio de correo electrónico"], correctAnswer: 1, explanation: "Dataverse es una base de datos escalable y segura diseñada para almacenar y gestionar datos utilizados por aplicaciones empresariales de Power Platform, con soporte para tipos de datos complejos, relaciones y reglas de negocio." },
          { id: 6, certification: "pl900", category: "Conceptos básicos de Power Platform", difficulty: "Fácil", question: "¿Qué es AI Builder en Power Platform?", options: ["Una herramienta para crear modelos de IA personalizados sin necesidad de código", "Un servicio de traducción automática", "Un motor de búsqueda con IA", "Una herramienta de edición de imágenes"], correctAnswer: 0, explanation: "AI Builder es una capacidad de Power Platform que permite crear y entrenar modelos de inteligencia artificial personalizados (como procesamiento de formularios, predicción, clasificación de texto) sin necesidad de escribir código." },
          { id: 7, certification: "pl900", category: "Conceptos básicos de Power Platform", difficulty: "Medio", question: "¿Qué es un conector en Power Platform?", options: ["Un tipo de base de datos relacional", "Un proxy de red para acceso seguro", "Una abstracción que permite conectar aplicaciones y servicios con fuentes de datos y APIs externas", "Un componente de hardware"], correctAnswer: 2, explanation: "Los conectores en Power Platform son abstracciones que permiten conectar aplicaciones y flujos con fuentes de datos y servicios externos (como SharePoint, SQL Server, Dynamics 365, Twitter, etc.) mediante APIs predefinidas." },
          { id: 8, certification: "pl900", category: "Conceptos básicos de Power Platform", difficulty: "Medio", question: "¿Cuál es la diferencia entre un conector estándar y un conector premium en Power Platform?", options: ["Los conectores estándar son más rápidos", "Los conectores premium requieren una licencia adicional y suelen conectarse a servicios empresariales o de terceros de pago", "Los conectores estándar solo funcionan en Power BI", "Los conectores premium son gratuitos"], correctAnswer: 1, explanation: "Los conectores estándar están incluidos en las licencias básicas de Power Platform. Los conectores premium requieren licencias adicionales (por usuario o por flujo) y suelen conectar con servicios empresariales avanzados o de terceros de pago." },
          { id: 9, certification: "pl900", category: "Conceptos básicos de Power Platform", difficulty: "Medio", question: "¿Qué es Microsoft Copilot Studio (anteriormente Power Virtual Agents)?", options: ["Una herramienta para crear chatbots y agentes de IA conversacionales sin código", "Un servicio de análisis de datos", "Una plataforma de desarrollo de juegos", "Un sistema de gestión de bases de datos"], correctAnswer: 0, explanation: "Microsoft Copilot Studio permite crear chatbots y agentes de IA conversacionales sin necesidad de código, integrándose con canales como Teams, sitios web y aplicaciones para responder preguntas y automatizar tareas." },
          { id: 10, certification: "pl900", category: "Conceptos básicos de Power Platform", difficulty: "Medio", question: "¿Qué es el 'low-code' en el contexto de Power Platform?", options: ["Un lenguaje de programación de bajo nivel como ensamblador", "Un enfoque de desarrollo que minimiza la cantidad de código manual necesario mediante interfaces visuales y componentes preconstruidos", "Un tipo de base de datos NoSQL", "Un protocolo de red de baja latencia"], correctAnswer: 1, explanation: "El enfoque low-code de Power Platform permite que desarrolladores ciudadanos y profesionales creen aplicaciones, flujos y dashboards mediante interfaces visuales de arrastrar y soltar, reduciendo drásticamente la necesidad de código manual." },
          { id: 11, certification: "pl900", category: "Power Apps", difficulty: "Fácil", question: "¿Cuáles son los dos tipos principales de aplicaciones en Power Apps?", options: ["Web y móvil", "Canvas y model-driven", "Local y en la nube", "Gratuita y de pago"], correctAnswer: 1, explanation: "Power Apps ofrece dos tipos principales de aplicaciones: Canvas apps (aplicaciones de lienzo, diseño libre con control total de la interfaz) y model-driven apps (aplicaciones basadas en datos, generadas automáticamente a partir de la estructura de Dataverse)." },
          { id: 12, certification: "pl900", category: "Power Apps", difficulty: "Fácil", question: "¿Qué tipo de app de Power Apps es más adecuada cuando necesitas un diseño de interfaz personalizado y control total sobre la disposición de los elementos?", options: ["Model-driven app", "Canvas app", "Portal app", "Dashboard app"], correctAnswer: 1, explanation: "Las Canvas apps permiten un diseño de interfaz completamente personalizable mediante un lienzo en blanco donde se pueden arrastrar y soltar controles, imágenes y componentes con total libertad de diseño." },
          { id: 13, certification: "pl900", category: "Power Apps", difficulty: "Fácil", question: "¿Qué tipo de app de Power Apps se genera automáticamente a partir de la estructura de datos de Dataverse?", options: ["Canvas app", "Model-driven app", "Web app", "Mobile app"], correctAnswer: 1, explanation: "Las model-driven apps se generan automáticamente a partir de la estructura de datos, relaciones y formularios definidos en Dataverse, proporcionando una interfaz consistente y basada en componentes." },
          { id: 14, certification: "pl900", category: "Power Apps", difficulty: "Fácil", question: "¿Qué fórmula se utiliza en Power Apps para mostrar una lista de registros de una fuente de datos?", options: ["Sum()", "Collect()", "Filter()", "All of the above"], correctAnswer: 3, explanation: "Power Apps utiliza fórmulas similares a Excel. Filter() filtra registros, Collect() recopila datos en una colección, y Sum() suma valores. Todas son fórmulas válidas dependiendo del contexto." },
          { id: 15, certification: "pl900", category: "Power Apps", difficulty: "Medio", question: "¿Qué es una galería (Gallery) en Power Apps?", options: ["Un componente que muestra una colección de registros en formato de lista o tabla", "Una herramienta para editar imágenes", "Un tipo de conector de datos", "Un servicio de almacenamiento"], correctAnswer: 0, explanation: "Una Gallery en Power Apps es un control que muestra múltiples registros de una fuente de datos en un formato repetitivo (tarjetas, listas, tablas), permitiendo navegar, seleccionar y mostrar datos." },
          { id: 16, certification: "pl900", category: "Power Apps", difficulty: "Medio", question: "¿Qué es un componente (component) reutilizable en Power Apps?", options: ["Un conector de datos premium", "Un bloque de interfaz de usuario que se puede reutilizar en múltiples pantallas y aplicaciones", "Un tipo de licencia de Power Platform", "Un servicio de autenticación"], correctAnswer: 1, explanation: "Los componentes reutilizables en Power Apps son bloques de interfaz de usuario personalizados (como encabezados, pies de página, menús) que se pueden crear una vez y reutilizar en múltiples pantallas y aplicaciones, facilitando el mantenimiento." },
          { id: 17, certification: "pl900", category: "Power Apps", difficulty: "Medio", question: "¿Qué función de Power Apps se usa para navegar a otra pantalla de la aplicación?", options: ["Navigate()", "GoTo()", "OpenScreen()", "SwitchScreen()"], correctAnswer: 0, explanation: "La función Navigate() se utiliza en Power Apps para cambiar de una pantalla a otra dentro de la aplicación, permitiendo especificar la pantalla de destino y la transición visual." },
          { id: 18, certification: "pl900", category: "Power Apps", difficulty: "Medio", question: "¿Qué es Power Apps Studio?", options: ["Un servicio de almacenamiento de aplicaciones", "El entorno de diseño visual donde se crean y editan aplicaciones de Power Apps", "Una herramienta de análisis de rendimiento", "Un sistema de gestión de bases de datos"], correctAnswer: 1, explanation: "Power Apps Studio es el entorno de desarrollo visual integrado en el navegador donde los creadores diseñan, construyen y prueban aplicaciones Canvas y model-driven." },
          { id: 19, certification: "pl900", category: "Power Apps", difficulty: "Medio", question: "¿Qué es una colección (Collection) en Power Apps?", options: ["Una tabla de datos temporal almacenada en la memoria de la aplicación", "Un tipo de base de datos SQL", "Un servicio de almacenamiento en la nube", "Un componente visual"], correctAnswer: 0, explanation: "Las colecciones en Power Apps son tablas de datos temporales que se almacenan en la memoria local de la aplicación, útiles para manipular datos sin necesidad de conectarse a una fuente de datos externa." },
          { id: 20, certification: "pl900", category: "Power Apps", difficulty: "Medio", question: "¿Qué es Power Fx en Power Apps?", options: ["Un lenguaje de programación de bajo nivel", "El lenguaje de fórmulas de bajo código de Power Apps, inspirado en Excel", "Un tipo de conector de datos", "Un servicio de traducción"], correctAnswer: 1, explanation: "Power Fx es el lenguaje de fórmulas de bajo código de Power Platform, inspirado en Excel. Se utiliza para expresar lógica de negocio, manipular datos y controlar el comportamiento de las aplicaciones." },
          { id: 21, certification: "pl900", category: "Power Automate", difficulty: "Fácil", question: "¿Qué tipos de flujos (flows) existen en Power Automate?", options: ["Solo flujos de nube", "Flujos de nube, flujos de escritorio y flujos de proceso de negocio", "Solo flujos de escritorio", "Solo flujos de aprobación"], correctAnswer: 1, explanation: "Power Automate ofrece tres tipos principales de flujos: Cloud flows (flujos de nube automatizados, instantáneos o programados), Desktop flows (flujos de escritorio para automatizar aplicaciones de escritorio) y Business process flows (flujos de proceso de negocio para guiar a los usuarios)." },
          { id: 22, certification: "pl900", category: "Power Automate", difficulty: "Fácil", question: "¿Qué tipo de flujo de Power Automate se ejecuta automáticamente cuando ocurre un evento específico?", options: ["Instant flow", "Automated cloud flow", "Scheduled flow", "Desktop flow"], correctAnswer: 1, explanation: "Un Automated cloud flow se ejecuta automáticamente cuando se produce un evento desencadenante (trigger), como recibir un correo electrónico, crear un elemento en SharePoint o recibir una mención en Twitter." },
          { id: 23, certification: "pl900", category: "Power Automate", difficulty: "Fácil", question: "¿Qué tipo de flujo de Power Automate se ejecuta manualmente cuando el usuario pulsa un botón?", options: ["Automated cloud flow", "Instant flow", "Scheduled flow", "Business process flow"], correctAnswer: 1, explanation: "Un Instant flow (flujo instantáneo) se ejecuta manualmente cuando un usuario pulsa un botón en la aplicación de Power Automate móvil o desde una aplicación de Power Apps." },
          { id: 24, certification: "pl900", category: "Power Automate", difficulty: "Fácil", question: "¿Qué tipo de flujo de Power Automate se ejecuta en intervalos de tiempo programados?", options: ["Automated cloud flow", "Instant flow", "Scheduled flow", "Desktop flow"], correctAnswer: 2, explanation: "Un Scheduled flow (flujo programado) se ejecuta automáticamente en intervalos de tiempo definidos, como cada hora, cada día o en días específicos de la semana." },
          { id: 25, certification: "pl900", category: "Power Automate", difficulty: "Medio", question: "¿Qué es un Desktop flow en Power Automate?", options: ["Un flujo que solo funciona en dispositivos móviles", "Un flujo que automatiza aplicaciones de escritorio y tareas en la interfaz de usuario de Windows", "Un flujo que solo funciona en la nube", "Un flujo para enviar correos electrónicos"], correctAnswer: 1, explanation: "Los Desktop flows (anteriormente UI flows o WinAutomation) automatizan tareas repetitivas en aplicaciones de escritorio de Windows mediante la grabación de interacciones con la interfaz de usuario, simulando clics y pulsaciones de teclas." },
          { id: 26, certification: "pl900", category: "Power Automate", difficulty: "Medio", question: "¿Qué es un Business Process Flow en Power Automate?", options: ["Un flujo que automatiza tareas de escritorio", "Un flujo que guía a los usuarios a través de un proceso de negocio definido en etapas", "Un flujo que envía notificaciones automáticas", "Un flujo de integración de datos"], correctAnswer: 1, explanation: "Los Business Process Flows guían a los usuarios a través de un proceso de negocio estandarizado en etapas definidas, asegurando que se completen los pasos necesarios en el orden correcto (por ejemplo, proceso de ventas de prospecto a cierre)." },
          { id: 27, certification: "pl900", category: "Power Automate", difficulty: "Medio", question: "¿Qué es un trigger (desencadenante) en Power Automate?", options: ["Una acción que envía un correo electrónico", "El evento que inicia la ejecución de un flujo", "Un tipo de licencia de Power Platform", "Un componente visual de Power Apps"], correctAnswer: 1, explanation: "Un trigger es el evento que inicia la ejecución de un flujo en Power Automate. Puede ser un evento de una aplicación (nuevo correo, nuevo archivo, nueva fila en una base de datos) o un botón pulsado manualmente." },
          { id: 28, certification: "pl900", category: "Power Automate", difficulty: "Medio", question: "¿Qué es una acción (action) en Power Automate?", options: ["El evento que inicia un flujo", "Una tarea que realiza el flujo después de ser desencadenado", "Un tipo de conector premium", "Un componente de Power BI"], correctAnswer: 1, explanation: "Una action en Power Automate es una tarea que el flujo realiza después de ser desencadenado, como enviar un correo, crear un registro, actualizar una fila o publicar en Teams." },
          { id: 29, certification: "pl900", category: "Power Automate", difficulty: "Medio", question: "¿Qué es la aprobación (Approval) en Power Automate?", options: ["Un tipo de flujo que requiere que uno o más usuarios aprueben o rechacen una solicitud antes de continuar", "Un conector de datos", "Un tipo de licencia", "Un componente de Power Apps"], correctAnswer: 0, explanation: "Las acciones de aprobación en Power Automate permiten enviar solicitudes de aprobación a uno o más usuarios, quienes pueden aprobar o rechazar directamente desde el correo electrónico o Teams, y el flujo continúa según la respuesta." },
          { id: 30, certification: "pl900", category: "Power Automate", difficulty: "Medio", question: "¿Qué es Power Automate Desktop?", options: ["La versión móvil de Power Automate", "La aplicación de escritorio gratuita para crear flujos de automatización de interfaz de usuario (RPA) en Windows", "Un servicio de almacenamiento en la nube", "Una herramienta de análisis de datos"], correctAnswer: 1, explanation: "Power Automate Desktop es la aplicación de escritorio gratuita (incluida en Windows 11 y disponible para Windows 10) que permite crear flujos de automatización RPA (Robotic Process Automation) para aplicaciones de escritorio y web." },
          { id: 31, certification: "pl900", category: "Power BI", difficulty: "Fácil", question: "¿Qué es Power BI?", options: ["Una herramienta de creación de aplicaciones móviles", "Un servicio de business intelligence para visualizar datos y compartir insights", "Un sistema de gestión de bases de datos", "Una plataforma de redes sociales"], correctAnswer: 1, explanation: "Power BI es un conjunto de herramientas de análisis de negocios que permite visualizar datos, crear informes interactivos y dashboards, y compartir insights en toda la organización." },
          { id: 32, certification: "pl900", category: "Power BI", difficulty: "Fácil", question: "¿Cuáles son los tres componentes principales de Power BI?", options: ["Power BI Desktop, Power BI Service y Power BI Mobile", "Power BI Studio, Power BI Cloud y Power BI App", "Power BI Designer, Power BI Server y Power BI Tablet", "Power BI Creator, Power BI Viewer y Power BI Admin"], correctAnswer: 0, explanation: "Los tres componentes principales de Power BI son: Power BI Desktop (aplicación de escritorio para crear informes), Power BI Service (servicio en la nube para publicar, compartir y colaborar) y Power BI Mobile (aplicaciones móviles para consumir informes)." },
          { id: 33, certification: "pl900", category: "Power BI", difficulty: "Fácil", question: "¿Qué herramienta de Power BI se utiliza para crear y diseñar informes en el escritorio de forma gratuita?", options: ["Power BI Service", "Power BI Desktop", "Power BI Mobile", "Power BI Premium"], correctAnswer: 1, explanation: "Power BI Desktop es la aplicación gratuita para Windows que permite conectar a fuentes de datos, transformar datos con Power Query, crear modelos de datos y diseñar informes visuales." },
          { id: 34, certification: "pl900", category: "Power BI", difficulty: "Fácil", question: "¿Qué es un dataset en Power BI?", options: ["Una colección de datos que sirve como fuente para crear informes y visualizaciones", "Un tipo de gráfico", "Un conector de datos", "Un tipo de licencia"], correctAnswer: 0, explanation: "Un dataset en Power BI es una colección de datos importados o conectados que sirve como fuente subyacente para crear informes, visualizaciones y dashboards en Power BI Service." },
          { id: 35, certification: "pl900", category: "Power BI", difficulty: "Fácil", question: "¿Qué es un dashboard en Power BI?", options: ["Un informe detallado con múltiples páginas", "Un lienzo único que muestra visualizaciones clave (tiles) fijadas desde diferentes informes", "Un tipo de base de datos", "Un flujo de automatización"], correctAnswer: 1, explanation: "Un dashboard en Power BI es un lienzo único que muestra visualizaciones clave (tiles) fijadas desde uno o más informes, proporcionando una vista consolidada de métricas importantes." },
          { id: 36, certification: "pl900", category: "Power BI", difficulty: "Fácil", question: "¿Qué es Power Query en Power BI?", options: ["Un motor de consultas SQL", "Una herramienta para conectar, transformar y limpiar datos antes de cargarlos en el modelo", "Un tipo de gráfico avanzado", "Un servicio de almacenamiento"], correctAnswer: 1, explanation: "Power Query es la herramienta de transformación de datos (ETL) integrada en Power BI Desktop (y Excel) que permite conectar a múltiples fuentes de datos, limpiar, transformar y combinar datos antes de cargarlos en el modelo." },
          { id: 37, certification: "pl900", category: "Power BI", difficulty: "Medio", question: "¿Qué es DAX en Power BI?", options: ["Un lenguaje de programación de propósito general", "Data Analysis Expressions: lenguaje de fórmulas para crear medidas, columnas calculadas y tablas calculadas", "Un tipo de conector de datos", "Un protocolo de red"], correctAnswer: 1, explanation: "DAX (Data Analysis Expressions) es el lenguaje de fórmulas de Power BI, Power Pivot y SSAS Tabular. Se utiliza para crear medidas, columnas calculadas, tablas calculadas y expresiones de filtro para análisis avanzado." },
          { id: 38, certification: "pl900", category: "Power BI", difficulty: "Medio", question: "¿Qué es una medida (Measure) en Power BI?", options: ["Una columna de datos importada directamente", "Un cálculo dinámico basado en DAX que se evalúa según el contexto de filtro de la visualización", "Un tipo de gráfico", "Un conector de datos"], correctAnswer: 1, explanation: "Una medida (Measure) en Power BI es un cálculo dinámico creado con DAX que se evalúa en tiempo real según el contexto de filtro de la visualización (por ejemplo, SUM de ventas filtrado por año y región)." },
          { id: 39, certification: "pl900", category: "Power BI", difficulty: "Medio", question: "¿Qué es una relación (Relationship) en el modelo de datos de Power BI?", options: ["Una conexión entre dos tablas basada en columnas comunes que permite combinar datos para análisis", "Un tipo de gráfico", "Un conector de red", "Un tipo de licencia"], correctAnswer: 0, explanation: "Las relaciones en el modelo de datos de Power BI conectan tablas mediante columnas comunes (claves), permitiendo crear visualizaciones que combinan datos de múltiples tablas (por ejemplo, ventas con información de clientes y productos)." },
          { id: 40, certification: "pl900", category: "Power BI", difficulty: "Medio", question: "¿Qué es un workspace en Power BI Service?", options: ["Un área de trabajo colaborativa donde los equipos pueden crear, compartir y gestionar informes, datasets y dashboards", "Una aplicación de escritorio", "Un tipo de base de datos", "Un conector de datos"], correctAnswer: 0, explanation: "Un workspace en Power BI Service es un área de trabajo colaborativa donde los equipos pueden publicar, compartir y gestionar informes, datasets, dashboards y aplicaciones de Power BI, con control de acceso basado en roles." },
          { id: 41, certification: "pl900", category: "Power BI", difficulty: "Medio", question: "¿Qué es una aplicación (App) en Power BI?", options: ["Una aplicación móvil nativa", "Un conjunto de informes y dashboards relacionados empaquetados para distribución masiva a usuarios finales", "Un tipo de conector", "Un servicio de almacenamiento"], correctAnswer: 1, explanation: "Una App en Power BI es un conjunto de informes y dashboards relacionados empaquetados para distribución masiva a usuarios finales, con navegación simplificada y permisos centralizados." },
          { id: 42, certification: "pl900", category: "Power BI", difficulty: "Medio", question: "¿Qué es el row-level security (RLS) en Power BI?", options: ["Un protocolo de red", "Una característica que restringe el acceso a datos a nivel de fila según el usuario que visualiza el informe", "Un tipo de gráfico", "Un conector de datos premium"], correctAnswer: 1, explanation: "El Row-Level Security (RLS) en Power BI permite restringir el acceso a datos a nivel de fila según el usuario que visualiza el informe, asegurando que cada usuario solo vea los datos autorizados para su rol." },
          { id: 43, certification: "pl900", category: "Power BI", difficulty: "Medio", question: "¿Qué es un tile en un dashboard de Power BI?", options: ["Una visualización individual fijada al dashboard desde un informe", "Un tipo de base de datos", "Un conector de datos", "Una licencia de usuario"], correctAnswer: 0, explanation: "Un tile es una visualización individual (gráfico, KPI, imagen, texto) que se fija (pin) a un dashboard de Power BI desde un informe, permitiendo crear vistas consolidadas de múltiples fuentes." },
          { id: 44, certification: "pl900", category: "Power BI", difficulty: "Medio", question: "¿Qué es Q&A en Power BI?", options: ["Un chatbot de soporte técnico", "Una característica que permite hacer preguntas en lenguaje natural sobre los datos y obtener respuestas visuales", "Un tipo de filtro", "Un servicio de traducción"], correctAnswer: 1, explanation: "La característica Q&A (Preguntas y respuestas) de Power BI permite a los usuarios hacer preguntas en lenguaje natural sobre sus datos (por ejemplo, 'ventas por región en 2023') y obtener respuestas en forma de visualizaciones automáticas." },
          { id: 45, certification: "pl900", category: "Power BI", difficulty: "Medio", question: "¿Qué es la segmentación de datos (Slicer) en Power BI?", options: ["Un tipo de gráfico circular", "Un control visual que permite filtrar los datos de un informe por valores específicos", "Un tipo de base de datos", "Un conector de red"], correctAnswer: 1, explanation: "Un Slicer (segmentación de datos) en Power BI es un control visual que permite a los usuarios filtrar los datos de un informe seleccionando valores específicos de una columna (por ejemplo, filtrar por año, región o categoría de producto)." },
          { id: 46, certification: "pl900", category: "Dataverse", difficulty: "Fácil", question: "¿Qué es Microsoft Dataverse?", options: ["Un servicio de almacenamiento de archivos", "Una base de datos escalable y segura diseñada para aplicaciones empresariales de Power Platform", "Un motor de búsqueda", "Un servicio de correo electrónico"], correctAnswer: 1, explanation: "Dataverse es una base de datos escalable y segura diseñada específicamente para almacenar y gestionar datos empresariales utilizados por aplicaciones de Power Platform, Dynamics 365 y Azure." },
          { id: 47, certification: "pl900", category: "Dataverse", difficulty: "Fácil", question: "¿Qué tipo de relaciones admite Dataverse entre tablas?", options: ["Solo relaciones uno a uno", "Relaciones uno a muchos, muchos a uno y muchos a muchos", "Solo relaciones muchos a muchos", "No admite relaciones entre tablas"], correctAnswer: 1, explanation: "Dataverse admite relaciones uno a muchos (1:N), muchos a uno (N:1) y muchos a muchos (N:N) entre tablas, permitiendo modelar datos empresariales complejos con integridad referencial." },
          { id: 48, certification: "pl900", category: "Dataverse", difficulty: "Fácil", question: "¿Qué es una tabla (Table) en Dataverse?", options: ["Un tipo de gráfico en Power BI", "Una estructura para almacenar datos con filas (registros) y columnas (campos)", "Un componente visual de Power Apps", "Un tipo de flujo en Power Automate"], correctAnswer: 1, explanation: "Una tabla en Dataverse es una estructura de base de datos que almacena datos en filas (registros) y columnas (campos/atributos), similar a una tabla de SQL pero con tipos de datos específicos de negocio y metadatos enriquecidos." },
          { id: 49, certification: "pl900", category: "Dataverse", difficulty: "Medio", question: "¿Qué es una columna de tipo Choice en Dataverse?", options: ["Un campo de texto libre", "Un campo que permite seleccionar un valor de una lista predefinida de opciones", "Un campo numérico", "Un campo de fecha"], correctAnswer: 1, explanation: "Una columna de tipo Choice (o Choices) en Dataverse permite definir una lista predefinida de opciones de las que el usuario puede seleccionar uno o varios valores, asegurando consistencia en los datos." },
          { id: 50, certification: "pl900", category: "Dataverse", difficulty: "Medio", question: "¿Qué es una regla de negocio (Business Rule) en Dataverse?", options: ["Un flujo de Power Automate", "Una regla que aplica lógica de negocio en formularios de Dataverse sin necesidad de código", "Un tipo de gráfico en Power BI", "Un conector de datos"], correctAnswer: 1, explanation: "Las Business Rules en Dataverse permiten aplicar lógica de negocio en los formularios (mostrar/ocultar campos, establecer valores, validar datos, hacer campos obligatorios) sin necesidad de escribir código." },
          { id: 51, certification: "pl900", category: "Dataverse", difficulty: "Medio", question: "¿Qué es una vista (View) en Dataverse?", options: ["Un tipo de gráfico en Power BI", "Una consulta filtrada y ordenada que define qué registros y columnas se muestran en una aplicación", "Un tipo de flujo en Power Automate", "Un componente visual de Power Apps"], correctAnswer: 1, explanation: "Una View (vista) en Dataverse es una consulta predefinida que filtra, ordena y selecciona columnas de una tabla, determinando qué registros se muestran en las aplicaciones model-driven y en las búsquedas." },
          { id: 52, certification: "pl900", category: "Dataverse", difficulty: "Medio", question: "¿Qué es un formulario (Form) en Dataverse?", options: ["Un tipo de informe en Power BI", "La interfaz visual para crear, leer y editar registros de una tabla en aplicaciones model-driven", "Un flujo de Power Automate", "Un conector de datos"], correctAnswer: 1, explanation: "Un Form (formulario) en Dataverse define la interfaz visual para crear, leer y editar registros de una tabla en aplicaciones model-driven, organizando campos en secciones y pestañas." },
          { id: 53, certification: "pl900", category: "Dataverse", difficulty: "Medio", question: "¿Qué es un conjunto de opciones (Option Set) en Dataverse?", options: ["Un tipo de gráfico", "Una lista predefinida de valores que se pueden reutilizar en múltiples columnas y tablas", "Un tipo de conector", "Un flujo de automatización"], correctAnswer: 1, explanation: "Un Option Set (conjunto de opciones) en Dataverse es una lista global de valores predefinidos que se puede reutilizar en múltiples columnas Choice de diferentes tablas, facilitando la estandarización y el mantenimiento." },
          { id: 54, certification: "pl900", category: "Dataverse", difficulty: "Medio", question: "¿Qué es la seguridad basada en roles en Dataverse?", options: ["Un tipo de encriptación de datos", "Un mecanismo que controla el acceso a datos mediante roles de seguridad asignados a usuarios y equipos", "Un tipo de gráfico en Power BI", "Un conector de red"], correctAnswer: 1, explanation: "La seguridad basada en roles en Dataverse permite controlar el acceso a datos mediante roles de seguridad que definen permisos a nivel de tabla (crear, leer, escribir, eliminar, anexar, asignar, compartir) asignados a usuarios y equipos." },
          { id: 55, certification: "pl900", category: "AI Builder", difficulty: "Fácil", question: "¿Qué es AI Builder?", options: ["Un servicio de almacenamiento de datos", "Una capacidad de Power Platform que permite crear modelos de IA personalizados sin código", "Un tipo de conector", "Una herramienta de diseño de informes"], correctAnswer: 1, explanation: "AI Builder es una capacidad de Power Platform que permite a los usuarios crear y entrenar modelos de inteligencia artificial personalizados sin necesidad de escribir código, integrándose con Power Apps y Power Automate." },
          { id: 56, certification: "pl900", category: "AI Builder", difficulty: "Fácil", question: "¿Cuáles son algunos de los tipos de modelos preconstruidos disponibles en AI Builder?", options: ["Solo modelos de predicción", "Procesamiento de formularios, predicción, clasificación de texto, detección de objetos y reconocimiento de entidades", "Solo modelos de traducción", "Solo modelos de visión computacional"], correctAnswer: 1, explanation: "AI Builder ofrece modelos preconstruidos como: procesamiento de formularios (Form Processing), predicción (Prediction), clasificación de texto (Text Classification), detección de objetos (Object Detection), reconocimiento de entidades (Entity Extraction) y más." },
          { id: 57, certification: "pl900", category: "AI Builder", difficulty: "Fácil", question: "¿Qué modelo de AI Builder permite extraer información estructurada de documentos escaneados como facturas o recibos?", options: ["Prediction", "Form Processing", "Text Classification", "Object Detection"], correctAnswer: 1, explanation: "El modelo de Form Processing (procesamiento de formularios) de AI Builder permite extraer texto, pares clave-valor, tablas y marcas de selección de documentos escaneados como facturas, recibos y formularios." },
          { id: 58, certification: "pl900", category: "AI Builder", difficulty: "Medio", question: "¿Qué modelo de AI Builder permite predecir un resultado futuro basado en datos históricos?", options: ["Form Processing", "Prediction", "Text Classification", "Object Detection"], correctAnswer: 1, explanation: "El modelo de Prediction (predicción) de AI Builder permite predecir resultados futuros (como si un cliente realizará una compra o si un equipo fallará) basándose en patrones de datos históricos." },
          { id: 59, certification: "pl900", category: "AI Builder", difficulty: "Medio", question: "¿Qué modelo de AI Builder permite clasificar automáticamente el sentimiento de un texto?", options: ["Form Processing", "Prediction", "Text Classification", "Object Detection"], correctAnswer: 2, explanation: "El modelo de Text Classification (clasificación de texto) de AI Builder permite clasificar automáticamente textos en categorías predefinidas, como clasificar correos electrónicos por urgencia o tickets de soporte por tipo de problema." },
          { id: 60, certification: "pl900", category: "AI Builder", difficulty: "Medio", question: "¿Qué modelo de AI Builder permite detectar y localizar objetos específicos en imágenes?", options: ["Form Processing", "Prediction", "Text Classification", "Object Detection"], correctAnswer: 3, explanation: "El modelo de Object Detection (detección de objetos) de AI Builder permite detectar y localizar objetos específicos en imágenes, dibujando cuadros delimitadores alrededor de ellos y contándolos." },
          { id: 61, certification: "pl900", category: "AI Builder", difficulty: "Medio", question: "¿Qué es el entrenamiento (training) de un modelo en AI Builder?", options: ["El proceso de instalar AI Builder en un servidor local", "El proceso de alimentar el modelo con datos de ejemplo para que aprenda a reconocer patrones", "El proceso de crear un conector de datos", "El proceso de diseñar un informe en Power BI"], correctAnswer: 1, explanation: "El entrenamiento en AI Builder consiste en alimentar el modelo con datos de ejemplo etiquetados (como documentos escaneados con campos resaltados) para que el modelo aprenda a reconocer patrones y realizar predicciones." },
          { id: 62, certification: "pl900", category: "AI Builder", difficulty: "Medio", question: "¿Qué es la publicación (publish) de un modelo en AI Builder?", options: ["El proceso de imprimir un informe", "El proceso de hacer disponible el modelo entrenado para su uso en Power Apps y Power Automate", "El proceso de crear una base de datos", "El proceso de enviar un correo electrónico"], correctAnswer: 1, explanation: "Publicar un modelo en AI Builder lo hace disponible para su uso en aplicaciones de Power Apps y flujos de Power Automate, permitiendo que los usuarios consuman las predicciones del modelo." },
          { id: 63, certification: "pl900", category: "AI Builder", difficulty: "Medio", question: "¿Dónde se pueden consumir los modelos de AI Builder una vez publicados?", options: ["Solo en Power BI", "En Power Apps y Power Automate", "Solo en Excel", "Solo en SharePoint"], correctAnswer: 1, explanation: "Los modelos de AI Builder se consumen principalmente en Power Apps (mediante componentes de IA) y en Power Automate (mediante acciones de AI Builder), integrando capacidades de IA en aplicaciones y flujos de trabajo." },
          { id: 64, certification: "pl900", category: "Power Pages", difficulty: "Fácil", question: "¿Qué es Microsoft Power Pages?", options: ["Una herramienta para crear aplicaciones de escritorio", "Una plataforma de bajo código para crear sitios web externos seguros y escalables", "Un servicio de correo electrónico", "Un motor de búsqueda"], correctAnswer: 1, explanation: "Microsoft Power Pages (anteriormente Power Apps Portals) es una plataforma de bajo código para crear sitios web externos seguros y escalables que permiten a usuarios externos interactuar con datos de Dataverse." },
          { id: 65, certification: "pl900", category: "Power Pages", difficulty: "Fácil", question: "¿Qué tipo de usuarios pueden acceder a un sitio creado con Power Pages?", options: ["Solo usuarios internos de la organización", "Usuarios externos (anónimos o autenticados) e internos", "Solo administradores de Azure", "Solo desarrolladores"], correctAnswer: 1, explanation: "Power Pages permite crear sitios web accesibles para usuarios externos (anónimos o autenticados mediante Azure AD, Microsoft Account, Google, etc.) e internos, extendiendo el alcance de las aplicaciones empresariales." },
          { id: 66, certification: "pl900", category: "Power Pages", difficulty: "Medio", question: "¿Qué es un portal en Power Pages?", options: ["Un tipo de aplicación móvil", "Un sitio web basado en plantillas que se conecta a Dataverse para mostrar y gestionar datos", "Un tipo de gráfico en Power BI", "Un flujo de Power Automate"], correctAnswer: 1, explanation: "Un portal en Power Pages es un sitio web basado en plantillas que se conecta a Dataverse, permitiendo mostrar datos, crear formularios, listas y páginas personalizadas para usuarios externos e internos." },
          { id: 67, certification: "pl900", category: "Power Pages", difficulty: "Medio", question: "¿Qué es una plantilla (Template) en Power Pages?", options: ["Un tipo de base de datos", "Un diseño predefinido de página web que define la estructura y el estilo visual", "Un tipo de conector", "Un flujo de automatización"], correctAnswer: 1, explanation: "Una plantilla en Power Pages define la estructura HTML, el diseño y los estilos de una página web, permitiendo crear sitios consistentes y personalizables sin necesidad de codificación extensa." },
          { id: 68, certification: "pl900", category: "Copilot Studio", difficulty: "Fácil", question: "¿Qué es Microsoft Copilot Studio?", options: ["Una herramienta para crear chatbots y agentes de IA conversacionales de bajo código", "Un servicio de análisis de datos", "Una plataforma de desarrollo de juegos", "Un sistema de gestión de bases de datos"], correctAnswer: 0, explanation: "Microsoft Copilot Studio es una herramienta de bajo código para crear chatbots y agentes de IA conversacionales personalizados, integrables con Microsoft Teams, sitios web y otras aplicaciones." },
          { id: 69, certification: "pl900", category: "Copilot Studio", difficulty: "Fácil", question: "¿Qué es un tema (Topic) en Copilot Studio?", options: ["Un tipo de base de datos", "Una conversación predefinida que guía al bot sobre cómo responder a una intención específica del usuario", "Un tipo de gráfico en Power BI", "Un conector de datos"], correctAnswer: 1, explanation: "Un Topic en Copilot Studio define una conversación predefinida para una intención específica del usuario. Incluye frases de activación (trigger phrases), mensajes del bot, preguntas al usuario y acciones a realizar." },
          { id: 70, certification: "pl900", category: "Copilot Studio", difficulty: "Medio", question: "¿Qué son las frases de activación (Trigger Phrases) en Copilot Studio?", options: ["Mensajes de error del sistema", "Frases que el usuario puede decir para activar un tema específico del bot", "Comandos de administración del sistema", "Notificaciones automáticas"], correctAnswer: 1, explanation: "Las Trigger Phrases en Copilot Studio son frases o palabras clave que los usuarios pueden escribir para activar un tema específico del bot. El bot utiliza NLU (Natural Language Understanding) para reconocer intenciones similares." },
          { id: 71, certification: "pl900", category: "Copilot Studio", difficulty: "Medio", question: "¿Qué es una entidad (Entity) en Copilot Studio?", options: ["Un tipo de base de datos relacional", "Una pieza de información extraída de la conversación del usuario que el bot puede utilizar", "Un tipo de gráfico", "Un conector de red"], correctAnswer: 1, explanation: "Una Entity en Copilot Studio es una pieza de información extraída del mensaje del usuario (como fechas, nombres, números) que el bot puede capturar y utilizar para personalizar respuestas o realizar acciones." },
          { id: 72, certification: "pl900", category: "Copilot Studio", difficulty: "Medio", question: "¿Qué es un canal (Channel) en Copilot Studio?", options: ["Un tipo de base de datos", "La plataforma donde se publica el bot para que los usuarios interactúen con él", "Un tipo de gráfico en Power BI", "Un conector de datos"], correctAnswer: 1, explanation: "Un Channel en Copilot Studio es la plataforma donde se publica el bot para que los usuarios interactúen, como Microsoft Teams, sitios web, Facebook Messenger, Slack, aplicaciones móviles, etc." },
          { id: 73, certification: "pl900", category: "Copilot Studio", difficulty: "Medio", question: "¿Qué es la escalación (Escalation) en Copilot Studio?", options: ["Un tipo de gráfico", "La capacidad de transferir una conversación del bot a un agente humano cuando el bot no puede resolver la consulta", "Un tipo de base de datos", "Un conector de red"], correctAnswer: 1, explanation: "La escalación en Copilot Studio permite transferir una conversación del bot a un agente humano cuando el bot no puede resolver la consulta del usuario, asegurando una experiencia de servicio al cliente completa." },
          { id: 74, certification: "pl900", category: "Seguridad y gobernanza", difficulty: "Fácil", question: "¿Qué es Microsoft Purview en el contexto de Power Platform?", options: ["Un servicio de almacenamiento de archivos", "Una solución de gobernanza, riesgo y cumplimiento que ayuda a gestionar y proteger datos", "Un tipo de gráfico en Power BI", "Un conector de datos"], correctAnswer: 1, explanation: "Microsoft Purview proporciona capacidades de gobernanza de datos, prevención de pérdida de datos (DLP), clasificación de datos y cumplimiento normativo para Power Platform y otros servicios de Microsoft 365." },
          { id: 75, certification: "pl900", category: "Seguridad y gobernanza", difficulty: "Fácil", question: "¿Qué es una política DLP (Data Loss Prevention) en Power Platform?", options: ["Un tipo de gráfico", "Una regla que previene la filtración accidental de datos sensibles restringiendo qué conectores pueden usarse juntos", "Un tipo de base de datos", "Un conector de red"], correctAnswer: 1, explanation: "Las políticas DLP en Power Platform definen qué conectores pueden usarse juntos en un entorno, creando grupos de conectores (Business y Non-Business) para prevenir la filtración de datos entre servicios no autorizados." },
          { id: 76, certification: "pl900", category: "Seguridad y gobernanza", difficulty: "Medio", question: "¿Qué es un entorno (Environment) en Power Platform?", options: ["Un tipo de aplicación móvil", "Un contenedor que almacena aplicaciones, flujos y datos, con su propia configuración de seguridad y base de datos Dataverse", "Un tipo de gráfico en Power BI", "Un conector de datos"], correctAnswer: 1, explanation: "Un Environment en Power Platform es un contenedor lógico que almacena aplicaciones, flujos, bots y datos, con su propia configuración de seguridad, roles, usuarios y base de datos Dataverse, permitiendo aislar recursos por proyecto, departamento o región." },
          { id: 77, certification: "pl900", category: "Seguridad y gobernanza", difficulty: "Medio", question: "¿Qué es el Centro de administración de Power Platform (Power Platform Admin Center)?", options: ["Una tienda de aplicaciones", "El portal web donde los administradores gestionan entornos, políticas DLP, capacidades, licencias y recursos de Power Platform", "Un tipo de gráfico", "Un conector de datos"], correctAnswer: 1, explanation: "El Power Platform Admin Center (admin.powerplatform.microsoft.com) es el portal de administración donde los administradores gestionan entornos, políticas DLP, capacidades, licencias, análisis de uso y recursos de toda la organización." },
          { id: 78, certification: "pl900", category: "Seguridad y gobernanza", difficulty: "Medio", question: "¿Qué es la auditoría (Auditing) en Dataverse?", options: ["Un tipo de gráfico", "La capacidad de registrar cambios en los datos para cumplimiento y seguimiento", "Un tipo de base de datos", "Un conector de red"], correctAnswer: 1, explanation: "La auditoría en Dataverse registra los cambios realizados en los datos (quién, cuándo y qué cambió) para fines de cumplimiento normativo, seguridad y seguimiento de actividades." },
          { id: 79, certification: "pl900", category: "Seguridad y gobernanza", difficulty: "Medio", question: "¿Qué es el cifrado de datos en reposo en Dataverse?", options: ["Un tipo de gráfico", "La encriptación de datos almacenados en la base de datos para protegerlos contra acceso no autorizado", "Un tipo de conector", "Un flujo de automatización"], correctAnswer: 1, explanation: "Dataverse cifra automáticamente los datos en reposo utilizando cifrado AES-256, protegiendo los datos almacenados contra acceso no autorizado a nivel de infraestructura." },
          { id: 80, certification: "pl900", category: "Seguridad y gobernanza", difficulty: "Medio", question: "¿Qué es una solución (Solution) en Power Platform?", options: ["Un tipo de gráfico", "Un mecanismo para empaquetar y transportar componentes de Power Platform entre entornos", "Un tipo de base de datos", "Un conector de red"], correctAnswer: 1, explanation: "Una Solution en Power Platform es un mecanismo para empaquetar y transportar componentes (aplicaciones, flujos, tablas, formularios, etc.) entre entornos, facilitando el desarrollo, las pruebas y la implementación en producción (ALM)." },
          { id: 81, certification: "pl900", category: "Integración y conectores", difficulty: "Fácil", question: "¿Qué es un conector personalizado (Custom Connector) en Power Platform?", options: ["Un tipo de base de datos", "Un conector que permite conectar con una API REST personalizada no cubierta por los conectores estándar", "Un tipo de gráfico", "Un flujo de automatización"], correctAnswer: 1, explanation: "Un Custom Connector permite conectar Power Platform con una API REST personalizada que no está cubierta por los conectores estándar, definiendo operaciones, parámetros y autenticación de la API." },
          { id: 82, certification: "pl900", category: "Integración y conectores", difficulty: "Medio", question: "¿Qué es Microsoft Graph en el contexto de Power Platform?", options: ["Un tipo de gráfico en Power BI", "Una API REST unificada para acceder a datos y servicios de Microsoft 365", "Un tipo de base de datos", "Un conector de red"], correctAnswer: 1, explanation: "Microsoft Graph es una API REST unificada que permite acceder a datos y servicios de Microsoft 365 (usuarios, correos, calendarios, archivos, equipos) desde Power Platform y otras aplicaciones." },
          { id: 83, certification: "pl900", category: "Integración y conectores", difficulty: "Medio", question: "¿Qué es una gateway (puerta de enlace) en Power Platform?", options: ["Un tipo de gráfico", "Un software que permite conectar Power Platform con fuentes de datos locales (on-premises) de forma segura", "Un tipo de base de datos", "Un conector de red estándar"], correctAnswer: 1, explanation: "La On-premises Data Gateway es un software que se instala en servidores locales para permitir que Power Platform (Power BI, Power Apps, Power Automate) se conecte de forma segura a fuentes de datos locales como SQL Server, SharePoint on-premises, etc." },
          { id: 84, certification: "pl900", category: "Integración y conectores", difficulty: "Medio", question: "¿Qué es Microsoft Dataverse para Teams?", options: ["Una versión de Dataverse integrada en Microsoft Teams para crear aplicaciones y flujos dentro del equipo", "Un servicio de videoconferencia", "Un tipo de gráfico", "Un conector de red"], correctAnswer: 0, explanation: "Dataverse para Teams es una versión ligera de Dataverse integrada en Microsoft Teams que permite crear aplicaciones, flujos y bots directamente dentro de un equipo, sin necesidad de un entorno de Power Platform separado." },
          { id: 85, certification: "pl900", category: "Integración y conectores", difficulty: "Medio", question: "¿Qué es la integración de Power Platform con Microsoft 365?", options: ["Un tipo de licencia", "La capacidad de usar datos y servicios de Microsoft 365 (SharePoint, Teams, Outlook, Excel) en aplicaciones y flujos de Power Platform", "Un tipo de gráfico", "Un conector de red"], correctAnswer: 1, explanation: "Power Platform se integra nativamente con Microsoft 365, permitiendo usar datos de SharePoint, Teams, Outlook, Excel y OneDrive en aplicaciones de Power Apps, flujos de Power Automate e informes de Power BI." },
          { id: 86, certification: "pl900", category: "Valor empresarial", difficulty: "Fácil", question: "¿Qué es un 'citizen developer' (desarrollador ciudadano)?", options: ["Un desarrollador profesional de software", "Un usuario de negocio que crea aplicaciones y automatizaciones con herramientas de bajo código sin ser programador profesional", "Un administrador de sistemas", "Un analista de datos"], correctAnswer: 1, explanation: "Un citizen developer es un usuario de negocio que crea aplicaciones, flujos y soluciones con herramientas de bajo código como Power Platform, sin necesidad de ser un programador profesional, reduciendo la carga sobre los departamentos de TI." },
          { id: 87, certification: "pl900", category: "Valor empresarial", difficulty: "Fácil", question: "¿Cuál es el principal beneficio de usar Power Platform para una organización?", options: ["Reducir el coste de licencias de Office", "Acelerar la innovación y la digitalización permitiendo a los usuarios de negocio crear soluciones sin depender exclusivamente de TI", "Eliminar la necesidad de servidores", "Reemplazar completamente a los desarrolladores profesionales"], correctAnswer: 1, explanation: "El principal beneficio de Power Platform es acelerar la innovación y la transformación digital al empoderar a los usuarios de negocio (citizen developers) para crear soluciones personalizadas, reduciendo el tiempo de desarrollo y la dependencia de TI." },
          { id: 88, certification: "pl900", category: "Valor empresarial", difficulty: "Medio", question: "¿Qué es la transformación digital en el contexto de Power Platform?", options: ["La migración de servidores físicos a la nube", "El uso de tecnología para cambiar procesos de negocio, mejorar la eficiencia y crear nuevos modelos de negocio", "La compra de nuevos ordenadores", "La eliminación de todos los procesos manuales"], correctAnswer: 1, explanation: "La transformación digital implica usar tecnología (como Power Platform) para modernizar procesos de negocio, mejorar la eficiencia operativa, mejorar la experiencia del cliente y crear nuevos modelos de negocio." },
          { id: 89, certification: "pl900", category: "Valor empresarial", difficulty: "Medio", question: "¿Qué es la automatización robótica de procesos (RPA) en Power Automate?", options: ["Un tipo de robot físico", "La automatización de tareas repetitivas en aplicaciones de escritorio y web mediante la simulación de interacciones de usuario", "Un tipo de base de datos", "Un conector de red"], correctAnswer: 1, explanation: "La RPA (Robotic Process Automation) en Power Automate Desktop permite automatizar tareas repetitivas en aplicaciones de escritorio y web simulando interacciones de usuario (clics, pulsaciones de teclas, lectura de datos), liberando a los empleados de tareas manuales." },
          { id: 90, certification: "pl900", category: "Valor empresarial", difficulty: "Medio", question: "¿Qué es la analítica de autoservicio (Self-service analytics) con Power BI?", options: ["Un servicio de soporte técnico", "La capacidad de los usuarios de negocio de crear sus propios informes y análisis sin depender de un departamento de BI centralizado", "Un tipo de base de datos", "Un conector de red"], correctAnswer: 1, explanation: "La analítica de autoservicio con Power BI permite que los usuarios de negocio creen, compartan y consuman informes y dashboards por sí mismos, reduciendo la dependencia de equipos de BI centralizados y acelerando la toma de decisiones basada en datos." },
          { id: 91, certification: "pl900", category: "Valor empresarial", difficulty: "Medio", question: "¿Qué es el ciclo de vida de las aplicaciones (ALM) en Power Platform?", options: ["Un tipo de gráfico", "El proceso de gestionar el desarrollo, pruebas e implementación de aplicaciones y componentes entre entornos", "Un tipo de base de datos", "Un conector de red"], correctAnswer: 1, explanation: "ALM (Application Lifecycle Management) en Power Platform gestiona el ciclo de vida de las aplicaciones, flujos y componentes desde el desarrollo, pasando por pruebas, hasta la implementación en producción, utilizando soluciones y pipelines de despliegue." },
          { id: 92, certification: "pl900", category: "Valor empresarial", difficulty: "Medio", question: "¿Qué es la gobernanza de Power Platform?", options: ["Un tipo de licencia", "El conjunto de políticas, procesos y controles para gestionar el uso de Power Platform de forma segura, eficiente y conforme a las normativas", "Un tipo de gráfico", "Un conector de red"], correctAnswer: 1, explanation: "La gobernanza de Power Platform incluye políticas DLP, control de entornos, gestión de licencias, auditoría, seguridad basada en roles y procesos de ALM para asegurar que el uso de la plataforma sea seguro, eficiente y conforme." },
          { id: 93, certification: "pl900", category: "Power Apps avanzado", difficulty: "Medio", question: "¿Qué es una aplicación basada en componentes (Component Library) en Power Apps?", options: ["Un tipo de base de datos", "Un repositorio centralizado de componentes reutilizables que se pueden compartir entre aplicaciones", "Un tipo de gráfico", "Un conector de red"], correctAnswer: 1, explanation: "La Component Library en Power Apps permite crear y almacenar componentes reutilizables (como encabezados, menús, botones personalizados) en un repositorio centralizado que se puede compartir entre múltiples aplicaciones." },
          { id: 94, certification: "pl900", category: "Power Apps avanzado", difficulty: "Medio", question: "¿Qué es una aplicación embebida (embedded app) en Power Apps?", options: ["Una aplicación que solo funciona sin conexión", "Una aplicación de Power Apps integrada en otra aplicación o sitio web (como SharePoint, Teams o un sitio web personalizado)", "Un tipo de base de datos", "Un conector de red"], correctAnswer: 1, explanation: "Las aplicaciones embebidas de Power Apps se integran directamente en otras aplicaciones o sitios web como SharePoint, Microsoft Teams, Dynamics 365 o sitios web personalizados mediante iframe o controles nativos." },
          { id: 95, certification: "pl900", category: "Power Apps avanzado", difficulty: "Medio", question: "¿Qué es el modo offline en Power Apps?", options: ["Un tipo de gráfico", "La capacidad de usar una aplicación sin conexión a Internet, sincronizando datos cuando se recupera la conectividad", "Un tipo de base de datos", "Un conector de red"], correctAnswer: 1, explanation: "El modo offline en Power Apps permite que las aplicaciones funcionen sin conexión a Internet, almacenando datos localmente y sincronizándolos con la fuente de datos cuando se recupera la conectividad." },
          { id: 96, certification: "pl900", category: "Power Automate avanzado", difficulty: "Medio", question: "¿Qué es una variable en Power Automate?", options: ["Un tipo de base de datos", "Un contenedor para almacenar valores temporales que se pueden usar y modificar durante la ejecución de un flujo", "Un tipo de gráfico", "Un conector de red"], correctAnswer: 1, explanation: "Las variables en Power Automate permiten almacenar valores temporales (números, texto, objetos, matrices) durante la ejecución de un flujo, que se pueden inicializar, establecer, incrementar y consultar en pasos posteriores." },
          { id: 97, certification: "pl900", category: "Power Automate avanzado", difficulty: "Medio", question: "¿Qué es un bucle (Apply to each) en Power Automate?", options: ["Un tipo de base de datos", "Una acción que repite un conjunto de pasos para cada elemento de una colección o matriz", "Un tipo de gráfico", "Un conector de red"], correctAnswer: 1, explanation: "La acción 'Apply to each' en Power Automate itera sobre cada elemento de una colección o matriz (como filas de una tabla, elementos de una lista) y ejecuta un conjunto de acciones para cada elemento." },
          { id: 98, certification: "pl900", category: "Power Automate avanzado", difficulty: "Medio", question: "¿Qué es una condición (Condition) en Power Automate?", options: ["Un tipo de base de datos", "Una acción que evalúa una expresión y dirige el flujo por diferentes ramas según el resultado (si/no)", "Un tipo de gráfico", "Un conector de red"], correctAnswer: 1, explanation: "La acción Condition en Power Automate evalúa una expresión lógica (por ejemplo, si un valor es mayor que otro) y dirige el flujo por ramas diferentes (If yes / If no) según el resultado de la evaluación." },
          { id: 99, certification: "pl900", category: "Power Automate avanzado", difficulty: "Medio", question: "¿Qué es un ámbito (Scope) en Power Automate?", options: ["Un tipo de base de datos", "Un contenedor que agrupa acciones relacionadas para facilitar la organización y el manejo de errores", "Un tipo de gráfico", "Un conector de red"], correctAnswer: 1, explanation: "La acción Scope en Power Automate agrupa un conjunto de acciones relacionadas en un bloque lógico, facilitando la organización del flujo y permitiendo capturar y manejar errores de forma centralizada para todo el grupo." },
          { id: 100, certification: "pl900", category: "Power Automate avanzado", difficulty: "Medio", question: "¿Qué es el manejo de errores (Configure run after) en Power Automate?", options: ["Un tipo de base de datos", "La configuración de qué acciones ejecutar después de que una acción anterior tenga éxito, falle o sea omitida", "Un tipo de gráfico", "Un conector de red"], correctAnswer: 1, explanation: "La configuración 'Configure run after' en Power Automate permite definir el comportamiento de una acción según el resultado de la acción anterior: ejecutar si tiene éxito, si falla, si es omitida o si se agota el tiempo, permitiendo manejar errores de forma robusta." }
        ],
        concepts: [
          { title: "Power Platform Overview", description: "Suite de aplicaciones de bajo código de Microsoft para crear soluciones empresariales: Power BI, Power Apps, Power Automate, Power Pages y Copilot Studio.", keyPoints: ["Power BI: visualización de datos y business intelligence", "Power Apps: creación de aplicaciones de negocio personalizadas", "Power Automate: automatización de flujos de trabajo", "Power Pages: sitios web externos seguros", "Copilot Studio: chatbots y agentes de IA conversacionales", "Dataverse: base de datos empresarial subyacente", "AI Builder: capacidades de IA sin código"] },
          { title: "Power Apps", description: "Herramienta de bajo código para crear aplicaciones de negocio personalizadas. Soporta Canvas apps (diseño libre) y model-driven apps (basadas en datos).", keyPoints: ["Canvas apps: diseño libre con control total de la interfaz", "Model-driven apps: generadas automáticamente desde Dataverse", "Power Fx: lenguaje de fórmulas inspirado en Excel", "Galerías, formularios, colecciones y componentes reutilizables", "Conectores para integrarse con cientos de fuentes de datos", "Component Library para reutilización entre aplicaciones"] },
          { title: "Power Automate", description: "Herramienta de automatización de flujos de trabajo que conecta aplicaciones y servicios para sincronizar datos, enviar notificaciones y automatizar tareas.", keyPoints: ["Cloud flows: automatizados, instantáneos y programados", "Desktop flows: RPA para automatizar aplicaciones de escritorio", "Business process flows: guían a usuarios en procesos de negocio", "Triggers desencadenan flujos; Actions realizan tareas", "Aprobaciones integradas con correo y Teams", "Variables, condiciones, bucles y manejo de errores"] },
          { title: "Power BI", description: "Herramienta de business intelligence para visualizar datos, crear informes interactivos y compartir insights en toda la organización.", keyPoints: ["Power BI Desktop: creación de informes gratuita", "Power BI Service: publicación, colaboración y sharing en la nube", "Power BI Mobile: consumo de informes en dispositivos móviles", "Power Query: transformación y limpieza de datos (ETL)", "DAX: lenguaje de fórmulas para medidas y columnas calculadas", "Dashboards, workspaces, apps y row-level security (RLS)"] },
          { title: "Dataverse", description: "Base de datos escalable y segura diseñada para almacenar datos empresariales utilizados por aplicaciones de Power Platform y Dynamics 365.", keyPoints: ["Tablas con filas (registros) y columnas (campos)", "Relaciones 1:N, N:1 y N:N entre tablas", "Tipos de datos específicos: Choice, Lookup, Currency, DateTime", "Business Rules para lógica sin código", "Seguridad basada en roles a nivel de tabla y registro", "Auditoría y cifrado de datos en reposo (AES-256)"] },
          { title: "AI Builder", description: "Capacidad de Power Platform que permite crear y usar modelos de IA personalizados sin necesidad de escribir código.", keyPoints: ["Form Processing: extracción de datos de documentos", "Prediction: predicción de resultados futuros", "Text Classification: clasificación de texto en categorías", "Object Detection: detección de objetos en imágenes", "Entity Extraction: reconocimiento de entidades en texto", "Entrenamiento con datos de ejemplo y publicación para consumo"] },
          { title: "Power Pages", description: "Plataforma de bajo código para crear sitios web externos seguros y escalables que interactúan con Dataverse.", keyPoints: ["Sitios web para usuarios externos (anónimos o autenticados)", "Autenticación con Azure AD, Microsoft Account, Google, etc.", "Portales basados en plantillas con formularios y listas", "Seguridad heredada de Dataverse", "Ideal para registro de clientes, soporte y autoservicio"] },
          { title: "Copilot Studio", description: "Herramienta de bajo código para crear chatbots y agentes de IA conversacionales personalizados.", keyPoints: ["Topics: conversaciones predefinidas para intenciones específicas", "Trigger Phrases: frases que activan un tema", "Entities: información extraída de la conversación", "Channels: Teams, web, Facebook Messenger, Slack", "Escalation a agentes humanos", "Integración con Power Automate para acciones"] },
          { title: "Conectores", description: "Abstracciones que permiten conectar aplicaciones y flujos con fuentes de datos y servicios externos.", keyPoints: ["Conectores estándar: incluidos en licencias básicas", "Conectores premium: requieren licencia adicional", "Custom Connectors: para APIs REST personalizadas", "On-premises Data Gateway: conexión segura a datos locales", "Microsoft Graph: API unificada para Microsoft 365"] },
          { title: "Seguridad y Gobernanza", description: "Conjunto de políticas, procesos y controles para gestionar Power Platform de forma segura y conforme.", keyPoints: ["Environments: contenedores lógicos con aislamiento de recursos", "DLP Policies: prevención de filtración de datos entre conectores", "Role-based security en Dataverse", "Auditoría de cambios en datos", "Microsoft Purview: gobernanza y cumplimiento", "Solutions y ALM para ciclo de vida de aplicaciones"] },
          { title: "Valor Empresarial", description: "Beneficios de Power Platform para la transformación digital y la innovación empresarial.", keyPoints: ["Citizen developers: usuarios de negocio crean soluciones sin código", "Reducción de dependencia de TI y aceleración de la innovación", "Automatización RPA para tareas repetitivas", "Analítica de autoservicio con Power BI", "ALM: desarrollo, pruebas y producción con soluciones", "Integración nativa con Microsoft 365 y Dynamics 365"] },
          { title: "Power Fx", description: "Lenguaje de fórmulas de bajo código de Power Platform, inspirado en Excel, para expresar lógica de negocio.", keyPoints: ["Sintaxis similar a Excel: fórmulas declarativas", "Usado en Power Apps para propiedades de controles", "Funciones: Navigate(), Collect(), Filter(), Patch(), LookUp()", "Variables globales y de contexto", "Colecciones temporales en memoria", "Expresiones reactivas: se recalculan automáticamente"] },
          { title: "DAX", description: "Data Analysis Expressions: lenguaje de fórmulas para análisis de datos en Power BI, Power Pivot y SSAS Tabular.", keyPoints: ["Medidas (Measures): cálculos dinámicos según contexto de filtro", "Columnas calculadas: cálculos por fila en el modelo", "Tablas calculadas: tablas derivadas del modelo", "Funciones de agregación: SUM, AVERAGE, COUNT", "Funciones de filtro: CALCULATE, FILTER, ALL", "Funciones de tiempo: SAMEPERIODLASTYEAR, DATESYTD"] },
          { title: "Microsoft 365 Integration", description: "Power Platform se integra nativamente con Microsoft 365 para extender la productividad y la colaboración.", keyPoints: ["SharePoint: listas y bibliotecas como fuentes de datos", "Teams: aplicaciones embebidas, bots y flujos", "Outlook: flujos basados en correos y calendarios", "Excel: importación/exportación y conectores", "OneDrive: almacenamiento de archivos", "Dataverse para Teams: apps dentro de equipos"] },
          { title: "Licensing", description: "Modelo de licencias de Power Platform que determina las capacidades disponibles para los usuarios.", keyPoints: ["Licencias por usuario: Power Apps Per User, Power Automate Per User", "Licencias por flujo: Power Automate Per Flow", "Conectores premium requieren licencia adicional", "Power BI Pro y Premium para compartir y publicar", "Copilot Studio: licencias por mensaje o por usuario", "AI Builder: créditos de capacidad incluidos en algunas licencias"] }
        ]
      }
    }
  }
};

